B.apu=new A.c1("C\u1ed5ng R\xeau Im","Th\u1ea1ch M\xf4n Nh\xe2n","B\u1ee9c t\u01b0\u1ee3ng \u0111\u1ee9ng gi\u1eefa c\u1ed5ng th\xe0nh \u0111\u1ed5, hai tay v\u1eabn gi\u1eef t\u01b0 th\u1ebf k\xe9o then c\u1eeda. R\xeau ph\u1ee7 k\xedn m\u1eb7t nh\u01b0 th\u1ec3 h\u1eafn \u0111\xe3 canh n\u01a1i n\xe0y l\xe2u h\u01a1n c\u1ea3 tu\u1ed5i c\u1ee7a m\u1ed9t v\u01b0\u01a1ng tri\u1ec1u.","Th\u1ea1ch M\xf4n Nh\xe2n t\u1eebng m\u1edf c\u1ed5ng cho d\xe2n ch\u1ea1y n\u1ea1n trong \u0111\xeam cu\u1ed1i r\u1ed3i t\u1ef1 xin h\xf3a \u0111\xe1 \u0111\u1ec3 l\u1ed1i tho\xe1t kh\xf4ng b\u1ecb x\xf3a kh\u1ecfi b\u1ea3n \u0111\u1ed3. T\u1eeb \u0111\xf3 t\u1edbi nay, h\u1eafn ch\u1ec9 c\xf2n bi\u1ebft nh\xecn c\u1ecf d\u1ea1i b\xf2 qua con \u0111\u01b0\u1eddng m\xecnh \u0111\xe3 c\u1ee9u.")
B.apo=new A.c1("Bia M\u1ea5t T\xean","Ng\u01b0\u1eddi Gi\u1eef T\xean Cu\u1ed1i","Quanh b\u1ec7 \u0111\xe1 l\xe0 h\xe0ng ch\u1ee5c t\u1ea5m bia b\u1ecb m\xe0i s\u1ea1ch, ch\u1ec9 c\xf2n t\u01b0\u1ee3ng \u0111\xe1 \xf4m \u0111\u1ee5c v\xe0 b\xfaa. Gi\xf3 qu\xe9t qua t\u1eebng m\u1eb7t bia nghe nh\u01b0 ti\u1ebfng ai \u0111\xf3 c\u1ed1 nh\u1edb l\u1ea1i m\u1ed9t c\xe1i t\xean \u0111\xe3 h\u1ee5t m\u1ea5t.","\xd4ng l\xe3o n\xe0y t\u1eebng kh\u1eafc l\u1ea1i t\xean ng\u01b0\u1eddi ch\u1ebft sau m\u1ed7i \u0111\u1ee3t lo\u1ea1n \u0111\u1ec3 h\u1ecd kh\xf4ng bi\u1ebfn m\u1ea5t l\u1ea7n th\u1ee9 hai trong qu\xean l\xe3ng. Khi tri\u1ec1u r\u1ed7ng b\u1eaft \u0111\u1ea7u nu\u1ed1t c\u1ea3 ch\u1eef vi\u1ebft, \xf4ng h\xf3a \u0111\xe1 \u0111\u1ec3 gi\u1eef l\u1ea5y ngh\u1ec1 l\xe0m ch\u1ee9ng cho ng\u01b0\u1eddi v\xf4 danh.")
B.aph=new A.c1("S\xe2n \u0110\xe1 Kh\xf4ng D\u1ea5u Ch\xe2n","M\u1eabu Th\u1ea1ch B\u1ed3ng Nhi","T\u01b0\u1ee3ng ng\u01b0\u1eddi m\u1eb9 c\xfai \xf4m m\u1ed9t kh\u1ed1i \u0111\xe1 nh\u1ecf nh\u01b0 \xf4m tr\u1ebb con ng\u1ee7. S\xe2n nh\xe0 hoang r\u1ed9ng nh\u01b0 v\u1eady m\xe0 kh\xf4ng c\xf2n b\u1ea5t k\u1ef3 d\u1ea5u ch\xe2n n\xe0o ngo\xe0i r\u1ec5 c\u1ecf xuy\xean qua k\u1ebd g\u1ea1ch.","N\xe0ng t\u1eebng c\xf5ng n\u0103m \u0111\u1ee9a tr\u1ebb kh\xf4ng c\xf9ng huy\u1ebft th\u1ed1ng ch\u1ea1y qua n\u1eeda th\xe0nh khi kh\xf3i \u0111en tr\xe0n xu\u1ed1ng. \u0110\u1ee9a cu\u1ed1i c\xf9ng s\u1ed1ng s\xf3t \u0111\xe3 xin \u0111\u1ebdo n\xe0ng th\xe0nh t\u01b0\u1ee3ng \u0111\xfang t\u01b0 th\u1ebf \xf4m con, \u0111\u1ec3 k\xfd \u1ee9c v\u1ec1 l\xf2ng t\u1ed1t kh\xf4ng b\u1ecb th\u1eddi gian b\xf3p m\xe9o.")
B.apU=new A.c1("Gi\u1ebfng C\u1ea1n M\u1ecdc C\u1ecf","L\xe3o Th\u1ee7 T\u1ec9nh","B\xe0n tay t\u01b0\u1ee3ng th\xf2 xu\u1ed1ng l\xf2ng gi\u1ebfng kh\xf4, nh\u01b0 v\u1eabn c\u1ed1 m\xfac n\u1ed1t g\xe1o n\u01b0\u1edbc cu\u1ed1i c\xf9ng. Quanh mi\u1ec7ng gi\u1ebfng ch\u1ec9 to\xe0n c\u1ecf d\u1ea1i v\xe0 d\xe2y leo qu\u1ea5n l\u1ea5y nh\u1eefng th\xf9ng g\u1ed7 m\u1ee5c.","L\xe3o gi\u1eef gi\u1ebfng \u0111\xe3 chia ph\u1ea7n n\u01b0\u1edbc cu\u1ed1i cho ng\u01b0\u1eddi l\u1ea1 tr\u01b0\u1edbc c\u1ea3 h\u1ecd h\xe0ng ru\u1ed9t th\u1ecbt c\u1ee7a m\xecnh. Khi n\u01b0\u1edbc m\u1ea5t, l\xe3o h\xf3a \u0111\xe1 b\xean mi\u1ec7ng gi\u1ebfng \u0111\u1ec3 nh\u1eefng ng\u01b0\u1eddi t\u1edbi sau bi\u1ebft r\u1eb1ng v\xf9ng \u0111\u1ea5t n\xe0y t\u1eebng c\xf3 k\u1ebb ch\u1ecdn c\xf4ng b\u1eb1ng thay v\xec b\u1ea3n n\u0103ng s\u1ed1ng s\xf3t.")
B.apl=new A.c1("Th\u1ec1m Nh\xe0 S\u1eadp N\u1eafng","Ch\u01b0\u1edfng B\u1ea1 B\u01b0ng Bia","T\u01b0\u1ee3ng gi\xe0 g\u1eadp l\u01b0ng \xf4m m\u1ed9t phi\u1ebfn \u0111\xe1 gia ph\u1ea3 \u0111\xe3 n\u1ee9t \u0111\xf4i. \xc1nh n\u1eafng r\u1ecdi qua m\xe1i s\u1eadp khi\u1ebfn b\xf3ng t\u01b0\u1ee3ng ng\u1eafn l\u1ea1i nh\u01b0 m\u1ed9t ng\u01b0\u1eddi ch\u01b0a t\u1eebng \u0111\u01b0\u1ee3c v\xe0o nh\xe0 l\u1ea7n cu\u1ed1i.","\xd4ng t\u1eebng ch\u1ea1y kh\u1eafp ph\u1ed1 gom gia ph\u1ea3, kh\u1ebf \u0111\u1ea5t v\xe0 th\u01b0 tay c\u1ee7a c\xe1c gia \u0111\xecnh b\u1ecb x\xf3a s\u1ed5 \u0111\u1ec3 ch\xf4n th\xe0nh kho l\u01b0u ni\u1ec7m chung. H\xf3a \u0111\xe1 v\u1edbi phi\u1ebfn gia ph\u1ea3 tr\xean tay l\xe0 c\xe1ch \xf4ng gi\u1eef h\u1ed9 m\u1ed9t qu\xea h\u01b0\u01a1ng \u0111\xe3 kh\xf4ng c\xf2n ai v\u1ec1 nh\u1eadn.")
B.apd=new A.c1("H\xe0nh Lang Gi\xf3 X\xe1m","N\xf4ng Phu Gi\u1eef V\u1ee5","Tr\xean vai t\u01b0\u1ee3ng v\u1eabn l\xe0 b\xf3 l\xfaa \u0111\xe1 \u0111\xe3 h\xf3a th\xe0nh m\xe0u ch\xec. M\u1ed7i \u0111\u1ee3t gi\xf3 th\u1ed5i qua h\xe0nh lang \u0111\u1ec1u mang m\xf9i \u0111\u1ea5t \u1ea9m nh\u01b0 m\xf9a g\u1eb7t ch\u01b0a k\u1ecbp kh\xe9p.","Ng\u01b0\u1eddi n\xf4ng phu n\xe0y bi\u1ebft m\xf9a cu\u1ed1i c\xf9ng ch\u1eafc ch\u1eafn th\u1ea5t b\u1ea1i nh\u01b0ng v\u1eabn gieo \u0111\u1ee7 m\u1ed9t th\u1eeda ru\u1ed9ng \u0111\u1ec3 b\u1ecdn tr\u1ebb nh\u1edb \u0111\u1ea5t t\u1eebng nu\xf4i ng\u01b0\u1eddi ra sao. H\u1eafn h\xf3a \u0111\xe1 gi\u1eefa h\xe0nh lang ch\u1ee9a l\xfaa, tr\u1edf th\xe0nh k\u1ebb canh gi\u1eef l\u1eddi h\u1ee9a r\u1eb1ng gi\u1ed1ng c\u0169 s\u1ebd c\xf2n ng\xe0y m\u1ecdc l\u1ea1i.")
B.apf=new A.c1("V\xf2m C\u1ed5ng D\xe2y Leo","Th\u1ee3 May C\u1edd R\xe1ch","T\u01b0\u1ee3ng th\u1ee3 may qu\u1ef3 b\xean kim \u0111\xe1, ph\xeda sau l\xe0 nh\u1eefng l\xe1 c\u1edd m\u1ee5c b\u1ecb d\xe2y leo xi\u1ebft ch\u1eb7t. C\xf3 v\xe0i m\u1ea3nh v\u1ea3i v\u1eabn c\xf2n m\xe0u \u0111\u1ecf c\u0169, nh\u01b0ng \u0111\xe3 nh\u1ea1t t\u1edbi m\u1ee9c g\u1ea7n nh\u01b0 m\xe0u m\xe1u kh\xf4.","N\xe0ng t\u1eebng v\xe1 c\u1edd c\u1ea7u c\u1ee9u, c\u1edd \u0111\u1ea7u h\xe0ng v\xe0 c\u1ea3 kh\u0103n tang cho c\xf9ng m\u1ed9t th\xe0nh ph\u1ed1 trong c\xf9ng m\u1ed9t th\xe1ng. Khi kh\xf4ng ai c\xf2n s\u1ee9c gi\u01b0\u01a1ng c\u1edd n\u1eefa, n\xe0ng h\xf3a \u0111\xe1 \u0111\u1ec3 gi\u1eef l\u1ea1i b\u1eb1ng ch\u1ee9ng r\u1eb1ng c\xf3 m\u1ed9t th\u1eddi ng\u01b0\u1eddi ta \u0111\xe3 c\u1ed1 c\u1ee9u nhau tr\u01b0\u1edbc khi tuy\u1ec7t v\u1ecdng ho\xe0n to\xe0n.")
B.apq=new A.c1("M\u1ed9 C\u1ed9t G\xe3y","K\u1ebb Gi\u1eef C\u1ea7u R\u1ec5","T\u01b0\u1ee3ng \u0111\u1ee9ng d\u1ea1ng ch\xe2n tr\xean \u0111o\u1ea1n tr\u1ee5 c\u1ea7u g\xe3y, hai tay si\u1ebft s\u1ee3i d\xe2y h\xf3a th\xe0nh r\u1ec5 c\xe2y. Nh\xecn t\u01b0 th\u1ebf \u1ea5y c\xf3 th\u1ec3 \u0111o\xe1n h\u1eafn \u0111\xe3 k\xe9o ai \u0111\xf3 qua v\u1ef1c trong m\u1ed9t c\u01a1n ho\u1ea3ng lo\u1ea1n r\u1ea5t d\xe0i.","Ng\u01b0\u1eddi gi\u1eef c\u1ea7u t\u1eebng ch\u1eb7t d\u1ea7m, bu\u1ed9c r\u1ec5 v\xe0 l\xe0m th\xe0nh chi\u1ebfc c\u1ea7u s\u1ed1ng cho d\xe2n ch\u1ea1y kh\u1ecfi l\u0169 s\u01b0\u01a1ng \u0103n th\u1ecbt. Khi ch\xednh m\xecnh kh\xf4ng c\xf2n s\u1ee9c r\u1eddi \u0111i, h\u1eafn xin h\xf3a \u0111\xe1 t\u1ea1i tr\u1ee5 g\xe3y \u0111\u1ec3 \u0111\u1eddi sau bi\u1ebft n\u01a1i n\xe0y t\u1eebng c\xf3 m\u1ed9t l\u1ed1i tho\xe1t \u0111\u01b0\u1ee3c gi\u1eef b\u1eb1ng th\xe2n ng\u01b0\u1eddi.")
B.apJ=new A.c1("B\u1ec7 Chu\xf4ng N\u1ee9t","Ng\u01b0\u1eddi G\xf5 Chu\xf4ng Tro","B\xfaa chu\xf4ng tr\xean tay t\u01b0\u1ee3ng ch\u1ec9 c\xf2n n\u1eeda c\xe1n, nh\u01b0ng t\u01b0 th\u1ebf \u0111\xe1nh xu\u1ed1ng v\u1eabn r\u1ea5t r\xf5. Chung quanh b\u1ec7 chu\xf4ng to\xe0n tro c\u0169, nh\u01b0 th\u1ec3 ti\u1ebfng b\xe1o nguy cu\u1ed1i c\xf9ng \u0111\xe3 b\u1ecb b\u1ee5i th\u1eddi gian ch\xf4n ngay t\u1ea1i ch\u1ed7.","\xd4ng l\xe3o tr\xf4ng chu\xf4ng g\xf5 li\xean t\u1ee5c ba ng\xe0y ba \u0111\xeam \u0111\u1ec3 b\xe1o t\u1eebng l\u1edbp d\xe2n trong th\xe0nh r\xfat kh\u1ecfi khu d\u1ecbch th\u1ea1ch. Chu\xf4ng v\u1ee1 tr\u01b0\u1edbc khi \xf4ng g\u1ee5c, n\xean \xf4ng \u0111\u1ec3 m\xecnh th\xe0nh t\u01b0\u1ee3ng canh b\u1ec7 chu\xf4ng, l\xe0m ti\u1ebfng c\u1ea3nh b\xe1o im l\u1eb7ng cho t\u1ea5t c\u1ea3 k\u1ebb \u0111\u1ebfn sau.")
B.ap7=new A.c1("\u0110\u1ed3i Bia L\xfan","Tinh Quan Ch\u1ec9 T\u1ecbch","T\u01b0\u1ee3ng ng\u1ea9ng m\u1ed9t ng\xf3n tay l\xean b\u1ea7u tr\u1eddi x\xe1m nh\u01b0 v\u1eabn \u0111ang ch\u1ec9 m\u1ed9t v\xec sao \u0111\xe3 ch\u1ebft. \u0110\u1ed3i bia quanh \u0111\xf3 nghi\xeang l\xfan theo n\u0103m th\xe1ng, c\xf2n h\u01b0\u1edbng tay t\u01b0\u1ee3ng v\u1eabn kh\xf4ng l\u1ec7ch l\u1ea5y m\u1ed9t ph\xe2n.","Tinh quan cu\u1ed1i c\xf9ng l\xe0 ng\u01b0\u1eddi \u0111\u1ea7u ti\xean ph\xe1t hi\u1ec7n b\u1ea7u tr\u1eddi n\u01a1i n\xe0y ng\u1eebng tr\xf4i v\xe0 m\u1eb7t tr\u1eddi b\u1eaft \u0111\u1ea7u m\u1ee5c d\u1ea7n nh\u01b0 m\u1ed9t x\xe1c \u0111\xe8n. \xd4ng h\xf3a \u0111\xe1 \u0111\u1ec3 gi\u1eef nguy\xean h\u01b0\u1edbng ch\u1ec9, bi\u1ebfn ch\xednh m\xecnh th\xe0nh l\u1eddi nh\u1eafc r\u1eb1ng th\u1ea3m h\u1ecda \u1edf \u0111\xe2y b\u1eaft \u0111\u1ea7u t\u1eeb tr\u1eddi cao r\u1ed3i m\u1edbi nu\u1ed1t xu\u1ed1ng nh\xe2n gian.")
B.apy=new A.c1("Ch\u1ee3 \u0110\xe1 T\u1eaft Ti\u1ebfng","Th\u01b0\u01a1ng N\u1eef C\xe2n \u0110\xe1","T\u01b0\u1ee3ng ng\u01b0\u1eddi b\xe1n h\xe0ng gi\u1eef chi\u1ebfc c\xe2n \u0111\u0129a tr\xean \u0111\u1ea7u g\u1ed1i, hai \u0111\u0129a c\xe2n \u0111\u1ec1u \u0111\u1ea7y s\u1ecfi. Nh\u1eefng qu\u1ea7y ch\u1ee3 xung quanh b\u1ecb c\u1ecf cao che l\u1ea5p, ch\u1ec9 c\xf2n nghe ti\u1ebfng l\xe1 c\u1ecd nhau nh\u01b0 \xe2m thanh m\u1eb7c c\u1ea3 \u0111\xe3 h\xf3a c\xe2m.","N\xe0ng th\u01b0\u01a1ng n\u1eef \u0111\u1ed5i h\u1ebft b\u1ea1c c\xf2n l\u1ea1i l\u1ea5y kh\u1ea9u ph\u1ea7n chung r\u1ed3i chia theo c\xe2n c\xf4ng b\u1eb1ng cho nh\u1eefng ng\u01b0\u1eddi kh\xf4ng quen bi\u1ebft. H\xf3a \u0111\xe1 b\xean chi\u1ebfc c\xe2n l\xe0 c\xe1ch n\xe0ng bu\u1ed9c th\u1eddi gian ph\u1ea3i nh\u1edb r\u1eb1ng trong c\u01a1n \u0111\xf3i v\u1eabn c\xf3 ng\u01b0\u1eddi gi\u1eef \u0111\u01b0\u1ee3c th\u01b0\u1edbc \u0111o l\u01b0\u01a1ng t\xe2m.")
B.apG=new A.c1("Kho Th\xf3c H\xf3a R\xeau","L\xe3o Qu\u1ea3n Kho","T\u01b0\u1ee3ng gi\xe0 ng\u1ed3i ch\u1eafn tr\u01b0\u1edbc c\u1eeda kho, ch\xeca kh\xf3a \u0111\xe1 n\u1eb1m g\u1ecdn trong l\xf2ng b\xe0n tay n\u1ee9t. M\xf9i r\u01a1m c\u0169 tr\u1ed9n v\u1edbi r\xeau \u01b0\u1edbt khi\u1ebfn c\u0103n kho gi\u1ed1ng m\u1ed9t ng\xf4i m\u1ed9 gi\u1eef m\xf9a v\u1ee5 \u0111\xe3 m\u1ea5t.","L\xe3o qu\u1ea3n kho t\u1eebng ch\u1ed1ng l\u1ec7nh t\u1ea7ng tr\xean \u0111\u1ec3 m\u1edf kho c\u1ee9u d\xe2n thay v\xec gi\u1eef cho qu\xe2n \u0111\u1ed9i. Khi b\u1ecb k\u1ebft t\u1ed9i ph\u1ea3n ngh\u1ecbch, l\xe3o xin bi\u1ebfn th\xe0nh t\u01b0\u1ee3ng ngay tr\u01b0\u1edbc c\u1eeda kho nh\u01b0 m\u1ed9t b\u1ea3n \xe1n v\u0129nh vi\u1ec5n d\xe0nh cho nh\u1eefng k\u1ebb \u0111\u1eb7t m\u1ea1ng ng\u01b0\u1eddi sau con d\u1ea5u quy\u1ec1n l\u1ef1c.")
B.apH=new A.c1("Ph\u01b0\u1eddng R\xe8n T\xe0n Tro","Th\u1ee3 R\xe8n M\xe0i Gi\xfap","T\u01b0\u1ee3ng th\u1ee3 r\xe8n ng\u1ed3i b\xean b\xe0n \u0111e, l\u01b0\u1ee1i ki\u1ebfm \u0111\xe1 tr\xean tay l\u1ea1i h\u01b0\u1edbng chu\xf4i v\u1ec1 ph\xeda ng\u01b0\u1eddi \u0111\u1ed1i di\u1ec7n ch\u1ee9 kh\xf4ng ch\u0129a ra ngo\xe0i. C\u1ea3 x\u01b0\u1edfng \u0111\xe3 t\u1eaft t\u1eeb l\xe2u nh\u01b0ng m\u1eb7t \u0111e v\u1eabn c\xf2n nh\u1eefng v\u1ec7t m\xe0i ngang d\u1ecdc.","\xd4ng kh\xf4ng r\xe8n v\u0169 kh\xed cho vinh quang m\xe0 m\xe0i l\u1ea1i n\xf4ng c\u1ee5, dao b\u1ebfp v\xe0 k\xe9o c\u1ee9u th\u01b0\u01a1ng cho d\xe2n trong c\u01a1n t\u1eadn th\u1ebf. Khi tay kh\xf4ng nh\u1ea5c n\u1ed5i b\xfaa n\u1eefa, \xf4ng h\xf3a \u0111\xe1 b\xean b\xe0n \u0111e \u0111\u1ec3 k\u1ec3 r\u1eb1ng c\xf3 nh\u1eefng x\u01b0\u1edfng r\xe8n t\u1ed3n t\u1ea1i ch\u1ec9 \u0111\u1ec3 gi\xfap ng\u01b0\u1eddi kh\xe1c s\u1ed1ng th\xeam m\u1ed9t ng\xe0y.")
B.apa=new A.c1("H\u1ecdc C\xe1c M\xf2n M\u1ef1c","Th\u1ea7y \u0110\xe1 Ch\u1ea5p B\xfat","B\u1ee9c t\u01b0\u1ee3ng ng\u1ed3i sau \xe1n th\u01b0, \u0111\u1ea7u b\xfat \u0111\xe1 ch\u1ea1m nh\u1eb9 xu\u1ed1ng m\u1eb7t b\xe0n nh\u01b0 ti\u1ebft h\u1ecdc v\u1eabn ch\u01b0a tan. M\u1ef1c tr\xean gi\xe1 \u0111\xe3 kh\xf4 th\xe0nh b\u1ed9t, nh\u01b0ng h\xe0ng gh\u1ebf h\u1ecdc tr\xf2 c\xf2n \u0111\u1ee7 v\u1ebft kh\u1eafc t\xean tr\u1ebb nh\u1ecf.","Ng\u01b0\u1eddi th\u1ea7y n\xe0y d\u1ea1y l\u0169 tr\u1ebb vi\u1ebft l\u1ea1i t\xean cha m\u1eb9 v\xe0 qu\xea qu\xe1n m\u1ed7i s\xe1ng \u0111\u1ec3 ch\xfang kh\xf4ng qu\xean m\xecnh thu\u1ed9c v\u1ec1 \u0111\xe2u khi s\u01a1 t\xe1n. \xd4ng t\u1ef1 bi\u1ebfn th\xe0nh t\u01b0\u1ee3ng c\xf9ng n\xe9t b\xfat dang d\u1edf, \u0111\u1ec3 b\xe0i h\u1ecdc cu\u1ed1i c\xf9ng c\u1ee7a m\xecnh l\xe0 m\u1ed9t l\u1eddi ch\u1ed1ng l\u1ea1i s\u1ef1 x\xf3a b\u1ecf k\xfd \u1ee9c.")
B.apM=new A.c1("S\xe2n T\u1ebf N\u1ee9t Tr\u0103ng","T\u01b0 T\u1ebf Kh\xf4ng Th\u1ea7n","T\u01b0\u1ee3ng t\u01b0 t\u1ebf qu\u1ef3 gi\u1eefa s\xe2n t\u1ebf \u0111\u1ed5, l\xf2ng b\xe0n tay m\u1edf ra nh\u01b0ng kh\xf4ng c\xf2n v\u1eadt c\xfang n\xe0o trong \u0111\xf3. V\u1ec7t n\u1ee9t tr\xean n\u1ec1n \u0111\xe1 ch\u1ea1y th\xe0nh m\u1ed9t \u0111\u01b0\u1eddng tr\xf2n nh\u01b0 v\u1ea7ng tr\u0103ng b\u1ecb \u0111\u1eadp v\u1ee1 ngay d\u01b0\u1edbi \u0111\u1ea5t.","\xd4ng t\u1eebng l\xe0 ng\u01b0\u1eddi ch\u1ee7 tr\xec nghi l\u1ec5 c\u1ea7u c\u1ee9u, r\u1ed3i l\xe0 k\u1ebb \u0111\u1ea7u ti\xean \u0111\u1ee9ng l\xean tuy\xean b\u1ed1 th\u1ea7n linh \u0111\xe3 b\u1ecf m\u1eb7c v\xf9ng \u0111\u1ea5t n\xe0y. H\xf3a \u0111\xe1 trong t\u01b0 th\u1ebf tay kh\xf4ng, \xf4ng \u0111\u1ec3 l\u1ea1i m\u1ed9t ch\u1ee9ng t\xedch r\u1eb1ng sau c\xf9ng con ng\u01b0\u1eddi ch\u1ec9 c\xf2n c\xf3 th\u1ec3 c\u1ee9u nhau b\u1eb1ng ch\xednh \u0111\xf4i tay tr\u1ed1ng r\u1ed7ng c\u1ee7a m\xecnh.")
B.apm=new A.c1("B\u1eadc Quan \u0110\xe0i","Quan \xc1n C\u1ee5t \u0110\u1ea7u","T\u01b0\u1ee3ng c\u1ee5t ph\u1ea7n \u0111\u1ea7u nh\u01b0ng th\xe2n v\u1eabn ng\u1ed3i ngay ng\u1eafn tr\xean b\u1eadc x\u1eed \xe1n. Nh\u1eefng b\u1ea3n \u0111\xe1 d\u01b0\u1edbi ch\xe2n kh\u1eafc la li\u1ec7t t\xean v\u1ee5 ki\u1ec7n c\xf2n dang d\u1edf v\xe0 nh\u1eefng d\u1ea5u m\xf3ng tay c\xe0o t\u1edbi b\u1eadt m\xe1u.","V\u1ecb quan n\xe0y ch\u1eb7t \u0111\u1ea7u ch\xednh m\xecnh trong chi\u1ebfu th\u01b0 h\xf3a th\u1ea1ch \u0111\u1ec3 kh\u1ecfi ph\u1ea3i k\xfd th\xeam \xe1n oan cho tri\u1ec1u \u0111\xecnh \u0111ang th\u1ed1i r\u1eefa. T\u01b0\u1ee3ng v\xf4 th\u1ee7 n\u01a1i \u0111\xe2y \u0111\xe3 nh\xecn h\xe0ng tr\u0103m n\u0103m c\u1ecf m\u1ecdc qua ph\xe1p \u0111\xecnh, nh\u01b0 m\u1ed9t l\u1eddi bu\u1ed9c t\u1ed9i kh\xf4ng bao gi\u1edd kh\xe9p l\u1ea1i.")
B.apC=new A.c1("C\u1ea7u Kh\u1eafc N\u0103m","Ng\u01b0\u1eddi \u0110\u1ebfm L\u0169","M\u1ed7i nh\u1ecbp c\u1ea7u \u0111\u1ec1u kh\u1eafc m\u1ed9t v\u1ea1ch s\xe2u, c\xf2n t\u01b0\u1ee3ng \u0111\xe1 \u0111\u1ee9ng cu\u1ed1i c\u1ea7u c\u1ea7m b\u1ea3ng g\u1ed7 chi ch\xedt con s\u1ed1. D\xf2ng n\u01b0\u1edbc d\u01b0\u1edbi c\u1ea7u \u0111\xe3 c\u1ea1n t\u1eeb l\xe2u, nh\u01b0ng th\xf3i quen ghi l\u1ea1i m\xf9a l\u0169 d\u01b0\u1eddng nh\u01b0 ch\u01b0a t\u1eebng r\u1eddi kh\u1ecfi h\u1eafn.","Ng\u01b0\u1eddi canh c\u1ea7u \u0111\xe3 \u0111\u1ebfm kh\xf4ng ph\u1ea3i n\u01b0\u1edbc m\xe0 l\xe0 s\u1ed1 gia \u0111\xecnh v\u01b0\u1ee3t sang b\u1edd an to\xe0n qua m\u1ed7i \u0111\u1ee3t t\u1ea3n c\u01b0. H\u1eafn h\xf3a \u0111\xe1 c\xf9ng t\u1ea5m b\u1ea3ng \u0111\u1ec3 v\u1ec1 sau khi kh\xf4ng c\xf2n ai s\u1ed1ng, c\xe2y c\u1ea7u v\u1eabn c\xf2n bi\u1ebft \u0111\xe3 t\u1eebng c\xf3 bao nhi\xeau m\u1ea1ng ng\u01b0\u1eddi \u0111\u01b0\u1ee3c \u0111\u01b0a qua \u0111\xe2y.")
B.apv=new A.c1("\u0110\xecnh L\u1ec7nh G\xe3y","Hi\u1ec7u L\u1ec7nh Cu\u1ed1i","T\u01b0\u1ee3ng mang n\u1eeda chi\u1ebfc tr\u1ed1ng l\u1ec7nh \u0111eo tr\u01b0\u1edbc ng\u1ef1c, t\u01b0 th\u1ebf nh\u01b0 chu\u1ea9n b\u1ecb gi\xf3ng th\xeam m\u1ed9t h\u1ed3i n\u1eefa. \u0110\xecnh l\xe0ng \u0111\xe3 s\u1eadp m\xe1i, ch\u1ec9 c\xf2n c\u1ed9t k\xe8o g\xe3y ng\u1ea3 v\xe0o nhau nh\u01b0 \u0111\xe1m ng\u01b0\u1eddi ki\u1ec7t s\u1ee9c.","\xd4ng tr\u01b0\u1edfng \u0111\xecnh d\xf9ng tr\u1ed1ng l\xe0ng \u0111\u1ec3 \u0111\u1ed5i c\xf4ng d\u1ee5ng, kh\xf4ng g\u1ecdi h\u1ed9i m\xe0 b\xe1o gi\u1edd di t\u1ea3n cho t\u1eebng ph\u1ed1. Khi ti\u1ebfng tr\u1ed1ng cu\u1ed1i c\xf9ng v\u1ee1 ra, \xf4ng h\xf3a \u0111\xe1 tr\u01b0\u1edbc \u0111\xecnh \u0111\u1ec3 bi\u1ebfn ch\xednh im l\u1eb7ng th\xe0nh m\u1ec7nh l\u1ec7nh ph\u1ea3i nh\u1edb l\u1ea5y nh\u1eefng ng\xe0y d\xe2n l\xe0ng c\xf2n bi\u1ebft g\u1ecdi nhau b\u1eb1ng t\xean.")
B.apx=new A.c1("V\u01b0\u1eddn T\u01b0\u1ee3ng C\xe2m","Ng\u1ef1 Th\u1ecb B\u1ecbt M\u1eaft","Trong v\u01b0\u1eddn to\xe0n t\u01b0\u1ee3ng h\u1ea7u c\u1eadn kh\xf4ng m\u1eaft, ri\xeang t\u01b0\u1ee3ng gi\u1eefa s\xe2n d\xf9ng ch\xednh hai tay b\u1ecbt l\xean m\u1eb7t m\xecnh. R\u1ec5 c\xe2y m\u1ecdc xuy\xean qua mi\u1ec7ng t\u01b0\u1ee3ng l\xe0m khu\xf4n m\u1eb7t c\xe2m l\u1eb7ng \u1ea5y c\xe0ng kh\xf3 nh\xecn.","N\u1ed9i th\u1ecb n\xe0y t\u1eebng ch\u1ee9ng ki\u1ebfn ho\xe0ng gia d\xf9ng thu\u1eadt th\u1ea1ch h\xf3a l\xean d\xe2n \u0111en tr\u01b0\u1edbc khi c\xf4ng b\u1ed1 s\u1ef1 th\u1eadt v\u1edbi tri\u1ec1u th\u1ea7n. \xd4ng t\u1ef1 h\u1ee7y m\u1eaft r\u1ed3i h\xf3a \u0111\xe1 \u0111\u1ec3 \u0111\u1eddi sau bi\u1ebft s\u1ef1 im l\u1eb7ng c\u1ee7a k\u1ebb h\u1ea7u c\u1eadn c\u0169ng l\xe0 m\u1ed9t ph\u1ea7n t\u1ed9i l\u1ed7i trong m\u1ecdi v\u01b0\u01a1ng tri\u1ec1u m\u1ee5c ru\u1ed7ng.")
B.apL=new A.c1("C\u1eeda B\u1eafc B\u1ee5i D\xe0y","L\xe3o K\u1ef5 Kh\xf4ng Y\xean","T\u01b0\u1ee3ng l\xednh gi\xe0 n\u1eafm d\xe2y c\u01b0\u01a1ng c\u1ee7a m\u1ed9t con chi\u1ebfn m\xe3 \u0111\xe1 \u0111\xe3 g\xe3y y\xean. C\u1eeda b\u1eafc ph\u1ee7 b\u1ee5i d\xe0y t\u1edbi m\u1ee9c kh\xf4ng r\xf5 l\u1ea7n cu\u1ed1i c\xf3 ai c\u01b0\u1ee1i qua n\u01a1i n\xe0y l\xe0 v\xe0o n\u0103m n\xe0o.","L\xe3o k\u1ef5 binh t\u1eebng d\xf9ng ng\u1ef1a ch\u1edf tr\u1ebb b\u1ecb th\u01b0\u01a1ng r\u1eddi th\xe0nh thay v\xec tham chi\u1ebfn cho vua. \xd4ng h\xf3a \u0111\xe1 c\u1ea1nh con chi\u1ebfn m\xe3 sau khi th\u1ea3 n\xf3 v\u1ec1 \u0111\u1ed3ng, \u0111\u1ec3 hai k\u1ebb gi\xe0 nua c\xf9ng tr\xf4ng l\u1ed1i b\u1eafc \u0111\xe3 t\u1eebng l\xe0 \u0111\u01b0\u1eddng s\u1ed1ng c\u1ee7a r\u1ea5t nhi\u1ec1u \u0111\u1ee9a tr\u1ebb.")
B.apr=new A.c1("L\u0169y Th\xe0nh Ch\xf4n C\u1edd","K\u1ebb Ch\xf4n Hi\u1ec7u K\u1ef3","T\u01b0\u1ee3ng qu\u1ef3 b\xean \u1ee5 \u0111\u1ea5t, n\u1eeda c\xe1n c\u1edd \u0111\xe1 v\u1eeba c\u1eafm xu\u1ed1ng v\u1eeba b\u1ecb ch\xf4n l\u1ea5p. Gi\xf3 cao qu\u1ea5t qua l\u0169y th\xe0nh nghe nh\u01b0 ti\u1ebfng v\u1ea3i m\u1ee5c x\xe9 th\xe0nh t\u1eebng d\u1ea3i d\xe0i v\xf4 t\u1eadn.","H\u1eafn l\xe0 ng\u01b0\u1eddi l\xednh tr\u1ebb cu\u1ed1i c\xf9ng hi\u1ec3u r\u1eb1ng gi\u1eef c\u1edd kh\xf4ng c\xf2n ngh\u0129a g\xec khi d\xe2n \u0111\xe3 ch\u1ebft s\u1ea1ch sau l\u01b0ng th\xe0nh. Ch\xf4n c\u1edd r\u1ed3i h\xf3a \u0111\xe1 t\u1ea1i \u0111\xf3, h\u1eafn bu\u1ed9c chi\u1ebfn tranh ph\u1ea3i nh\u1eadn l\u1ea5y m\u1ed9t bia m\u1ed9 thay v\xec m\u1ed9t b\u1ea3n anh h\xf9ng ca d\u1ed1i tr\xe1.")
B.apE=new A.c1("Doanh Tr\u1ea1i H\xf3a R\u1ec5","T\u01b0\u1edbng C\xe2m Gi\u1eef Qu\xe2n","T\u01b0\u1ee3ng t\u01b0\u1edbng qu\xe2n ng\u1ed3i th\u1eb3ng l\u01b0ng gi\u1eefa doanh tr\u1ea1i m\u1ee5c n\xe1t, m\xf4i kh\xf4ng kh\u1eafc th\xe0nh h\xecnh m\u1edf ra d\xf9 r\xf5 r\xe0ng \u0111ang mu\u1ed1n ra l\u1ec7nh. R\u1ec5 c\xe2y qu\u1ea5n quanh nh\u1eefng c\u1ecdc tr\u1ea1i nh\u01b0 l\xednh g\xe1c m\u1edbi c\u1ee7a m\u1ed9t \u0111\u1ed9i qu\xe2n \u0111\xe3 tan.","V\u1ecb t\u01b0\u1edbng n\xe0y im l\u1eb7ng sau khi bi\u1ebft m\u1ed7i m\u1ec7nh l\u1ec7nh ti\u1ebfp theo ch\u1ec9 c\xf2n khi\u1ebfn qu\xe2n s\u0129 ch\u1ebft \u0111\u1ec3 che l\u1ed7i cho tri\u1ec1u \u0111\xecnh. \xd4ng h\xf3a \u0111\xe1 gi\u1eefa doanh tr\u1ea1i \u0111\u1ec3 gi\u1eef y\xean h\u1ecd l\u1ea1i trong k\xfd \u1ee9c, kh\xf4ng cho ai v\u1ec1 sau g\u1ecdi \u0111\xe1m binh \u0111\xe3 hi sinh v\xf4 \xedch \u1ea5y l\xe0 nh\u1eefng con s\u1ed1 v\xf4 danh.")
B.apN=new A.c1("Khe Khi\xean V\u1ee1","Thu\u1eabn Binh M\u1ed9t M\u1eaft","T\u01b0\u1ee3ng chi\u1ebfn binh t\xec n\u1eeda t\u1ea5m khi\xean v\u1ee1 xu\u1ed1ng \u0111\u1ea5t, m\u1ed9t h\u1ed1c m\u1eaft r\u1ed7ng h\u01b0\u1edbng th\u1eb3ng v\u1ec1 khe n\xfai. \u0110\xe1 quanh ch\xe2n h\u1eafn \u0111\u1ea7y v\u1ebft c\u1eaft ch\xe9o, nh\u01b0 c\xf3 c\u1ea3 m\u1ed9t \u0111\u01a1n v\u1ecb t\u1eebng ch\u1ebft \u0111\u1ee9ng t\u1ea1i \u0111i\u1ec3m ch\u1eb7n n\xe0y.","Thu\u1eabn binh m\u1ed9t m\u1eaft \u0111\xe3 ch\u1eb7n khe n\xfai \u0111\u1ee7 l\xe2u \u0111\u1ec3 \u0111o\xe0n th\u01b0\u1eddng d\xe2n ph\xeda sau v\u01b0\u1ee3t qua c\u01a1n truy s\xe1t. H\u1eafn xin h\xf3a \u0111\xe1 c\xf9ng chi\u1ebfc khi\xean n\u1ee9t \u0111\u1ec3 v\u1ebft ph\xf2ng th\u1ee7 cu\u1ed1i c\xf9ng kh\xf4ng b\u1ecb ng\u01b0\u1eddi \u0111\u1eddi \u0111\u1ed5i t\xean th\xe0nh th\u1ea5t b\u1ea1i.")
B.apj=new A.c1("B\u1ec7 Ph\xe1o C\u1ecf Ch\xe1y","Ph\xe1o Th\u1ee7 G\xe3y Tay","T\u01b0\u1ee3ng ch\u1ec9 c\xf2n m\u1ed9t c\xe1nh tay t\u1ef1a v\xe0o b\u1ec7 ph\xe1o \u0111\xe1 \u0111\xe3 ph\u1ee7 c\u1ecf ch\xe1y. Tr\xean n\xf2ng ph\xe1o c\xf2n kh\u1eafc r\u1ea5t s\xe2u nh\u1eefng d\u1ea5u \u0111\u1ebfm nh\u01b0 th\u1ec3 c\xf3 ng\u01b0\u1eddi \u0111\xe3 c\u1ea9n th\u1eadn ghi t\u1eebng l\u1ea7n b\u1eafn t\u1edbi vi\xean cu\u1ed1i.","Ng\u01b0\u1eddi ph\xe1o th\u1ee7 \u0111\u1ed5i m\u1ee5c ti\xeau t\u1eeb qu\xe2n \u0111\u1ecbch sang c\xe1c v\xe1ch n\xfai \u0111\u1ec3 m\u1edf \u0111\u01b0\u1eddng s\u1eadp, ch\u1eb7n s\u01b0\u01a1ng \u0111\xe1 lan t\u1edbi khu s\u01a1 t\xe1n. C\xe1nh tay m\u1ea5t \u0111i tr\u01b0\u1edbc khi \xf4ng k\u1ecbp r\xfat lui, v\xe0 b\u1ec7 ph\xe1o tr\u1edf th\xe0nh n\u01a1i \xf4ng h\xf3a \u0111\xe1 \u0111\u1ec3 canh gi\u1eef quy\u1ebft \u0111\u1ecbnh t\xe0n nh\u1eabn nh\u01b0ng c\u1ee9u \u0111\u01b0\u1ee3c nhi\u1ec1u m\u1ea1ng ng\u01b0\u1eddi.")
B.apt=new A.c1("H\u1ebbm Ng\u01b0\u1eddi G\xe1nh \u0110\xe1","Phu D\u1ecbch L\u01b0ng C\xf2ng","T\u01b0\u1ee3ng phu d\u1ecbch g\xe1nh \u0111\xf2n \u0111\xe1 tr\xean vai, c\u1ed9t s\u1ed1ng cong nh\u01b0 ch\u01b0a t\u1eebng \u0111\u01b0\u1ee3c du\u1ed7i th\u1eb3ng. H\u1ebbm s\xe2u sau l\u01b0ng h\u1eafn ch\u1ee9a \u0111\u1ea7y nh\u1eefng vi\xean k\xea t\u01b0\u1eddng dang d\u1edf c\u1ee7a m\u1ed9t c\xf4ng tr\xecnh kh\xf4ng bao gi\u1edd ho\xe0n th\xe0nh.","\xd4ng \u0111\xe3 d\u1eabn nh\xf3m d\xe2n \u0111en x\xe2y t\u01b0\u1eddng ch\u1eafn b\u1ee5i th\u1ea1ch cho tr\u1ebb nh\u1ecf n\u1ea5p t\u1ea1m, d\xf9 bi\u1ebft b\u1ea3n th\xe2n s\u1ebd b\u1ecb b\u1ecf m\u1eb7c sau c\xf9ng. H\xf3a \u0111\xe1 v\u1edbi \u0111\xf4i vai c\xf2n mang \u0111\xf2n g\xe1nh, \xf4ng gi\u1eef l\u1ea1i h\xecnh d\xe1ng c\u1ee7a m\u1ed9t t\u1ea7ng l\u1edbp th\u01b0\u1eddng b\u1ecb l\u1ecbch s\u1eed d\xf9ng xong r\u1ed3i qu\xean m\u1ea5t.")
B.apw=new A.c1("\u0110i\u1ec7n Vua N\u1ee9t M\xe1i","Th\u1ecb Th\u1ea7n Kh\xf4ng Ch\u1ee7","T\u01b0\u1ee3ng h\u1ea7u c\u1eadn \u0111\u1ee9ng ch\u1edd l\u1ec7nh d\u01b0\u1edbi m\xe1i \u0111i\u1ec7n n\u1ee9t l\xe0m \u0111\xf4i, \u0111\u1ea7u h\u01a1i c\xfai nh\u01b0 ng\u01b0\u1eddi \u0111\u1ed1i di\u1ec7n v\u1eabn c\xf2n ng\u1ed3i tr\xean ngai. Trong \u0111i\u1ec7n kh\xf4ng c\xf2n vua, ch\u1ec9 c\xf3 b\u1ee5i v\xe0 nh\u1eefng m\u1ea3nh r\xe8m r\xe1ch \u0111ung \u0111\u01b0a.","Th\u1ecb th\u1ea7n n\xe0y \u1edf l\u1ea1i \u0111i\u1ec7n tr\u1ed1ng su\u1ed1t b\u1ea3y ng\xe0y sau khi qu\xe2n v\u01b0\u01a1ng b\u1ecf ch\u1ea1y, ch\u1ec9 \u0111\u1ec3 gom t\xe0n th\u01b0 v\xe0 m\u1edf kho cho d\xe2n c\u01b0\u1edbp l\u01b0\u01a1ng. H\u1eafn h\xf3a \u0111\xe1 n\u01a1i b\u1eadc \u0111i\u1ec7n \u0111\u1ec3 ch\u1ee9ng minh r\u1eb1ng kh\xf4ng ph\u1ea3i m\u1ecdi k\u1ebb \u1edf g\u1ea7n ngai v\xe0ng \u0111\u1ec1u \u0111\u01b0\u1ee3c ph\xe9p t\u1ea9y s\u1ea1ch tr\xe1ch nhi\u1ec7m b\u1eb1ng hai ch\u1eef trung th\xe0nh.")
B.apk=new A.c1("T\xe0ng Th\u01b0 R\u01a1i L\xe1","S\u1eed Quan N\u1ee9t M\xf3ng","T\u01b0\u1ee3ng c\xfai tr\u01b0\u1edbc gi\xe1 s\xe1ch m\u1ee5c, \u0111\u1ea7u ng\xf3n tay n\u1ee9t to\xe1c nh\u01b0 t\u1eebng b\u1edbi t\xecm \u0111i\u1ec1u g\xec d\u01b0\u1edbi l\u1edbp gi\u1ea5y v\u1ee5n. L\xe1 kh\xf4 r\u01a1i k\xedn t\xe0ng th\u01b0, ch\xf4n t\u1eebng cu\u1ed1n s\u1eed nh\u01b0 ch\xf4n nhi\u1ec1u \u0111\u1eddi ng\u01b0\u1eddi v\xe0o c\xf9ng m\u1ed9t m\xf9a.","V\u1ecb s\u1eed quan n\xe0y \u0111\xe3 x\xe9 \xe1o b\u1ecdc l\u1ea5y nh\u1eefng trang ghi t\xean n\u1ea1n d\xe2n thay v\xec s\u1eafc l\u1ec7nh ca t\u1ee5ng vua. \xd4ng h\xf3a \u0111\xe1 trong t\xe0ng th\u01b0 \u0111\u1ec3 b\u1ea3n ghi ch\xe9p cu\u1ed1i c\xf9ng c\u1ee7a m\xecnh kh\xf4ng b\u1ecb s\u1eeda th\xe0nh m\u1ed9t tri\u1ec1u \u0111\u1ea1i ch\u1ebft trong s\u1ea1ch.")
B.apA=new A.c1("C\u1ed5ng H\u1ea7m Tro L\u1ea1nh","Ng\u1ee5c T\u1ed1t Th\u1ea3 Xi\u1ec1ng","T\u01b0\u1ee3ng ng\u1ee5c t\u1ed1t gi\u1eef ch\xf9m ch\xeca kh\xf3a \u0111\xe1 \u0111\xe3 g\xe3y n\u1eeda, ch\xe2n \u0111\u1ea1p l\xean m\u1ed9t \u0111o\u1ea1n xi\u1ec1ng r\u01a1i. H\u01a1i l\u1ea1nh t\u1eeb c\u1eeda h\u1ea7m tr\xe0n ra kh\xf4ng gi\u1ed1ng gi\xf3 m\xe0 gi\u1ed1ng ti\u1ebfng th\u1edf d\xe0i c\u1ee7a k\u1ebb v\u1eeba mu\u1ed9n m\u1ed9t b\u01b0\u1edbc.","Ng\u01b0\u1eddi coi ng\u1ee5c \u0111\xe3 m\u1edf h\u1ebft c\u1eeda h\u1ea7m cho t\xf9 nh\xe2n b\u1ecf tr\u1ed1n khi bi\u1ebft tr\xean m\u1eb7t \u0111\u1ea5t kh\xf4ng c\xf2n lu\u1eadt l\u1ec7 n\xe0o \u0111\xe1ng ph\u1ee5c t\xf9ng. H\u1eafn h\xf3a \u0111\xe1 c\xf9ng s\u1ee3i x\xedch \u0111\u1ee9t \u0111\u1ec3 nh\u1eafc r\u1eb1ng c\xf3 nh\u1eefng l\u1ea7n ph\u1ea3n b\u1ed9i b\u1ed5n ph\u1eadn l\u1ea1i ch\xednh l\xe0 kho\u1ea3nh kh\u1eafc m\u1ed9t con ng\u01b0\u1eddi b\u1eaft \u0111\u1ea7u s\u1ed1ng \u0111\xfang h\u01a1n.")
B.apb=new A.c1("\u0110\xe0i Thi\xean V\u0103n C\u0169","Tinh S\u01b0 Ch\u1edd Sao","T\u01b0\u1ee3ng \u0111\u1ee9ng b\xean th\u01b0\u1edbc ng\u1eafm b\u1ea7u tr\u1eddi \u0111\xe3 l\u1ec7ch kh\u1ecfi qu\u1ef9 \u0111\u1ea1o, m\u1eaft h\u01b0\u1edbng m\xe3i l\xean m\u1ea3ng m\xe2y x\xe1m \u0111\xf4ng c\u1ee9ng. \u0110\xe0i thi\xean v\u0103n m\u1ee5c h\u1ebft r\u1ed3i m\xe0 t\u01b0 th\u1ebf ch\u1edd \u0111\u1ee3i c\u1ee7a h\u1eafn v\u1eabn c\xf2n nguy\xean m\u1ed9t n\u1ed7i nh\u1eabn n\u1ea1i \u0111au \u0111\u1edbn.","Tinh s\u01b0 n\xe0y tin s\u1ebd c\xf3 m\u1ed9t ng\xf4i sao s\xe1ng tr\u1edf l\u1ea1i \u0111\u1ec3 b\xe1o thi\xean th\u1eddi h\u1ed3i ph\u1ee5c, n\xean ng\xe0y n\xe0o c\u0169ng tr\xe8o l\xean \u0111\xe0i quan s\xe1t d\xf9 tr\u1eddi kh\xf4ng c\xf2n chuy\u1ec3n \u0111\u1ed9ng. Khi hy v\u1ecdng cu\u1ed1i c\xf9ng t\u1eaft \u0111i, h\u1eafn h\xf3a \u0111\xe1 t\u1ea1i ch\u1ed7 ch\u1edd, bi\u1ebfn ni\u1ec1m tin kh\xf4ng th\xe0nh hi\u1ec7n th\u1ef1c th\xe0nh b\u1eb1ng ch\u1ee9ng r\u1eb1ng n\u01a1i \u0111\xe2y t\u1eebng ch\u1ed1ng c\u1ef1 c\u1ea3 tuy\u1ec7t v\u1ecdng b\u1eb1ng khoa h\u1ecdc l\u1eabn l\xf2ng ng\u01b0\u1eddi.")
B.apS=new A.c1("T\u1ea3ng Th\u1ec1 M\u1ee5c Ch\u1eef","H\u1ed9 \u1ea4n L\u1eddi Th\u1ec1","T\u01b0\u1ee3ng \xf4m m\u1ed9t h\u1ed9p \u1ea5n \u0111\xe1 tr\u01b0\u1edbc ng\u1ef1c, l\u01b0ng t\u1ef1a v\xe0o t\u1ea3ng th\u1ec1 \u0111\xe3 m\u1ee5c g\u1ea7n h\u1ebft ch\u1eef. Ch\u1ec9 c\xf2n v\xe0i n\xe9t kh\u1eafc s\xf3t l\u1ea1i \u0111\u1ee7 \u0111\u1ecdc th\xe0nh m\u1ed9t c\xe2u kh\xf4ng tr\u1ecdn v\u1eb9n v\u1ec1 vi\u1ec7c c\xf9ng s\u1ed1ng c\xf9ng ch\u1ebft v\u1edbi d\xe2n.","Ng\u01b0\u1eddi gi\u1eef \u1ea5n c\u1ee7a th\xe0nh kh\xf4ng ch\u1ecbu \u0111\xf3ng d\u1ea5u l\xean k\u1ebf ho\u1ea1ch b\u1ecf m\u1eb7c khu d\xe2n ngh\xe8o n\xean \u0111\xe3 gi\u1ea5u con \u1ea5n th\u1eadt v\xe0 ch\xf4n l\u1eddi th\u1ec1 c\xf4ng ch\u1ee9c b\xean c\u1ea1nh. H\xf3a \u0111\xe1 tr\xean t\u1ea3ng th\u1ec1, \xf4ng \u0111\u1ec3 l\u1ecbch s\u1eed c\xf3 m\u1ed9t nh\xe2n ch\u1ee9ng r\u1eb1ng l\u1eddi h\u1ee9a v\u1edbi d\xe2n khi b\u1ecb ph\u1ea3n b\u1ed9i v\u1eabn t\u1eebng c\xf3 ng\u01b0\u1eddi c\u1ed1 gi\u1eef \u0111\u1ebfn c\xf9ng.")
B.apT=new A.c1("Vi\u1ec7n \u1ea4n Kh\xf4 M\xe1u","Ph\xf9 S\u01b0 Gi\u1eef M\u1ea1ch","Tr\xean tay t\u01b0\u1ee3ng l\xe0 t\u1eebng l\xe1 ph\xf9 \u0111\xe1 d\xednh ch\u1eb7t v\xe0o da nh\u01b0 m\xf3ng tay kh\xf4ng b\xf3c \u0111\u01b0\u1ee3c n\u1eefa. S\xe0n vi\u1ec7n c\xf2n nh\u1eefng \u0111\u01b0\u1eddng m\xe1u kh\xf4 n\u1ed1i th\xe0nh \u0111\u1ed3 h\xecnh v\xe1 l\u1ed7 th\u1ee7ng \u1edf m\u1ea1ch \u0111\u1ea5t.","Ph\xf9 s\u01b0 n\xe0y d\xf9ng ch\xednh m\xe1u m\xecnh \u0111\u1ec3 v\xe1 d\xf2ng \u0111\u1ecba m\u1ea1ch n\u1ee9t, k\xe9o ch\u1eadm tri\u1ec1u r\u1ed7ng \u0111ang ng\u1ea5m v\xe0o l\xf2ng \u0111\u1ea5t th\xeam ba ng\xe0y qu\xfd gi\xe1 cho d\xe2n s\u01a1 t\xe1n. H\u1eafn h\xf3a \u0111\xe1 gi\u1eefa tr\u1eadn \u0111\u1ed3 nh\u01b0 m\u1ed9t c\xe2y ch\u1ed1t cu\u1ed1i c\xf9ng \u0111\xf3ng xu\u1ed1ng v\u1ebft n\u1ee9t c\u1ee7a c\u1ea3 v\xf9ng \u0111\u1ea5t.")
B.app=new A.c1("H\u1ed3 Bia Tr\u1ea7m S\u01b0\u01a1ng","Ng\u01b0\u1eddi V\u1edbt Ch\u1eef","T\u01b0\u1ee3ng n\u1eeda qu\u1ef3 n\u1eeda nghi\xeang tr\xean m\xe9p h\u1ed3, b\xe0n tay nh\u01b0 \u0111ang v\u1edbt m\u1ed9t phi\u1ebfn \u0111\xe1 ch\xecm d\u01b0\u1edbi s\u01b0\u01a1ng. M\u1eb7t h\u1ed3 l\u1eb7ng \u0111\u1ebfn m\u1ee9c ph\u1ea3n chi\u1ebfu bia c\u1ed5 quanh \u0111\xf3 nh\u01b0 m\u1ed9t ngh\u0129a \u0111\u1ecba c\u1ee7a c\xe2u ch\u1eef.","N\xe0ng l\u1eb7n xu\u1ed1ng h\u1ed3 m\u1ed7i \u0111\xeam \u0111\u1ec3 nh\u1eb7t nh\u1eefng bia \u0111\xe1 b\u1ecb c\u1ed1 \xfd qu\u0103ng b\u1ecf nh\u1eb1m phi tang h\u1ed3 s\u01a1 ng\u01b0\u1eddi m\u1ea5t t\xedch. Khi ph\u1ed5i \u0111\xe3 h\u1ecfng v\xec kh\xed l\u1ea1nh, n\xe0ng h\xf3a \u0111\xe1 b\xean m\xe9p n\u01b0\u1edbc \u0111\u1ec3 canh nh\u1eefng m\u1ea3nh s\u1ef1 th\u1eadt cu\u1ed1i c\xf9ng kh\xf4ng ch\xecm th\xeam l\u1ea7n n\u1eefa.")
B.ape=new A.c1("Chu\u1ed3ng Th\xfa H\xf3a Th\u1ea1ch","M\u1ee5c \u0110\u1ed3ng G\u1ecdi \u0110\xe0n","T\u01b0\u1ee3ng c\u1eadu b\xe9 th\u1ed5i s\xe1o \u0111\xe1 tr\u01b0\u1edbc m\u1ed9t b\u1ea7y th\xfa h\xf3a th\u1ea1ch n\u1eb1m r\u1ea3i kh\u1eafp s\xe2n. Giai \u0111i\u1ec7u \u0111\xe3 m\u1ea5t t\u1eeb l\xe2u, ch\u1ec9 c\xf2n t\u01b0 th\u1ebf g\u1ecdi \u0111\xe0n khi\u1ebfn kho\u1ea3ng s\xe2n v\u1eafng th\xeam bu\u1ed3n.","C\u1eadu m\u1ee5c \u0111\u1ed3ng d\u1eabn \u0111\xe0n linh th\xfa th\u1ed3 h\xe0ng c\u1ee9u tr\u1ee3 tho\xe1t kh\u1ecfi v\xf2ng s\u0103n b\u1eaft c\u1ee7a qu\xe2n nhu tri\u1ec1u \u0111\xecnh. \u0110\u1ebfn khi c\u1ea3 \u0111\xe0n l\u1eabn ch\u1ee7 \u0111\u1ec1u b\u1ecb s\xf3ng \u0111\xe1 b\u1eaft k\u1ecbp, c\u1eadu ch\u1ecdn h\xf3a \u0111\xe1 c\xf9ng ch\xfang \u0111\u1ec3 k\xfd \u1ee9c v\u1ec1 nh\u1eefng con v\u1eadt trung th\xe0nh \u1ea5y kh\xf4ng ch\u1ebft l\u1eb7ng trong m\u1ed9t chu\u1ed3ng b\u1ecf hoang.")
B.api=new A.c1("V\u01b0\u1eddn Thu\u1ed1c Hoang","D\u01b0\u1ee3c N\u1eef Ch\xf4n H\u1ea1t","T\u01b0\u1ee3ng thi\u1ebfu n\u1eef ch\u1ed1ng thu\u1ed5ng gi\u1eefa v\u01b0\u1eddn thu\u1ed1c m\u1ecdc d\u1ea1i, ch\xe2n c\xf2n \u0111\u1ea1p l\xean nh\u1eefng g\xf3i h\u1ea1t gi\u1ed1ng h\xf3a \u0111\xe1. H\u01b0\u01a1ng th\u1ea3o m\u1ed9c l\u1eabn m\xf9i \u0111\u1ea5t \u01b0\u1edbt khi\u1ebfn n\u01a1i n\xe0y gi\u1ed1ng m\u1ed9t gian ph\xf2ng ch\u1eefa b\u1ec7nh \u0111\xe3 b\u1ecb qu\xean ngo\xe0i tr\u1eddi.","D\u01b0\u1ee3c n\u1eef tr\u1ebb tu\u1ed5i n\xe0y bi\u1ebft m\xecnh kh\xf4ng c\u1ee9u n\u1ed5i c\u1ea3 th\xe0nh n\xean ch\xf4n gi\u1ea5u h\u1ea1t thu\u1ed1c \u1edf nhi\u1ec1u b\xe3i \u0111\u1ea5t \u0111\u1ec3 th\u1ebf h\u1ec7 sau c\xf2n c\xf3 c\u01a1 may ch\u1eefa b\u1ec7nh. H\xf3a \u0111\xe1 ngay gi\u1eefa lu\u1ed1ng tr\u1ed3ng, n\xe0ng bi\u1ebfn th\xe2n m\xecnh th\xe0nh c\u1ed9t m\u1ed1c ch\u1ec9 n\u01a1i nh\u1eefng h\u1ea1t s\u1ed1ng \u0111\u01b0\u1ee3c c\u1ea5t l\u1ea1i.")
B.apI=new A.c1("Th\xe1p Chu\xf4ng M\xf9 T\u1ed1i","Ti\u1ebfng Chu\xf4ng Kh\xf4ng Ng\u01b0\u1eddi","T\u01b0\u1ee3ng quay l\u01b0ng v\u1ec1 c\u1ea7u thang th\xe1p chu\xf4ng, tay v\u1eabn n\u1eafm s\u1ee3i d\xe2y chu\xf4ng h\xf3a \u0111\xe1. B\xf3ng t\u1ed1i trong th\xe1p d\xe0y t\u1edbi m\u1ee9c c\u1ea3m gi\xe1c m\u1ed7i b\u1eadc \u0111\xe1 \u0111\u1ec1u \u0111ang nh\u1edb ti\u1ebfng b\u01b0\u1edbc ch\xe2n c\u1ee7a m\u1ed9t ng\u01b0\u1eddi \u0111\xe3 \u0111i m\xe3i kh\xf4ng xu\u1ed1ng.","Ng\u01b0\u1eddi k\xe9o chu\xf4ng cu\u1ed1i gi\u1eef nh\u1ecbp th\u1eddi gian cho th\xe0nh khi \u0111\u1ed3ng h\u1ed3, m\u1eb7t tr\u1eddi v\xe0 l\u1ecbch ph\xe1p \u0111\u1ec1u h\u1ecfng. Khi ch\u1eb3ng c\xf2n ai nghe n\u1eefa, \xf4ng h\xf3a \u0111\xe1 c\xf9ng s\u1ee3i d\xe2y \u0111\u1ec3 th\xe1p chu\xf4ng ti\u1ebfp t\u1ee5c l\xe0m nh\xe2n ch\u1ee9ng r\u1eb1ng th\xe0nh ph\u1ed1 n\xe0y t\u1eebng ch\u1ed1ng l\u1ea1i h\u1ed7n lo\u1ea1n b\u1eb1ng k\u1ef7 lu\u1eadt gi\u1ea3n d\u1ecb m\u1ed7i ng\xe0y.")
B.aps=new A.c1("Nh\xe0 \u0110\xe1 Gi\u1eef Tr\u1ebb","B\u1ea3o M\u1eabu Tr\u1ea5n M\xf4n","T\u01b0\u1ee3ng n\u1eef nh\xe2n dang hai tay ch\u1eafn tr\u01b0\u1edbc c\u0103n nh\xe0 \u0111\xe1 th\u1ea5p b\xe9, sau l\u01b0ng l\xe0 v\xf4 s\u1ed1 v\u1ec7t kh\u1eafc chi\u1ec1u cao c\u1ee7a tr\u1ebb con. C\xe1nh c\u1eeda \u0111\xe3 m\u1ee5c h\u1ebft nh\u01b0ng t\u01b0 th\u1ebf b\u1ea3o v\u1ec7 \u1ea5y khi\u1ebfn ng\u01b0\u1eddi ta kh\xf4ng d\xe1m b\u01b0\u1edbc qua qu\xe1 m\u1ea1nh.","B\u1ea3o m\u1eabu \u1edf \u0111\xe2y gom b\u1ecdn tr\u1ebb m\u1ed3 c\xf4i, b\u1eaft ch\xfang \u0111\u1ecdc t\xean nhau m\u1ed7i t\u1ed1i \u0111\u1ec3 kh\xf4ng \u0111\u1ee9a n\xe0o b\u1ecb bi\u1ebfn th\xe0nh con s\u1ed1 trong s\u1ed5 c\u1ee9u t\u1ebf. N\xe0ng h\xf3a \u0111\xe1 ngay c\u1eeda \u0111\u1ec3 gi\u1eef ng\xf4i nh\xe0 th\xe0nh m\u1ed9t chi\u1ebfc k\xe9n k\xfd \u1ee9c cho \u0111\xe1m tr\u1ebb t\u1eebng s\u1ed1ng s\xf3t \u1edf \u0111\xe2y.")
B.apQ=new A.c1("Tr\u1ee5 Canh \u0110\u1ea7u S\xf4ng","L\xe1i \u0110\xf2 Neo C\u1ea1n","T\u01b0\u1ee3ng ch\xe8o ch\u1ed1ng tr\xean chi\u1ebfc thuy\u1ec1n \u0111\xe1 m\u1eafc c\u1ea1n gi\u1eefa l\xf2ng s\xf4ng \u0111\xe3 th\xe0nh b\xe3i c\u1ecf. \u0110\u1ea7u s\xe0o c\u1eafm r\u1ea5t s\xe2u xu\u1ed1ng \u0111\u1ea5t nh\u01b0 ng\u01b0\u1eddi ch\xe8o tin r\u1eb1ng n\u01b0\u1edbc r\u1ed3i c\u0169ng s\u1ebd tr\u1edf l\u1ea1i.","Ng\u01b0\u1eddi l\xe1i \u0111\xf2 ch\u1edf mi\u1ec5n ph\xed nh\u1eefng \u0111o\xe0n ch\u1ea1y lo\u1ea1n cho t\u1edbi khi s\xf4ng c\u1ea1n v\xec m\u1ea1ch n\u01b0\u1edbc ch\u1ebft. H\u1eafn h\xf3a \u0111\xe1 tr\xean con thuy\u1ec1n kh\xf4 \u0111\u1ec3 b\u1ebfn s\xf4ng n\xe0y c\xf2n nh\u1edb \u0111\xe3 t\u1eebng c\xf3 m\u1ed9t ngh\u1ec1 l\u1ea5y vi\u1ec7c \u0111\u01b0a ng\u01b0\u1eddi qua b\u1edd l\xe0m l\u1ebd s\u1ed1ng.")
B.apg=new A.c1("Ph\u1ee7 T\u1ec3 T\u01b0\u1edbng M\u1ed1c","Gia Th\u1ea7n Gi\u1eef \u1ea4n","T\u01b0\u1ee3ng gia th\u1ea7n \xf4m tr\xe1p \u1ea5n tr\u01b0\u1edbc c\u1ed5ng ph\u1ee7 n\xe1t m\u1ed1c, qu\u1ef3 kh\xf4ng th\u1eb3ng c\u0169ng kh\xf4ng \u0111\u1ed5. S\u1ef1 nh\u1eabn nh\u1ee5c c\xf2n \u0111\u1ecdng l\u1ea1i trong d\xe1ng qu\u1ef3 \u1ea5y khi\u1ebfn n\u01a1i t\u1eebng l\xe0 quy\u1ec1n l\u1ef1c n\xe0y c\xe0ng th\xeam \u0111\xe1ng gh\xe9t.","K\u1ebb h\u1ea7u c\u1eadn n\xe0y \u0111\xe3 \u0111\xe1nh tr\xe1o \u1ea5n l\u1ec7nh \u0111\u1ec3 ch\u1eb7n l\u1ec7nh thi\xeau kho d\xe2n s\u1ef1 r\u1ed3i \xf4m t\u1ed9i thay m\u1ed9t ng\u01b0\u1eddi ch\u1ee7 kh\xf4ng x\u1ee9ng \u0111\xe1ng. H\xf3a \u0111\xe1 n\u01a1i c\u1ed5ng ph\u1ee7, h\u1eafn bi\u1ebfn m\xecnh th\xe0nh b\u1ea3n sao l\u1ec7ch c\u1ee7a l\xf2ng trung, v\u1eeba \u0111\xe1ng th\u01b0\u01a1ng v\u1eeba \u0111\u1ee7 \u0111\u1ec3 nh\u1eafc ng\u01b0\u1eddi \u0111\u1eddi ph\xe2n bi\u1ec7t trung v\u1edbi m\xf9 qu\xe1ng.")
B.ap9=new A.c1("S\xe2n \u0110\xfac T\u01b0\u1ee3ng","Th\u1ee3 \u0110\xe1 N\u1eb7n H\u1ed3n","H\xe0ng tr\u0103m ph\xf4i t\u01b0\u1ee3ng dang d\u1edf \u0111\u1ee9ng quanh s\xe2n, c\xf2n t\u01b0\u1ee3ng trung t\xe2m c\u1ea7m b\xfaa \u0111\u1ee5c nh\u01b0 v\u1eeba d\u1eebng gi\u1eefa m\u1ed9t nh\xe1t cu\u1ed1i. C\u1ea3m gi\xe1c n\u01a1i n\xe0y kh\xf4ng ph\u1ea3i x\u01b0\u1edfng m\xe0 l\xe0 ph\xf2ng l\u01b0u tr\u1eef c\u1ee7a nh\u1eefng linh h\u1ed3n ch\u01b0a \u0111\u01b0\u1ee3c g\u1ecdi t\xean.","Ng\u01b0\u1eddi th\u1ee3 \u0111\xe1 n\xe0y nh\u1eadn l\u1ec7nh kh\u1eafc t\u01b0\u1ee3ng cho nh\u1eefng ai t\xecnh nguy\u1ec7n h\xf3a th\u1ea1ch \u0111\u1ec3 gi\u1eef k\xfd \u1ee9c c\u1ee7a v\xf9ng \u0111\u1ea5t. \xd4ng l\xe0 ng\u01b0\u1eddi cu\u1ed1i c\xf9ng t\u1ef1 \u0111\u1ee5c ch\xednh h\xecnh h\xe0i m\xecnh, \u0111\u1ec3 x\u01b0\u1edfng \u0111\xfac t\u01b0\u1ee3ng kh\xf4ng bao gi\u1edd qu\xean c\xe1i gi\xe1 con ng\u01b0\u1eddi \u0111\xe3 tr\u1ea3 cho vi\u1ec7c ch\u1ed1ng l\u1ea1i l\xe3ng qu\xean.")
B.apR=new A.c1("M\u1ed9 Tr\u01b0\u1eddng Ca","N\u1eef Nh\u1ea1c Nh\xe2n C\xe2m","T\u01b0\u1ee3ng n\u1eef \xf4m nh\u1ea1c c\u1ee5 \u0111\xe1 b\u1ecb g\xe3y m\u1ed9t d\xe2y, \u0111\u1ea7u h\u01a1i ng\u1ea9ng nh\u01b0 v\u1eabn \u0111ang gi\u1eef n\u1ed1t ng\xe2n cu\u1ed1i. Quanh m\u1ed9 ch\u1ec9 c\xf2n c\u1ecf lau v\xe0 nh\u1eefng bia nh\u1ecf kh\u1eafc t\xean c\xe1c b\xe0i h\xe1t kh\xf4ng ai c\xf2n bi\u1ebft giai \u0111i\u1ec7u.","N\xe0ng nh\u1ea1c nh\xe2n \u0111i kh\u1eafp n\u01a1i h\xe1t l\u1ea1i t\xean ng\u01b0\u1eddi ch\u1ebft \u0111\u1ec3 tang quy\u1ebfn c\xf2n d\xe1m kh\xf3c. T\u1edbi ng\xe0y gi\u1ecdng m\xecnh t\u1eaft v\xec b\u1ee5i \u0111\xe1, n\xe0ng h\xf3a \u0111\xe1 b\xean m\u1ed9 tr\u01b0\u1eddng ca \u0111\u1ec3 \xe2m nh\u1ea1c n\u01a1i \u0111\xe2y v\u1eabn c\xf2n m\u1ed9t th\xe2n x\xe1c l\xe0m ch\u1ee9ng cho n\u1ed7i bu\u1ed3n t\u1eebng \u0111\u01b0\u1ee3c h\xe1t l\xean th\xe0nh ti\u1ebfng.")
B.apn=new A.c1("B\u1ebfn Xe Bia C\u1ed5","Ng\u01b0\u1eddi K\xe9o Xa Cu\u1ed1i","T\u01b0\u1ee3ng ng\u01b0\u1eddi k\xe9o xe \u0111\u1ee9ng gh\xec vai v\xe0o c\xe0ng g\u1ed7 \u0111\xe1, th\xf9ng xe ph\xeda sau ch\u1edf \u0111\u1ea7y bia v\xe0 h\xf2m nh\u1ecf. M\u1eb7t \u0111\u01b0\u1eddng \u0111\xe3 m\u1ee5c h\u1ebft v\u1ec7t b\xe1nh nh\u01b0ng t\u01b0 th\u1ebf \u1ea5y v\u1eabn c\u0103ng nh\u01b0 chuy\u1ebfn \u0111i ch\u01b0a \u0111\u1ebfn \u0111\xedch.","\xd4ng l\xe3o chuy\xean ch\u1edf kh\xf4ng v\u1eadn chuy\u1ec3n c\u1ee7a c\u1ea3i m\xe0 ch\u1edf bia m\u1ed9, di v\u1eadt v\xe0 l\u1eddi nh\u1eafn cu\u1ed1i cho c\xe1c khu t\u1ea3n c\u01b0. Khi ch\xednh m\xecnh ki\u1ec7t s\u1ee9c ngo\xe0i b\u1ebfn, \xf4ng h\xf3a \u0111\xe1 c\xf9ng c\u1ed7 xe \u0111\u1ec3 h\xe0nh tr\xecnh \u0111\u01b0a k\xfd \u1ee9c t\u1edbi tay ng\u01b0\u1eddi s\u1ed1ng kh\xf4ng b\u1ecb b\u1ecf d\u1edf trong qu\xean l\xe3ng.")
B.apD=new A.c1("\u0110i\u1ec7n H\xf3a Sinh","Ph\u01b0\u01a1ng S\u0129 \u0110\u1ed5i Th\u1ecbt","T\u01b0\u1ee3ng ph\u01b0\u01a1ng s\u0129 \u0111\u1eb7t tay l\xean l\xf2 \u0111an \u0111\xe3 \u0111\xf4ng c\u1ee9ng th\xe0nh \u0111\xe1, quanh ch\xe2n l\xe0 v\xf4 s\u1ed1 b\xecnh th\xed nghi\u1ec7m v\u1ee1. M\xf9i kho\xe1ng \u0111\u1eadm \u0111\u1ebfn m\u1ee9c c\u1ea3 gian \u0111i\u1ec7n gi\u1ed1ng nh\u01b0 m\u1ed9t c\u01a1 th\u1ec3 kh\u1ed5ng l\u1ed3 v\u1eeba ng\u1eebng th\u1edf.","Ph\u01b0\u01a1ng s\u0129 n\xe0y l\xe0 ng\u01b0\u1eddi \u0111\u1ea7u ti\xean bi\u1ebfn th\u1ea1ch h\xf3a t\u1eeb h\xecnh ph\u1ea1t th\xe0nh c\xe1ch gi\u1eef k\xfd \u1ee9c, nh\u01b0ng c\u0169ng v\xec v\u1eady m\xe0 m\u1edf ra bi k\u1ecbch c\u1ee7a c\u1ea3 v\xf9ng \u0111\u1ea5t. \xd4ng h\xf3a \u0111\xe1 trong \u0111i\u1ec7n luy\u1ec7n \u0111\u1ec3 t\u1ef1 nh\u1eadn m\xecnh l\xe0 kh\u1edfi ngu\u1ed3n c\u1ee7a m\u1ed9t ph\u01b0\u01a1ng thu\u1ed1c c\u1ee9u \u0111\u01b0\u1ee3c l\u1ecbch s\u1eed nh\u01b0ng gi\u1ebft m\u1ea5t \u0111\u1eddi s\u1ed1ng.")
B.apO=new A.c1("\u0110\u01b0\u1eddng Kh\xf3a Nh\u1eadt","L\u1ecbch Quan Ghim Ng\xe0y","T\u01b0\u1ee3ng quan l\u1ecbch \u0111\xf3ng chi\u1ebfc \u0111inh \u0111\xe1 v\xe0o m\u1ed9t m\u1eb7t nh\u1eadt lu\xe2n \u0111\xe3 d\u1eebng l\u1ea1i. Con \u0111\u01b0\u1eddng d\xe0i ph\xeda sau ph\u1ee7 k\xedn c\u1ecf x\xe1m, nh\u01b0 th\u1eddi gian \u1edf \u0111\xe2y t\u1eebng b\u1ecb \u0111\xf3ng ch\u1eb7t r\u1ed3i b\u1ecf qu\xean.","V\u1ecb quan l\u1ecbch n\xe0y ghim c\u1ed1 ng\xe0y cu\u1ed1i c\xf9ng c\xf2n tr\u1eadt t\u1ef1 \u0111\u1ec3 d\xe2n n\u01b0\u01a1ng v\xe0o m\u1ed9t m\u1ed1c th\u1eadt m\xe0 gi\u1eef t\u1ec9nh t\xe1o. \xd4ng h\xf3a \u0111\xe1 gi\u1eefa \u0111\u01b0\u1eddng kh\xf3a nh\u1eadt, \u0111\u1ec3 ng\u01b0\u1eddi b\u01b0\u1edbc v\xe0o v\xf9ng \u0111\u1ea5t n\xe0y hi\u1ec3u r\u1eb1ng n\u01a1i \u0111\xe2y \u0111\xe3 ch\u1ecdn d\u1eebng th\u1eddi gian trong t\xe2m tr\xed tr\u01b0\u1edbc khi th\u1eddi gian th\u1eadt s\u1ef1 ph\u1ea3n b\u1ed9i h\u1ecd.")
B.apc=new A.c1("Gi\xe0n T\u1ebf Th\u1eddi Gian","T\u1ebf Th\u1ee7 \u0110\u1ed1t Gi\u1edd","T\u01b0\u1ee3ng t\u1ebf th\u1ee7 n\xe2ng l\u01b0 h\u01b0\u01a1ng \u0111\xe1 l\xean cao, xung quanh l\xe0 nh\u1eefng \u0111\u1ed3ng h\u1ed3 c\xe1t v\u1ee1 \u0111\xf4ng c\u1ee9ng gi\u1eefa kh\xf4ng trung. B\u01b0\u1edbc ch\xe2n t\u1edbi g\u1ea7n \u0111\xe2y nghe nh\u01b0 \u0111ang ch\u1ea1m v\xe0o tro c\u1ee7a nh\u1eefng n\u0103m th\xe1ng b\u1ecb ai \u0111\xf3 \u0111em thi\xeau l\xe0m v\u1eadt hi\u1ebfn.","Ng\u01b0\u1eddi ch\u1ee7 t\u1ebf \u0111\xe3 \u0111\u1ed1t h\xe0ng tr\u0103m linh c\u1ee5 t\xednh gi\u1edd \u0111\u1ec3 k\xe9o ch\u1eadm l\xe0n s\xf3ng x\xf3a m\xf2n \u0111ang nu\u1ed1t t\xean ng\u01b0\u1eddi v\xe0 m\u1eb7t \u0111\u1ea5t. \xd4ng h\xf3a \u0111\xe1 gi\u1eefa gi\xe0n t\u1ebf \u0111\u1ec3 th\xfa nh\u1eadn r\u1eb1ng c\xf3 nh\u1eefng nghi th\u1ee9c c\u1ee9u \u0111\u01b0\u1ee3c v\xe0i ng\u01b0\u1eddi h\xf4m nay nh\u01b0ng s\u1ebd \u0111\u1ec3 l\u1ea1i m\u1ed9t hoang \u0111\u1ecba k\xe9o d\xe0i h\xe0ng thi\xean ni\xean k\u1ef7.")
B.apP=new A.c1("Mi\u1ebfu L\u1eddi Tr\u0103n Tr\u1ed1i","S\u1ee9 Gi\u1ea3 G\u1ecdi T\xean","T\u01b0\u1ee3ng s\u1ee9 gi\u1ea3 c\u1ea7m chu\u1ed7i th\u1ebb b\xe0i tr\u01b0\u1edbc mi\u1ebfu nh\u1ecf \u0111\u1ea7y gi\u1ea5y m\u1ee5c. Gi\xf3 l\u1ecdt qua m\xe1i mi\u1ebfu c\u1ee9 l\xe0m nh\u1eefng d\u1ea3i gi\u1ea5y run l\xean nh\u01b0 t\u1eebng l\u1eddi tr\u0103n tr\u1ed1i c\xf2n m\u1eafc \u1edf c\u1ed5 h\u1ecdng ai \u0111\xf3.","H\u1eafn t\u1eebng \u0111i kh\u1eafp th\xe0nh \u0111\u1ecdc l\u1ea1i l\u1eddi cu\u1ed1i c\u1ee7a ng\u01b0\u1eddi ch\u1ebft cho \u0111\xfang ng\u01b0\u1eddi th\xe2n tr\u01b0\u1edbc khi k\xfd \u1ee9c bi\u1ebfn d\u1ea1ng v\xec thu\u1eadt \u0111\xe1. Khi kh\xf4ng c\xf2n ai \u0111\u1ec3 \u0111\u1ecdc cho, h\u1eafn h\xf3a \u0111\xe1 c\xf9ng ch\xf9m th\u1ebb t\xean \u0111\u1ec3 \xedt nh\u1ea5t l\u1eddi tr\u0103n tr\u1ed1i cu\u1ed1i c\u1ee7a m\u1ed9t th\u1eddi \u0111\u1ea1i v\u1eabn c\xf2n ng\u01b0\u1eddi gi\u1eef h\u1ed9.")
B.apz=new A.c1("Tr\u01b0\u1eddng B\u1eadc Kh\xf4ng Ng\u01b0\u1eddi","Gi\xe1o Th\u1ee5 Gi\u1eef Kh\xf3a","T\u01b0\u1ee3ng th\u1ea7y gi\xe1o \u0111\u1ee9ng cu\u1ed1i c\u1ea7u thang tr\u01b0\u1eddng h\u1ecdc, m\u1ed9t ch\xf9m ch\xeca kh\xf3a \u0111\xe1 bu\xf4ng d\u1ecdc c\u1ed5 tay. C\xe1c b\u1eadc th\u1ec1m \u0111\u1ea7y r\xeau m\xe0 v\u1eabn gi\u1eef v\u1ebft l\xf5m c\u1ee7a h\xe0ng tr\u0103m \u0111\xf4i ch\xe2n nh\u1ecf t\u1eebng l\xean l\u1edbp.","Gi\xe1o th\u1ee5 n\xe0y kh\xf3a t\u1eebng ph\xf2ng h\u1ecdc sau khi d\u1eb7n h\u1ecdc tr\xf2 t\u1ea3n \u0111i, quy\u1ebft gi\u1eef nguy\xean b\u1ea3ng, s\xe1ch v\xe0 s\u01a1 \u0111\u1ed3 ng\u1ed3i \u0111\u1ec3 mai sau ai tr\u1edf l\u1ea1i v\u1eabn nh\u1eadn ra l\u1edbp c\u0169. H\xf3a \u0111\xe1 \u1edf ch\xe2n c\u1ea7u thang, \xf4ng tr\u1edf th\xe0nh ng\u01b0\u1eddi g\xe1c c\u1ed5ng cho m\u1ed9t n\u1ec1n h\u1ecdc v\u1ea5n kh\xf4ng ch\u1ecbu ch\u1ebft c\xf9ng tri\u1ec1u \u0111\u1ea1i c\u1ee7a m\xecnh.")
B.apK=new A.c1("T\xe2m M\xf4n H\xf3a \u0110\xe1","M\xf4n Ch\u1ee7 Ch\u1ed1ng C\u1eeda","C\xe1nh c\u1eeda \u0111\xe1 kh\u1ed5ng l\u1ed3 b\u1ecb ch\u1eb7n b\u1eb1ng th\xe2n t\u01b0\u1ee3ng trong t\u01b0 th\u1ebf d\xf9ng vai ch\u1ed1ng \u0111\u1ea9y. M\u1eb7t \u0111\u1ea5t quanh \u0111\xf3 n\u1ee9t s\xe2u nh\u01b0 t\u1eebng c\xf3 m\u1ed9t s\u1ee9c \xe9p kinh kh\u1ee7ng mu\u1ed1n ph\xe1 tung c\u1ed5ng t\u1eeb ph\xeda b\xean kia.","M\xf4n ch\u1ee7 c\u1ee7a v\xf9ng \u0111\u1ea5t n\xe0y \u0111\xe3 \u1edf l\u1ea1i ch\u1eb7n khe h\u1edf n\u01a1i tri\u1ec1u r\u1ed7ng tr\xe0n v\xe0o, d\xf9ng ch\xednh qu\xe1 tr\xecnh h\xf3a th\u1ea1ch \u0111\u1ec3 bi\u1ebfn m\xecnh th\xe0nh then c\u1eeda s\u1ed1ng. Bao n\u0103m qua \xf4ng ch\u1ec9 c\xf2n l\xe0 m\u1ed9t kh\u1ed1i \u0111\xe1 ch\u1ed1ng c\u1eeda, nh\u01b0ng nh\u1edd th\u1ebf c\u1ea3 mi\u1ec1n \u0111\u1ea5t m\u1edbi c\xf3 th\u1eddi gian tr\u1edf th\xe0nh ngh\u0129a \u0111\u1ecba nh\xe2n ch\u1ee9ng thay v\xec bi\u1ebfn m\u1ea5t s\u1ea1ch kh\xf4ng d\u1ea5u.")
B.apB=new A.c1("V\u1ef1c Ch\u1ee9ng Nh\xe2n","Ng\u01b0\u1eddi Ch\xe9p \u0110\xeam Cu\u1ed1i","T\u01b0\u1ee3ng th\u01b0 sinh ng\u1ed3i b\xean m\xe9p v\u1ef1c, t\u1ea5m b\u1ea3n th\u1ea3o \u0111\xe1 tr\u1ea3i d\xe0i t\u1edbi t\u1eadn ch\xe2n m\xecnh. Gi\xf3 t\u1eeb v\u1ef1c th\u1ed5i l\xean l\xe0m ng\u01b0\u1eddi ta c\xf3 c\u1ea3m gi\xe1c d\u01b0\u1edbi \u0111\xe1y c\xf2n c\u1ea5t c\u1ea3 m\u1ed9t \u0111\xeam ch\u01b0a ch\xe9p xong.","Ch\xe0ng th\u01b0 sinh n\xe0y ng\u1ed3i su\u1ed1t \u0111\xeam cu\u1ed1i \u0111\u1ec3 ghi l\u1ea1i ai \u0111\xe3 s\u1ed1ng, ai \u0111\xe3 ch\u1ebft, ai \u0111\xe3 t\u1ef1 nguy\u1ec7n h\xf3a \u0111\xe1 v\xe0 ai b\u1ecb \xe9p th\xe0nh t\u01b0\u1ee3ng. H\xf3a th\u1ea1ch khi n\xe9t cu\u1ed1i c\xf2n dang, ch\xe0ng gi\u1eef l\u1ea1i cu\u1ed1n bi\xean ni\xean s\u1eed trung th\u1ef1c nh\u1ea5t c\u1ee7a Hoang \u0110\u1ecba Ch\u1ee9ng Th\u1ea1ch.")
B.apF=new A.c1("Bia M\u1eb9 G\u1ecdi Con","M\u1eabu Th\u1ea1ch \u0110\u1ee3i Ti\u1ebfng","T\u01b0\u1ee3ng ng\u01b0\u1eddi m\u1eb9 \xe1p tai v\xe0o t\u1ea5m bia cao ngang ng\u1ef1c, nh\u01b0 v\u1eabn ch\u1edd m\u1ed9t gi\u1ecdng tr\u1ebb con v\u1ecdng ra t\u1eeb b\xean kia \u0111\xe1. C\u1ea3 kho\u1ea3ng s\xe2n t\u0129nh t\u1edbi m\u1ee9c ti\u1ebfng gi\xf3 x\u01b0\u1edbc qua c\u1ecf c\u0169ng nghe nh\u01b0 ti\u1ebfng g\u1ecdi l\u1ea1c m\u1ea5t.","B\xe0 m\u1eb9 n\xe0y \u0111\xe3 g\u1eedi con trai l\xean \u0111o\xe0n s\u01a1 t\xe1n r\u1ed3i t\u1ef1 \u1edf l\u1ea1i ghi t\xean t\u1eebng \u0111\u1ee9a tr\u1ebb th\u1ea5t l\u1ea1c l\xean bia ch\u1edd ng\u01b0\u1eddi th\xe2n \u0111\u1ebfn nh\u1eadn. Sau khi \u0111\u1ee3i qu\xe1 l\xe2u kh\xf4ng c\xf2n ai tr\u1edf v\u1ec1, b\xe0 h\xf3a \u0111\xe1 ngay t\u01b0 th\u1ebf l\u1eafng nghe, \u0111\u1ec3 c\u1ea3 mi\u1ec1n \u0111\u1ea5t n\xe0y c\xf3 m\u1ed9t ng\u01b0\u1eddi m\u1eb9 ti\u1ebfp t\u1ee5c \u0111\u1ee3i thay nh\u1eefng gia \u0111\xecnh \u0111\xe3 tan.")
B.ap8=new A.c1("V\u01b0\u01a1ng T\u1ecda R\u1ed7ng","V\u01b0\u01a1ng Ch\u1ee9ng Cu\u1ed1i C\xf9ng","Tr\xean ngai \u0111\xe1 kh\xf4ng c\xf2n vua, ch\u1ec9 c\xf3 t\u01b0\u1ee3ng ng\u01b0\u1eddi m\u1eb7c tri\u1ec1u ph\u1ee5c \u0111\u1ee9ng d\u01b0\u1edbi b\u1eadc th\u1ec1m nh\xecn th\u1eb3ng v\xe0o kho\u1ea3ng tr\u1ed1ng. Sau l\u01b0ng h\u1eafn l\xe0 r\u1eebng bia, tr\u01b0\u1edbc m\u1eb7t l\xe0 v\u01b0\u01a1ng t\u1ecda r\u1ed7ng nh\u01b0 c\u1ea3 th\u1eddi \u0111\u1ea1i n\xe0y ch\u1ec9 c\xf2n l\u1ea1i ngh\u0129a v\u1ee5 ph\u1ea3i nh\u1edb.","Ng\u01b0\u1eddi cu\u1ed1i c\xf9ng \u1edf \u0111\xe2y kh\xf4ng ph\u1ea3i qu\xe2n v\u01b0\u01a1ng, m\xe0 l\xe0 v\u1ecb s\u1eed l\u1ec7nh \u0111\xe3 bu\u1ed9c tri\u1ec1u \u0111\xecnh th\u1eeba nh\u1eadn: c\u1ea3 v\u01b0\u01a1ng qu\u1ed1c ch\u1ecdn h\xf3a \u0111\xe1 \u0111\u1ec3 gi\u1eef s\u1ef1 th\u1eadt tr\u01b0\u1edbc khi tri\u1ec1u r\u1ed7ng nu\u1ed1t s\u1ea1ch t\xean tu\u1ed5i c\u1ee7a h\u1ecd. Khi ta ch\u1ea1m v\xe0o t\u01b0\u1ee3ng, ta hi\u1ec3u Hoang \u0110\u1ecba Ch\u1ee9ng Th\u1ea1ch kh\xf4ng ph\u1ea3i ngh\u0129a \u0111\u1ecba c\u1ee7a ng\u01b0\u1eddi ch\u1ebft m\xe0 l\xe0 th\u01b0 kh\u1ed1 s\u1ed1ng b\u1eb1ng \u0111\xe1, v\xe0 con \u0111\u01b0\u1eddng k\u1ebf ti\u1ebfp h\u1eb3n d\u1eabn t\u1edbi n\u01a1i \u0111\xe3 phong k\xedn g\u1ed1c r\u1ec5 c\u1ee7a c\u01a1n x\xf3a m\xf2n \u1ea5y.")
