B.af8=new A.c0("M\xf4n R\u1ec5 Ng\u1ee7","C\u1ed5 Th\u1ee5 Khai L\u1ed9","Tho\xe1t kh\u1ecfi Hoang \u0110\u1ecba Ch\u1ee9ng Th\u1ea1ch, ta b\u01b0\u1edbc v\xe0o m\u1ed9t c\xe1nh c\u1ed5ng l\xe0m t\u1eeb hai b\u1ed9 r\u1ec5 kh\u1ed5ng l\u1ed3 \xf4m l\u1ea5y nhau. Kh\xf4ng c\xf3 ng\u01b0\u1eddi, ch\u1ec9 c\xf3 m\xf9i nh\u1ef1a c\xe2y c\u1ed5 v\xe0 ti\u1ebfng l\xe1 c\u1ecd nhau nh\u01b0 l\u1eddi th\xec th\u1ea7m c\u1ee7a m\u1ed9t khu r\u1eebng \u0111\xe3 th\u1ee9c qu\xe1 l\xe2u.","C\u1ed5 th\u1ee5 n\xe0y t\u1eebng m\u1edf r\u1ec5 t\xe1ch \u0111\u1ea5t \u0111\xf3n nh\u1eefng k\u1ebb l\xe1nh n\u1ea1n \u0111\u1ea7u ti\xean r\u1eddi kh\u1ecfi nh\xe2n gi\u1edbi \u0111\u1ed5 n\xe1t. Khi con ng\u01b0\u1eddi cu\u1ed1i c\xf9ng bi\u1ebfn m\u1ea5t, n\xf3 v\u1eabn \u0111\u1ee9ng \u0111\xe2y gi\u1eef c\u1ed5ng nh\u01b0 ch\u1edd m\u1ed9t l\u1eddi \u0111\xe1p r\u1eb1ng mi\u1ec1n \u0111\u1ea5t tr\xfa \u1ea9n \u1ea5y r\u1ed1t cu\u1ed9c \u0111\xe3 c\u1ee9u \u0111\u01b0\u1ee3c ai.")
B.afz=new A.c0("B\xe3i C\u1ecf \xc1nh Lam","Lam Linh Th\u1ea3o Ch\u1ee7","C\u1ea3 b\xe3i c\u1ecf ph\xe1t s\xe1ng m\xe0u lam nh\u1ea1t, gi\u1eefa \u0111\xf3 l\xe0 m\u1ed9t tinh linh nh\u1ecf mang h\xecnh thi\u1ebfu n\u1eef k\u1ebft t\u1eeb l\xe1 non. D\u01b0\u1edbi l\u1edbp s\xe1ng y\xean \u1ea3 \u1ea5y l\u1ea1i n\u1eb1m r\u1ea3i r\xe1c x\u01b0\u01a1ng v\u1ee5n c\u1ee7a nh\u1eefng linh th\xfa \u0111\xe3 h\xf3a tr\u1eafng.","Lam Linh t\u1eebng ch\u0103m s\xf3c b\u1ea7y th\xfa b\u1ecb th\u01b0\u01a1ng ch\u1ea1y v\xe0o r\u1eebng sau m\u1ed9t cu\u1ed9c s\u0103n gi\u1ebft c\u1ed5 x\u01b0a. N\xe0ng gi\u1eef ch\u1ed7 n\xe0y su\u1ed1t ng\xe0n n\u0103m, \u0111\u1ec3 \xe1nh s\xe1ng c\u1ecf lam thay th\u1ebf cho nh\u1eefng n\xe9n nhang kh\xf4ng ai c\xf2n s\u1ed1ng \u0111\u1ec3 th\u1eafp n\u1eefa.")
B.af9=new A.c0("Su\u1ed1i L\xe1 Tr\xf4i","Thanh Kh\xea M\u1ed9c Tinh","D\xf2ng su\u1ed1i \u1edf \u0111\xe2y kh\xf4ng ch\u1ea3y n\u01b0\u1edbc m\xe0 ch\u1ea3y l\xe1 xanh m\u1ecfng nh\u01b0 nh\u1eefng m\u1ea3nh k\xfd \u1ee9c. M\u1ed9t b\xf3ng h\xecnh b\u1eb1ng g\u1ed7 trong veo \u0111\u1ee9ng gi\u1eefa l\xf2ng su\u1ed1i, m\u1ed7i b\u01b0\u1edbc ch\xe2n c\u1ee7a n\xf3 \u0111\u1ec1u l\xe0m m\u1eb7t \u0111\u1ea5t m\u1ecdc th\xeam r\u1ec5 non.","Thanh Kh\xea t\u1eebng d\u1eabn n\u01b0\u1edbc t\u1edbi kh\u1eafp v\xf9ng cho c\u1ea3 ng\u01b0\u1eddi l\u1eabn ti\xean linh c\xf9ng s\u1ed1ng chung. Sau bi\u1ebfn c\u1ed1 qu\xe9t s\u1ea1ch nh\xe2n th\u1ebf kh\u1ecfi khu r\u1eebng, n\xf3 bi\u1ebfn d\xf2ng su\u1ed1i th\xe0nh d\xf2ng l\xe1 \u0111\u1ec3 gi\u1eef l\u1ea1i ti\u1ebfng th\xec th\u1ea7m c\u1ee7a nh\u1eefng ng\xe0y c\u0169.")
B.afK=new A.c0("\u0110\u1ed3i N\u1ea5m Thi\xeang","C\xf4 T\u1eed B\xe0o T\u1eed","Nh\u1eefng c\xe2y n\u1ea5m kh\u1ed5ng l\u1ed3 d\u1ef1ng l\xean nh\u01b0 nh\xe0 m\u1ed9, m\u0169 n\u1ea5m ph\u1ee7 \u0111\u1ea7y ph\u1ea5n s\xe1ng. \u1ede gi\u1eefa \u0111\u1ed3i l\xe0 m\u1ed9t sinh linh \u0111\u1ed9i v\u01b0\u01a1ng mi\u1ec7n b\xe0o t\u1eed, \u0111\xf4i m\u1eaft mang v\u1ebb ng\xe2y th\u01a1 \u0111\u1ebfn m\u1ee9c nguy hi\u1ec3m.","B\xe0o t\u1eed v\u01b0\u01a1ng n\xe0y \u0111\u01b0\u1ee3c sinh ra t\u1eeb x\xe1c nh\u1eefng th\xfa nh\u1ecf ch\u1ebft \u0111\xf3i trong m\xf9a d\xe0i nh\u1ea5t c\u1ee7a T\u1ecbch L\xe2m. N\xf3 gi\u1eef linh h\u1ed3n ch\xfang l\u1ea1i trong c\xe1c m\u0169 n\u1ea5m \u0111\u1ec3 khu r\u1eebng c\xf2n c\xf3 ti\u1ebfng ch\u1ea1y nh\u1ea3y, d\xf9 ch\u1ec9 l\xe0 b\u1eb1ng nh\u1eefng h\u1ea1t s\xe1ng mong manh.")
B.afg=new A.c0("G\u1ed1c \u0110\xe0n C\u1ed5","M\u1ed9c C\u1ea7m Y\xeau N\u1eef","M\u1ed9t th\xe2n c\xe2y r\u1ed7ng treo \u0111\u1ea7y d\xe2y leo c\u0103ng nh\u01b0 d\xe2y \u0111\xe0n, m\u1ed7i c\u01a1n gi\xf3 qua \u0111\u1ec1u b\u1eadt th\xe0nh kh\xfac nh\u1ea1c bu\u1ed3n. Ng\u01b0\u1eddi g\u1ea3y \u0111\xe0n l\xe0 m\u1ed9t tinh linh t\xf3c d\xe0i d\u1ec7t t\u1eeb v\u1ecf c\xe2y, c\u1ee9 l\u1eb7p \u0111i l\u1eb7p l\u1ea1i \u0111\xfang m\u1ed9t \u0111i\u1ec7u ti\u1ec5n bi\u1ec7t.","N\xe0ng t\u1eebng \u0111\xe0n cho c\xe1c linh th\xfa h\u1ea5p h\u1ed1i gi\u1eefa th\u1eddi lo\u1ea1n \u0111\u1ec3 ch\xfang ra \u0111i trong y\xean t\u0129nh. Khi kh\xf4ng c\xf2n ai nghe, n\xe0ng nh\u1eadp th\xe2n v\xe0o g\u1ed1c \u0111\xe0n, bi\u1ebfn \xe2m nh\u1ea1c th\xe0nh t\u1ea5m kh\u0103n tang d\xe0i v\xf4 t\u1eadn cho c\u1ea3 khu r\u1eebng.")
B.afD=new A.c0("L\u1ed1i Nai M\xf9 S\u01b0\u01a1ng","B\u1ea1ch Gi\xe1c H\u1ed3n Nai","S\u01b0\u01a1ng d\xe0y ph\u1ee7 k\xedn l\u1ed1i \u0111i, ch\u1ec9 th\u1ea5y chi\u1ebfc s\u1eebng tr\u1eafng ph\xe1t s\xe1ng c\u1ee7a m\u1ed9t con nai kh\u1ed5ng l\u1ed3. B\u01b0\u1edbc ch\xe2n n\xf3 kh\xf4ng g\xe2y ti\u1ebfng \u0111\u1ed9ng, nh\u01b0ng m\u1ed7i n\u01a1i n\xf3 \u0111i qua \u0111\u1ec1u m\u1ecdc ra nh\u1eefng c\xe0nh c\u1ecf m\u1ec1m \xf4m l\u1ea5y x\u01b0\u01a1ng th\xfa c\u0169.","Linh nai n\xe0y t\u1eebng d\u1eabn b\u1ea7y con ng\u01b0\u1eddi l\u1ea1c \u0111\u01b0\u1eddng t\u1edbi v\xf9ng an to\xe0n s\xe2u trong r\u1eebng. \u0110\u1ebfn khi \u0111o\xe0n ng\u01b0\u1eddi cu\u1ed1i c\xf9ng kh\xf4ng tr\u1edf l\u1ea1i n\u1eefa, n\xf3 \u1edf l\u1ea1i canh l\u1ed1i m\xf9 \u0111\u1ec3 kh\xf4ng th\xeam sinh linh n\xe0o ph\u1ea3i \u0111i v\xe0o n\u1ed7i l\u1ea1c m\u1ea5t m\u1ed9t m\xecnh.")
B.afB=new A.c0("Tr\u1ee5 M\xe2y D\xe2y Qu\u1ea5n","V\xe2n \u0110\u1eb1ng H\u1ed9 C\u1ea3nh","M\u1ed9t c\u1ed9t g\u1ed7 kh\u1ed5ng l\u1ed3 \u0111\xe2m th\u1eb3ng l\xean m\xe2y, quanh th\xe2n c\u1ed9t l\xe0 v\xf4 s\u1ed1 d\xe2y leo qu\u1ea5n ch\u1eb1ng ch\u1ecbt nh\u01b0 \u1ea5n ch\xfa s\u1ed1ng. T\u1eeb \u0111\u1ec9nh c\u1ed9t v\u1ecdng xu\u1ed1ng nh\u1ecbp tim n\u1eb7ng n\u1ec1 c\u1ee7a th\u1ee9 g\xec \u0111\xf3 ch\u01b0a ch\u1ecbu ng\u1ee7 y\xean.","\u0110\u1eb1ng linh n\xe0y \u0111\xe3 tr\xf3i th\xe2n m\xecnh quanh c\u1ed9t thi\xean m\u1ea1ch \u0111\u1ec3 v\xe1 ch\u1ed7 n\u1ee9t gi\u1eefa b\u1ea7u tr\u1eddi v\xe0 r\u1eebng s\xe2u. N\xf3 tr\u1ea5n gi\u1eef n\u01a1i \u0111\xe2y qua v\xf4 s\u1ed1 m\xf9a m\u01b0a, ch\u1ea5p nh\u1eadn \u0111\u1ec3 th\xe2n th\u1ec3 m\u1ee5c d\u1ea7n ch\u1ec9 \u0111\u1ec3 thi\xean kh\xed kh\xf4ng gi\xe1ng n\xe1t T\u1ecbch L\xe2m th\xeam l\u1ea7n n\u1eefa.")
B.afQ=new A.c0("M\u1ed9 Ph\u01b0\u1ee3ng M\u1ed9c","Ph\u01b0\u1ee3ng C\u1ed1t Thanh V\xe2n","Gi\u1eefa r\u1eebng m\u1ecdc l\xean b\u1ed9 x\u01b0\u01a1ng ph\u01b0\u1ee3ng ho\xe0ng h\xf3a g\u1ed7 xanh, t\u1eebng chi\u1ebfc x\u01b0\u01a1ng s\u01b0\u1eddn th\xe0nh v\xf2m l\xe1 che k\xedn kho\u1ea3ng tr\u1eddi. Trong l\u1ed3ng ng\u1ef1c kh\xf4 \u1ea5y c\xf3 m\u1ed9t t\xe0n h\u1ed3n \u0111ang ng\u1ee7 g\u1eadt tr\xean \u0111\u1ed1m l\u1eeda l\u1ee5c r\u1ea5t nh\u1ecf.","Con ph\u01b0\u1ee3ng n\xe0y t\u1eebng lao xu\u1ed1ng d\u1eadp t\u1eaft h\u1ecfa ki\u1ebfp qu\xe9t qua r\u1eebng b\u1eb1ng ch\xednh linh h\u1ecfa c\u1ee7a m\xecnh, r\u1ed3i ng\xe3 l\u1ea1i th\xe0nh m\u1ed9t b\u1ed9 khung h\xf3a m\u1ed9c. T\xe0n h\u1ed3n c\u1ee7a n\xf3 kh\xf4ng ch\u1ecbu si\xeau tho\xe1t, ch\u1ec9 v\xec s\u1ee3 r\u1eebng s\u1ebd ch\xe1y l\u1ea7n n\u1eefa n\u1ebfu kh\xf4ng c\xf2n ai nh\u1edb c\xe1i gi\xe1 \u0111\xe3 tr\u1ea3.")
B.afo=new A.c0("B\xe3i S\u1eebng R\u1ee5ng","L\u1ed9c V\u01b0\u01a1ng T\xe1i Sinh","H\xe0ng tr\u0103m c\u1eb7p s\u1eebng linh l\u1ed9c c\u1eafm xu\u1ed1ng \u0111\u1ea5t nh\u01b0 r\u1eebng c\xe2y nh\u1ecf, chung quanh m\u1ecdc \u0111\u1ea7y r\xeau m\u1ec1m. Gi\u1eefa b\xe3i l\xe0 m\u1ed9t linh l\u1ed9c gi\xe0 \u0111ang \u0111\u1ec3 c\xe0nh l\xe1 \u0111\xe2m ra t\u1eeb ch\xednh nh\u1eefng chi\u1ebfc s\u1eebng c\u0169 c\u1ee7a m\xecnh.","L\u1ed9c v\u01b0\u01a1ng \u0111\xe3 d\u1ea1y b\u1ea7y con m\u1ed7i l\u1ea7n r\u1ee5ng s\u1eebng ph\u1ea3i ch\xf4n l\u1ea1i nh\u01b0 gieo h\u1ea1t, \u0111\u1ec3 c\xe1i m\u1ea5t \u0111i c\u1ee7a m\u1ed9t \u0111\u1eddi tr\u1edf th\xe0nh m\xe1i che cho \u0111\u1eddi sau. H\u1eafn canh gi\u1eef b\xe3i n\xe0y nh\u01b0 m\u1ed9t t\u1ed9c ph\u1ea3 kh\xf4ng vi\u1ebft ch\u1eef, ch\u1ec9 vi\u1ebft b\u1eb1ng th\xe2n x\xe1c \u0111\u01b0\u1ee3c trao \u0111i.")
B.af7=new A.c0("\u0110\xe0i Hoa U Minh","U Hoa Tr\u1ea5n D\u1ea1","Nh\u1eefng \u0111\xf3a hoa \u0111en m\u1edf ra ngay c\u1ea3 trong \xe1nh ng\xe0y, nh\u1ee5y ph\xe1t s\xe1ng t\xedm nh\u1ea1t nh\u01b0 m\u1eaft m\u1edf trong b\xf3ng t\u1ed1i. Tr\xean b\u1ec7 \u0111\xe1 ph\u1ee7 r\xeau \u0111\u1ee9ng m\u1ed9t tinh linh hoa mang khu\xf4n m\u1eb7t \u0111\u1eb9p \u0111\u1ebfn l\u1ea1nh l\u1ebdo.","U Hoa \u0111\u01b0\u1ee3c sinh ra \u0111\u1ec3 h\xfat \u0111\u1ed9c ra kh\u1ecfi \u0111\u1ea5t sau tr\u1eadn th\u01b0 \u0111\u1ed9c khi\u1ebfn c\u1ea3 c\xe1nh r\u1eebng ch\u1ebft l\u1eb7ng. M\u1ed7i c\xe1nh hoa n\xf3 n\u1edf l\xe0 m\u1ed9t ph\u1ea7n \u0111\u1ed9c l\u1ef1c \u0111\u01b0\u1ee3c gi\u1eef l\u1ea1i trong th\xe2n, v\xec th\u1ebf s\u1eafc \u0111\u1eb9p n\u01a1i n\xe0y th\u1ef1c ra l\xe0 h\xecnh d\u1ea1ng c\u1ee7a \u0111au \u0111\u1edbn \u0111\xe3 b\u1ecb kh\xf3a k\xedn.")
B.afH=new A.c0("S\u01b0\u1eddn D\u1ed1c G\u1ecdi Gi\xf3","Th\u1ee5 Nh\xe2n Ph\u1ea5t Di\u1ec7p","M\u1ed9t h\xe0ng c\xe2y nghi\xeang m\xecnh c\xf9ng m\u1ed9t h\u01b0\u1edbng nh\u01b0 \u0111ang c\xfai ch\xe0o c\u01a1n gi\xf3 c\u1ed5 x\u01b0a n\xe0o \u0111\xf3. \u1ede \u0111\u1ea7u d\u1ed1c, th\u1ee5 nh\xe2n cao nh\u01b0 th\xe1p d\xf9ng c\xe0nh tay qu\u1ea1t l\xe1, m\u1ed7i nh\u1ecbp qu\u1ea1t l\xe0m c\u1ea3 s\u01b0\u1eddn \u0111\u1ed3i r\xec r\xe0o nh\u01b0 ti\u1ebfng b\u01b0\u1edbc ng\u01b0\u1eddi x\u01b0a.","Th\u1ee5 nh\xe2n n\xe0y t\u1eebng thay gi\xf3 g\u1ecdi \u0111\xe0n chim mang h\u1ea1t gi\u1ed1ng \u0111i kh\u1eafp mi\u1ec1n \u0111\u1ea5t c\u1ea1n ki\u1ec7t. Khi chim th\u1ea7n ch\u1ebft d\u1ea7n, n\xf3 \u1edf l\u1ea1i l\xe0m ch\xednh c\u01a1n gi\xf3, gi\u1eef cho s\u1ef1 h\u1ed3i sinh c\u1ee7a khu r\u1eebng kh\xf4ng b\u1ecb \u0111\u1ee9t \u0111o\u1ea1n gi\u1eefa ch\u1eebng.")
B.afk=new A.c0("C\u1ea7u R\xeau Linh","M\u1ed9c Ly Th\u1ee7 Ki\u1ec1u","M\u1ed9t c\xe2y c\u1ea7u s\u1ed1ng b\u1eafc qua v\u1ef1c s\xe2u, m\u1eb7t c\u1ea7u ch\xednh l\xe0 l\u01b0ng c\u1ee7a nh\u1eefng th\xe2n r\xeau k\u1ebft l\u1ea1i. Ng\u01b0\u1eddi gi\u1eef c\u1ea7u l\xe0 sinh v\u1eadt n\u1eeda ch\u1ed3n n\u1eeda c\xe2y, \u0111\xf4i tai b\u1eb1ng l\xe1 li\xean t\u1ee5c nghi\xeang nghe nh\u1eefng ti\u1ebfng \u0111\u1ed9ng kh\xf4ng thu\u1ed9c v\u1ec1 hi\u1ec7n t\u1ea1i.","M\u1ed9c Ly t\u1eebng \u0111\u01b0a c\xe1c ti\xean linh nh\u1ecf v\u01b0\u1ee3t v\u1ef1c khi m\xf9a s\u0103n th\xfa huy\u1ec1n b\xed \u1eadp t\u1edbi. N\xf3 kh\xf4ng gi\u1eef c\u1ea7u v\xec quy\u1ec1n l\u1ef1c, m\xe0 v\xec ch\u01b0a bao gi\u1edd tha th\u1ee9 cho b\u1ea3n th\xe2n chuy\u1ec7n \u0111\xe3 \u0111\u1ec3 r\u01a1i m\u1ea5t m\u1ed9t b\u1ea7y con trong l\u1ea7n ch\u1ea1y \u0111\u1ea7u ti\xean.")
B.afR=new A.c0("Tr\u0169ng H\u01b0\u01a1u Ng\u1ee7","M\u1eabu Linh \u1ee6 M\u1ed9ng","Trong l\xf2ng tr\u0169ng l\xe0 v\xf4 s\u1ed1 h\u01b0\u01a1u con b\u1eb1ng g\u1ed7 \u0111ang n\u1eb1m ng\u1ee7 nh\u01b0 ch\u01b0a t\u1eebng l\u1edbn l\xean. M\u1ed9t b\xf3ng m\u1eb9 b\u1eb1ng l\xe1 ng\u1ed3i quanh \u0111\xf3, tay vu\u1ed1t m\xe3i l\xean tr\xe1n t\u1eebng con trong m\u1ed9t c\u1eed ch\u1ec9 \u0111\xe3 h\xf3a th\xe0nh nghi l\u1ec5.","M\u1eabu linh n\xe0y gom h\u1ed3n c\u1ee7a nh\u1eefng linh th\xfa non ch\u1ebft qu\xe1 s\u1edbm v\xe0o nh\u1eefng th\xe2n g\u1ed7 nh\u1ecf \u0111\u1ec3 ch\xfang c\xf2n m\u1ed9t gi\u1ea5c ng\u1ee7 nguy\xean v\u1eb9n. N\xe0ng bi\u1ebft \u0111\xf3 kh\xf4ng ph\u1ea3i h\u1ed3i sinh, nh\u01b0ng c\u0169ng kh\xf4ng \u0111\xe0nh \u0111\u1ec3 tu\u1ed5i nh\u1ecf c\u1ee7a ch\xfang bi\u1ebfn m\u1ea5t trong kho\u1ea3ng t\u1ed1i v\xf4 danh.")
B.afn=new A.c0("R\u1ec5 \xd4m Tinh \u0110\xe0i","Tinh M\u1ed9c Quan Thi\xean","M\u1ed9t \u0111\xe0i quan s\xe1t c\u1ed5 b\u1ecb r\u1ec5 c\xe2y qu\u1ea5n k\xedn t\u1edbi t\u1eadn \u0111\u1ec9nh, ch\u1ec9 c\xf2n v\xe0i khe h\u1edf \u0111\u1ee7 th\u1ea5y tr\u1eddi xanh ng\u1ecdc ph\xeda sau. Tr\xean b\u1eadc cao nh\u1ea5t l\xe0 m\u1ed9t linh th\u1ec3 b\u1eb1ng v\u1ecf c\xe2y \u0111ang ng\u01b0\u1edbc m\xe3i l\xean tr\u1eddi kh\xf4ng ch\u1edbp m\u1eaft.","N\xf3 t\u1eebng d\xf9ng tinh \u0111\xe0i n\xe0y \u0111o v\u1eadn chuy\u1ec3n linh kh\xed \u0111\u1ec3 tr\xe1nh nh\u1eefng \u0111\u1ee3t th\xfa d\u1eef tr\xe0n xu\u1ed1ng. Khi c\xe1c v\xec sao \u0111\u1ed5i l\u1ed1i v\xe0 con ng\u01b0\u1eddi ng\u1eebng \u0111\u1ebfn, n\xf3 \u0111\u1ec3 r\u1ec5 nu\u1ed1t c\u1ea3 \u0111\xe0i, bi\u1ebfn tri th\u1ee9c c\u1ee7a m\xecnh th\xe0nh m\u1ed9t ph\u1ea7n th\xe2n khu r\u1eebng thay v\xec th\xe0nh di v\u1eadt tr\u1ed1ng r\u1ed7ng.")
B.afL=new A.c0("V\xf2m \u0110om \u0110\xf3m M\u1ed9","Minh Tr\xf9ng Th\u1ee7 H\u1ed3n","V\xf4 s\u1ed1 \u0111om \u0111\xf3m xanh \u0111\u1eadu th\xe0nh m\xe1i v\xf2m tr\xean m\u1ed9t kho\u1ea3ng \u0111\u1ea5t \u0111\u1ea7y bia g\u1ed7 m\u1ee5c. \u1ede gi\u1eefa l\xe0 m\u1ed9t con tr\xf9ng kh\u1ed5ng l\u1ed3 trong su\u1ed1t, b\u1ee5ng n\xf3 ph\xe1t s\xe1ng b\u1eb1ng nh\u1ecbp th\u1edf r\u1ea5t \u0111\u1ec1u nh\u01b0 \u0111ang canh m\u1ed9t gi\u1ea5c ng\u1ee7 t\u1eadp th\u1ec3.","Minh Tr\xf9ng \u0103n k\xfd \u1ee9c h\xe3i h\xf9ng c\u1ee7a nh\u1eefng linh h\u1ed3n ch\u1ebft oan \u0111\u1ec3 ch\xfang c\xf3 th\u1ec3 ng\u1ee7 y\xean h\u01a1n. N\xf3 \u1edf l\u1ea1i \u0111\xe2y l\xe0m ng\u01b0\u1eddi canh m\u1ed9, t\u1ef1 g\xe1nh l\u1ea5y ph\u1ea7n \xe1m \u1ea3nh qu\xe1 n\u1eb7ng m\xe0 nh\u1eefng k\u1ebb \u0111\xe3 khu\u1ea5t kh\xf4ng c\xf2n s\u1ee9c mang ti\u1ebfp.")
B.afx=new A.c0("Hang G\u1ea5u M\u1ed9c","Th\u1ea7n H\xf9ng N\u1ee9t Vu\u1ed1t","Mi\u1ec7ng hang ph\u1ee7 \u0111\u1ea7y r\u1ec5 c\xe2y nh\u01b0 nh\u1eefng v\u1ebft kh\xe2u kh\u1ed5ng l\u1ed3. Trong b\xf3ng t\u1ed1i l\xe0 m\u1ed9t con g\u1ea5u th\u1ea7n l\u01b0ng m\u1ecdc \u0111\u1ecba lan, m\u1ed9t vu\u1ed1t tr\u01b0\u1edbc \u0111\xe3 n\u1ee9t v\u1ee1 nh\u01b0ng m\u1eaft v\u1eabn kh\xf4ng h\u1ec1 suy chuy\u1ec3n.","Th\u1ea7n H\xf9ng \u0111\xe3 d\xf9ng th\xe2n m\xecnh ch\u1eb7n \u0111\u1ee3t th\xfa h\xf3a \u0111i\xean lao v\xe0o \u1ed5 non trong m\xf9a \u0111en. V\u1ebft vu\u1ed1t g\xe3y \u1ea5y l\xe0 d\u1ea5u m\u1ed9t l\u1ea7n th\u1eafng r\u1ea5t \u0111\u1eaft, c\xf2n hang m\u1ed9c n\xe0y l\xe0 n\u01a1i n\xf3 gi\u1eef l\u1eddi h\u1ee9a r\u1eb1ng s\u1ebd kh\xf4ng \u0111\u1ec3 m\xe1u tr\u1ebb nh\u1ecf nhu\u1ed9m r\u1eebng l\u1ea7n n\u1eefa.")
B.afu=new A.c0("B\u1edd H\u1ed3 H\u1ea1t S\xe1ng","H\u1ed3 Linh Gieo H\u1ed3n","M\u1eb7t h\u1ed3 ph\u1ee7 k\xedn nh\u1eefng h\u1ea1t s\xe1ng li ti nh\u01b0 b\u1ea7u tr\u1eddi b\u1ecb \u0111\u1ed5 xu\u1ed1ng n\u01b0\u1edbc. M\u1ed9t tinh linh d\xe1ng ng\u01b0\u1eddi m\u1ea3nh nh\u01b0 c\xe0nh li\u1ec5u \u0111ang l\u1eb7ng l\u1ebd r\u1eafc th\xeam nh\u1eefng h\u1ea1t \u1ea5y xu\u1ed1ng m\u1eb7t h\u1ed3 b\u1eb1ng \u0111\xf4i tay run r\u1ea5t kh\u1ebd.","N\xe0ng gieo h\u1ea1t s\xe1ng t\u1eeb ph\u1ea7n linh th\u1ee9c c\xf2n s\xf3t c\u1ee7a c\xe1c ti\xean linh tan r\xe3, \u0111\u1ec3 h\u1ed3 ghi nh\u1edb t\u1eebng t\u1ed3n t\u1ea1i b\xe9 nh\u1ecf. C\u1eed ch\u1ec9 d\u1ecbu d\xe0ng \u1ea5y th\u1ef1c ra l\xe0 c\xf4ng vi\u1ec7c mai t\xe1ng d\xe0i nh\u1ea5t c\u1ee7a to\xe0n b\u1ed9 v\xf9ng \u0111\u1ea5t n\xe0y.")
B.afC=new A.c0("Gi\xe0n M\xe2y Xanh","Thanh \u0110\u1eb1ng Phi H\u1ea1c","Nh\u1eefng d\xe2y leo b\u1eafc qua kh\xf4ng trung th\xe0nh m\u1ed9t gi\xe0n m\xe2y xanh, n\u01a1i m\u1ed9t con h\u1ea1c g\u1ed7 \u0111ang \u0111i b\u1ed9 nh\u01b0 tr\xean m\u1eb7t \u0111\u1ea5t. M\u1ed7i nh\u1ecbp ch\xe2n c\u1ee7a n\xf3 l\xe0m kh\xf4ng kh\xed rung l\xean b\u1eb1ng ti\u1ebfng chu\xf4ng r\u1ea5t nh\u1ecf.","Phi H\u1ea1c t\u1eebng mang h\u1ea1t gi\u1ed1ng v\xe0 th\u01b0 \u01b0\u1edbc gi\u1eefa c\xe1c v\xf9ng ti\xean l\xe2m, l\xe0 s\u1ee9 gi\u1ea3 c\u1ee7a m\u1ed9t th\u1eddi \u0111\u1ea1i c\xf2n tin v\xe0o chung s\u1ed1ng. Khi hi\u1ec7p \u01b0\u1edbc tan theo m\xe1u v\xe0 l\u1eeda, n\xf3 t\u1ef1 bi\u1ebfn m\xecnh th\xe0nh k\u1ebb tu\u1ea7n tra c\xf4 \u0111\u1ed9c tr\xean con \u0111\u01b0\u1eddng m\xe2y kh\xf4ng c\xf2n \u0111i\u1ec3m \u0111\u1ebfn.")
B.afS=new A.c0("M\u1ea1ch Tr\xfac \u0110en","Tr\xfac Y\xeau T\xe0ng Ki\u1ebfm","R\u1eebng tr\xfac \u1edf \u0111\xe2y \u0111en b\xf3ng nh\u01b0 s\u1eaft, m\u1ed7i khi va nhau \u0111\u1ec1u k\xeau ti\u1ebfng kim kh\xed l\u1ea1nh. Trong l\xf5i r\u1eebng l\xe0 m\u1ed9t th\xe2n tr\xfac c\xf3 h\xecnh ng\u01b0\u1eddi, b\xean h\xf4ng c\u1eafm \u0111\u1ea7y nh\u1eefng m\u1ea3nh ki\u1ebfm c\u0169 \u0111\xe3 b\u1ecb r\u1ec5 nu\u1ed1t m\u1ea5t n\u1eeda l\u01b0\u1ee1i.","Tr\xfac y\xeau n\xe0y t\u1eebng nh\u1eb7t v\u0169 kh\xed r\u01a1i l\u1ea1i sau m\u1ed9t cu\u1ed9c th\u1ea3m s\xe1t r\u1ed3i nu\u1ed1t h\u1ebft v\xe0o th\xe2n \u0111\u1ec3 kh\xf4ng ai c\xf3 th\u1ec3 d\xf9ng ch\xfang gi\u1ebft ch\xf3c th\xeam n\u1eefa. M\u1ed7i m\u1ea3nh ki\u1ebfm trong ng\u01b0\u1eddi n\xf3 l\xe0 m\u1ed9t l\u1eddi tuy\xean b\u1ed1 c\xe2m l\u1eb7ng r\u1eb1ng khu r\u1eebng th\xe0 \u0111au c\xf2n h\u01a1n \u0111\u1ec3 b\u1ea1o l\u1ef1c \u0111\u01b0\u1ee3c l\u01b0u truy\u1ec1n nguy\xean v\u1eb9n.")
B.afq=new A.c0("\u0110\u01b0\u1eddng Ve X\xe1c","C\u1eedu X\xe1c Thi\u1ec1n V\u01b0\u01a1ng","Hai b\xean \u0111\u01b0\u1eddng treo k\xedn x\xe1c ve trong su\u1ed1t, t\u1eebng l\u1edbp t\u1eebng l\u1edbp nh\u01b0 nh\u1eefng chi\u1ebfc chu\xf4ng m\u1ecfng. \u1ede cu\u1ed1i \u0111\u01b0\u1eddng l\xe0 m\u1ed9t c\u1ef1 thi\u1ec1n c\xf3 ch\xedn l\u1ea7n l\u1ed9t x\xe1c ch\u01b0a ch\u1ecbu b\u1ecf \u0111i, m\u1eaft v\xe0ng s\xe2u nh\u01b0 nh\xecn xuy\xean qua c\xe1c m\xf9a.","Thi\u1ec1n v\u01b0\u01a1ng gi\u1eef l\u1ea1i v\u1ecf x\xe1c c\u0169 \u0111\u1ec3 d\u1ea1y h\u1eadu sinh r\u1eb1ng t\xe1i sinh kh\xf4ng c\xf3 ngh\u0129a l\xe0 ph\u1ee7 nh\u1eadn n\u1ed7i \u0111au c\u1ee7a h\xecnh d\u1ea1ng tr\u01b0\u1edbc. N\xf3 canh con \u0111\u01b0\u1eddng n\xe0y \u0111\u1ec3 m\u1ecdi k\u1ebb b\u01b0\u1edbc qua \u0111\u1ec1u hi\u1ec3u tr\u01b0\u1edfng th\xe0nh c\u0169ng l\xe0 mang theo r\u1ea5t nhi\u1ec1u ph\u1ea7n \u0111\xe3 ch\u1ebft c\u1ee7a ch\xednh m\xecnh.")
B.afj=new A.c0("B\u1ebfn S\xf3i L\xe1","M\u1ed9c Lang G\u1ecdi \u0110\xe0n","B\u1ebfn \u0111\u1ea5t b\xean su\u1ed1i \u0111\u1ea7y d\u1ea5u ch\xe2n s\xf3i, nh\u01b0ng to\xe0n l\xe0m b\u1eb1ng l\xe1 n\xe9n ch\u1eb7t xu\u1ed1ng b\xf9n. Tr\xean t\u1ea3ng \u0111\xe1 \u0111\u1ea7u b\u1ebfn, con s\xf3i l\u1edbn ph\u1ee7 r\xeau xanh ng\u1eeda c\u1ed5 tru m\xe0 \xe2m thanh ph\xe1t ra l\u1ea1i gi\u1ed1ng ti\u1ebfng s\xe1o g\u1ecdi b\u1ea1n.","M\u1ed9c Lang l\xe0 k\u1ebb d\u1eabn \u0111\u1ea7u \u0111\xe0n th\xfa tr\u1ed1n cu\u1ed9c s\u0103n linh c\u1ed1t cu\u1ed1i c\xf9ng c\u1ee7a con ng\u01b0\u1eddi. N\xf3 gi\u1eef b\u1ebfn n\xe0y v\xec t\u1eebng m\u1ea5t n\u1eeda \u0111\xe0n khi ch\u1ecdn sai \u0111\u01b0\u1eddng, n\xean t\u1eeb \u0111\xf3 th\u1ec1 r\u1eb1ng b\u1ea5t c\u1ee9 sinh v\u1eadt n\xe0o \u0111i l\u1ea1c t\u1edbi \u0111\xe2y c\u0169ng ph\u1ea3i \u0111\u01b0\u1ee3c nghe ti\u1ebfng g\u1ecdi tr\u1edf v\u1ec1.")
B.afs=new A.c0("Th\u1ec1m H\u1ea1t M\u1ea7m","\u1ea4u Th\u1ee5 Tr\xf4ng Xu\xe2n","C\u1ea3 th\u1ec1m \u0111\xe1 ph\u1ee7 k\xedn nh\u1eefng h\u1ea1t m\u1ea7m to b\u1eb1ng n\u1eafm tay \u0111ang ng\u1ee7 d\u01b0\u1edbi l\u1edbp s\u01b0\u01a1ng m\u1ecfng. \u1ede gi\u1eefa l\xe0 m\u1ed9t c\xe2y non c\xf3 m\u1eaft tr\u1ebb con, d\xe1ng nh\u1ecf nh\u01b0ng kh\xed t\u1ee9c l\u1ea1i d\xe0y nh\u01b0 gi\u1eef c\u1ea3 m\u1ed9t m\xf9a xu\xe2n ch\u01b0a t\u1edbi.","\u1ea4u th\u1ee5 n\xe0y \u0111\u01b0\u1ee3c giao tr\xf4ng h\u1ea1t gi\u1ed1ng c\u1ee7a to\xe0n v\xf9ng ph\xf2ng khi T\u1ecbch L\xe2m b\u1ecb t\u1eadn di\u1ec7t. N\xf3 ch\u01b0a t\u1eebng l\u1edbn l\xean v\xec c\u1ee9 li\xean t\u1ee5c nh\u01b0\u1eddng linh l\u1ef1c cho nh\u1eefng m\u1ea7m ng\u1ee7 quanh m\xecnh, ch\u1ecdn gi\u1eef t\u01b0\u01a1ng lai c\u1ee7a khu r\u1eebng thay v\xec tr\u01b0\u1edfng th\xe0nh cho ri\xeang b\u1ea3n th\xe2n.")
B.afe=new A.c0("B\xe3i X\u01b0\u01a1ng Long C\u1ed1t","Thanh Long M\u1ed9c \u1ea2nh","M\u1ed9t b\u1ed9 x\u01b0\u01a1ng long h\xf3a th\xe0nh g\u1ed7 xanh n\u1eb1m v\u1eaft ngang b\xe3i c\u1ecf r\u1ed9ng, c\u1ed9t s\u1ed1ng c\u1ee7a n\xf3 m\u1ecdc \u0111\u1ea7y hoa tr\u1eafng. Gi\u1eefa c\xe1c \u0111\u1ed1t x\u01b0\u01a1ng l\u1ea5p l\xf3 m\u1ed9t c\xe1i b\xf3ng r\u1ed3ng b\u1eb1ng l\xe1 \u0111ang l\u01b0\u1ee3n ch\u1eadm nh\u01b0 gi\u1eef l\u1ec5 cho c\xe1i x\xe1c kh\u1ed5ng l\u1ed3 c\u1ee7a ch\xednh m\xecnh.","Thanh long n\xe0y hy sinh th\xe2n x\xe1c \u0111\u1ec3 phong k\xedn con \u0111\u01b0\u1eddng th\u1ee3 s\u0103n ti\u1ebfn v\xe0o tim r\u1eebng. B\xf3ng l\xe1 c\xf2n l\u1ea1i c\u1ee7a n\xf3 canh b\u1ed9 x\u01b0\u01a1ng kh\xf4ng ph\u1ea3i v\xec ti\u1ebfc m\xecnh, m\xe0 v\xec s\u1ee3 m\u1ed9t ng\xe0y ai \u0111\xf3 \u0111\xe0o l\xean r\u1ed3i l\u1ea1i bi\u1ebfn x\u01b0\u01a1ng thi\xeang th\xe0nh chi\u1ebfn l\u1ee3i ph\u1ea9m.")
B.afc=new A.c0("H\u1ed3 Sen Kh\xf4ng Ng\u01b0\u1eddi","Li\xean Linh Gi\u1eef T\u1ecbnh","M\u1eb7t h\u1ed3 d\xe0y \u0111\u1eb7c sen l\u1edbn b\u1eb1ng thuy\u1ec1n nh\u1ecf, nh\u01b0ng kh\xf4ng c\xf3 l\u1ea5y m\u1ed9t c\xf4n tr\xf9ng n\xe0o \u0111\u1eadu l\xean. Tr\xean \u0111\xe0i sen gi\u1eefa h\u1ed3, m\u1ed9t linh n\u1eef b\u1eb1ng c\xe1nh hoa \u0111ang nh\u1eafm m\u1eaft nh\u01b0 gi\u1eef cho m\u1eb7t n\u01b0\u1edbc n\xe0y kh\u1ecfi nh\u1edb l\u1ea1i \u0111i\u1ec1u qu\xe1 \u0111au.","Li\xean Linh t\u1eebng h\u1ea5p th\u1ee5 nh\u1eefng c\u01a1n ho\u1ea3ng lo\u1ea1n cu\u1ed1i c\xf9ng c\u1ee7a b\u1ea7y ti\xean linh ch\u1ea1y n\u1ea1n \u0111\u1ec3 ch\xfang kh\xf4ng l\xe0m h\u1ed3 nhi\u1ec5m \u0111\u1ed9c linh kh\xed. S\u1ef1 t\u0129nh l\u1eb7ng tuy\u1ec7t \u0111\u1ed1i \u1edf \u0111\xe2y l\xe0 th\u1ee9 y\xean b\xecnh \u0111\u01b0\u1ee3c mua b\u1eb1ng vi\u1ec7c m\u1ed9t m\xecnh n\xe0ng g\xe1nh h\u1ebft \u0111\xeam d\xe0i c\u1ee7a ng\u01b0\u1eddi kh\xe1c.")
B.afb=new A.c0("M\u1ea1ch C\xe2y Song Sinh","Nh\u1ecb M\u1ed9c \u0110\u1ed3ng T\xe2m","Hai th\xe2n c\xe2y kh\u1ed5ng l\u1ed3 m\u1ecdc xo\u1eafn v\xe0o nhau, v\u1ecf m\u1ed9t tr\u1eafng m\u1ed9t l\u1ee5c nh\u01b0 ng\xe0y v\xe0 \u0111\xeam \xf4m ch\u1eb7t l\u1ea5y nhau. T\u1eeb th\xe2n c\xe2y t\xe1ch ra hai g\u01b0\u01a1ng m\u1eb7t gi\u1ed1ng h\u1ec7t, c\xf9ng nh\xecn xu\u1ed1ng ta b\u1eb1ng m\u1ed9t n\u1ed7i c\u1ea3nh gi\xe1c \u0111\xe3 luy\u1ec7n th\xe0nh ph\u1ea3n x\u1ea1.","C\u1eb7p song th\u1ee5 n\xe0y sinh ra \u0111\u1ec3 thay nhau canh gi\u1ea5c ng\u1ee7 c\u1ee7a h\u1ea1t m\u1ea7m linh ch\u1ee7. Khi m\u1ed9t c\xe2y t\u1eebng \u0111\u1ecbnh \u0111\u1ed1n n\u1eeda th\xe2n m\xecnh c\u1ee9u v\xf9ng ch\xe1y, c\xe2y c\xf2n l\u1ea1i \u0111\xe3 d\xf9ng c\u1ea3 \u0111\u1eddi r\u1ec5 gi\u1eef b\u1ea1n \u1edf l\u1ea1i. T\u1eeb \u0111\xf3, ch\xfang canh n\u01a1i n\xe0y nh\u01b0 minh ch\u1ee9ng r\u1eb1ng c\u1ee9u r\u1ed7i \u0111\xf4i khi c\u0169ng c\u1ea7n hai k\u1ebb c\xf9ng g\xe1nh m\u1ed9t quy\u1ebft \u0111\u1ecbnh kh\xf4ng tr\u1ecdn v\u1eb9n.")
B.afO=new A.c0("L\u1ec1u R\xeau C\u1ed5 T\xedch","M\u1ed9c Y\xeau K\u1ec3 S\u1eed","Gi\u1eefa v\xf2ng c\xe2y c\xf3 m\u1ed9t t\xfap l\u1ec1u r\xeau tr\xf4ng nh\u01b0 ch\u1ed7 \u1edf c\u1ee7a ai \u0111\xf3 v\u1eeba r\u1eddi \u0111i, nh\u01b0ng b\xean trong ch\u1ec9 c\xf3 s\xe1ch l\xe0m t\u1eeb l\xe1 kh\xf4. Ch\u1ee7 l\u1ec1u l\xe0 m\u1ed9c y\xeau nh\u1ecf b\xe9 c\xf3 \u0111\xf4i m\u1eaft gi\xe0 nua, \u0111ang ch\xe9p l\u1ea1i chuy\u1ec7n c\u0169 l\xean m\u1eb7t phi\u1ebfn l\xe1 b\u1eb1ng gai nh\u1ecdn.","N\xf3 l\xe0 k\u1ebb ch\xe9p s\u1eed cu\u1ed1i c\xf9ng c\u1ee7a T\u1ecbch L\xe2m, l\u01b0u l\u1ea1i t\xean t\u1eebng gi\u1ed1ng lo\xe0i \u0111\xe3 bi\u1ebfn m\u1ea5t khi kh\xf4ng c\xf2n ai \u0111\u1ec3 g\u1ecdi ch\xfang n\u1eefa. C\u1ea3 t\xfap l\u1ec1u l\xe0 th\u01b0 vi\u1ec7n c\u1ee7a nh\u1eefng sinh v\u1eadt kh\xf4ng bi\u1ebft vi\u1ebft, n\xean t\u1eebng trang l\xe1 \u1edf \u0111\xe2y \u0111\u1ec1u \u0111\xe1ng gi\xe1 nh\u01b0 m\u1ed9t bia m\u1ed9 bi\u1ebft th\u1edf.")
B.afT=new A.c0("Th\xe1c M\u1ea7m Xanh","Th\u1ee7y M\u1ed9c D\u1eabn H\u1ed3n","M\u1ed9t con th\xe1c m\u1ecfng nh\u01b0 d\u1ea3i l\u1ee5a \u0111\u1ed5 qua t\u01b0\u1eddng r\xeau, b\xean trong n\u01b0\u1edbc m\u1ecdc l\u1eabn c\xe1c ch\u1ed3i non \u0111ang tr\xf4i ng\u01b0\u1ee3c l\xean tr\xean. \u1ede m\xe9p th\xe1c l\xe0 sinh linh n\u1eeda n\u01b0\u1edbc n\u1eeda c\xe2y, b\xe0n tay n\xf3 c\u1ee9 m\xe3i v\u1edbt nh\u1eefng \u0111\u1ed1m s\xe1ng kh\u1ecfi d\xf2ng ch\u1ea3y.","N\xf3 d\u1eabn h\u1ed3n c\xe1c sinh v\u1eadt g\xe3y linh m\u1ea1ch v\u1ec1 n\u01a1i t\xe1i sinh b\u1eb1ng con th\xe1c n\xe0y, \u0111\u1ed5i l\u1ea1i b\u1ea3n th\xe2n m\u1ed7i ng\xe0y m\u1ea5t d\u1ea7n h\xecnh ng\u01b0\u1eddi. Gi\u1eef th\xe1c xanh ng\u01b0\u1ee3c chi\u1ec1u \u0111\u1eddi l\xe0 c\xe1ch cu\u1ed1i c\xf9ng n\xf3 n\xedu cho v\xf2ng s\u1ed1ng ch\u1ebft \u1edf T\u1ecbch L\xe2m kh\xf4ng \u0111\u1ee9t h\u1eb3n.")
B.afI=new A.c0("L\u1ed1i H\u1ed3 \u0110i\u1ec7p C\u1ed1t","\u0110i\u1ec7p Linh T\xe0ng Xu\xe2n","Xung quanh l\u1ed1i \u0111i bay d\xe0y nh\u1eefng con b\u01b0\u1edbm l\xe1, c\xe1nh ch\xfang in hoa v\u0103n gi\u1ed1ng x\u01b0\u01a1ng s\u01b0\u1eddn. M\u1ed9t c\xf4 g\xe1i b\u1eb1ng c\xe0nh m\u1ea3nh \u0111\u1ee9ng gi\u1eefa \u0111\xe0n b\u01b0\u1edbm, v\u1eeba \u0111\u1eb9p v\u1eeba g\u1ee3i c\u1ea3m gi\xe1c nh\u01b0 c\u1ea3 th\xe2n th\u1ec3 n\xe0ng \u0111\u01b0\u1ee3c gh\xe9p t\u1eeb th\u1ee9 r\u1ea5t d\u1ec5 tan.","\u0110i\u1ec7p Linh gi\u1eef trong \u0111\xe0n b\u01b0\u1edbm nh\u1eefng k\xfd \u1ee9c vui \xedt \u1ecfi c\xf2n s\xf3t c\u1ee7a khu r\u1eebng, \u0111\u1ec3 s\u1ef1 s\u1ed1ng \u1edf \u0111\xe2y kh\xf4ng ch\u1ec9 c\xf2n bi\u1ebft t\u1edbi tang t\xf3c. N\xe0ng chi\u1ebfn \u0111\u1ea5u d\u1eef d\u1ed9i kh\xf4ng ph\u1ea3i v\xec hi\u1ebfu chi\u1ebfn, m\xe0 v\xec s\u1ee3 m\u1ed9t ng\xe0y n\u1ee5 c\u01b0\u1eddi cu\u1ed1i c\xf9ng c\u1ee7a T\u1ecbch L\xe2m c\u0169ng b\u1ecb b\xe0o m\xf2n m\u1ea5t.")
B.afl=new A.c0("R\xe3nh H\u1ed5 Ph\xe1ch","H\u1ed5 Ph\xe1ch S\u01a1n Mi\xeau","M\u1ed9t r\xe3nh s\xe2u \u0111\u1ea7y nh\u1ef1a c\xe2y k\u1ebft c\u1ee9ng nh\u01b0 v\xe0ng n\xe2u, trong \u0111\xf3 l\u1ed9 ra v\xf4 s\u1ed1 c\xe1nh c\xf4n tr\xf9ng c\u1ed5. Tr\xean m\xe9p r\xe3nh, con s\u01a1n mi\xeau \u0111u\xf4i d\xe2y leo b\u01b0\u1edbc r\u1ea5t nh\u1eb9, m\u1eaft n\xf3 ph\u1ea3n chi\u1ebfu th\u1eddi gian nh\u01b0 \u0111\xe1 h\u1ed5 ph\xe1ch s\u1ed1ng.","S\u01a1n mi\xeau n\xe0y \u0111\xe3 gom nh\u1ef1a c\xe2y b\u1ecb th\u01b0\u01a1ng c\u1ee7a linh m\u1ed9c v\xe0o r\xe3nh s\xe2u \u0111\u1ec3 gi\u1eef l\u1ea1i h\u1ea1t gi\u1ed1ng v\xe0 \u1ea5u tr\xf9ng kh\u1ecfi m\xf9a b\u0103ng \u0111\u1ed9c. N\xf3 canh kho h\u1ed5 ph\xe1ch \u1ea5y nh\u01b0 m\u1ed9t b\u1ea3o t\xe0ng c\u1ee7a nh\u1eefng m\u1ea7m s\u1ed1ng t\u1eebng su\xfdt b\u1ecb x\xf3a kh\u1ecfi ti\u1ebfn tr\xecnh t\xe1i sinh.")
B.afy=new A.c0("V\xe0nh \u0110ai T\u1ea7m G\u1eedi","T\u1ea7m Linh M\u1eabu Ch\u1ee7","Nh\u1eefng kh\u1ed1i t\u1ea7m g\u1eedi to nh\u01b0 m\xe1i nh\xe0 treo k\xedn quanh m\u1ed9t th\xe2n c\u1ed5 th\u1ee5 r\u1ed7ng ru\u1ed9t. Gi\u1eefa \u0111\xf3 l\xe0 m\u1ed9t m\u1eabu ch\u1ee7 b\xe1n th\xe2n b\xe1m v\xe0o g\u1ed7, n\u1eeda tr\xean duy\xean d\xe1ng nh\u01b0 ti\xean, n\u1eeda d\u01b0\u1edbi l\u1ea1i h\xf2a v\xe0o \u0111\xe1m r\u1ec5 h\xfat s\u1ef1 s\u1ed1ng \u0111\u1ea7y \xe1m \u1ea3nh.","T\u1ea7m Linh t\u1eebng b\u1ecb c\u1ea3 r\u1eebng xem l\xe0 k\xfd sinh, nh\u01b0ng ch\xednh n\xe0ng \u0111\xe3 c\xf5ng nh\u1eefng m\u1ea7m b\u1ec7nh \u0111\u1ed9c ra kh\u1ecfi l\xf5i m\u1ea1ch b\u1eb1ng c\xe1ch h\xfat ch\xfang v\xe0o ng\u01b0\u1eddi m\xecnh. C\xe1i d\xe1ng n\u1eeda ng\u01b0\u1eddi n\u1eeda c\xe2y n\u01a1i \u0111\xe2y l\xe0 h\xecnh ph\u1ea1t l\u1eabn vinh quang c\u1ee7a m\u1ed9t k\u1ebb ch\u1ea5p nh\u1eadn b\u1ecb hi\u1ec3u l\u1ea7m \u0111\u1ec3 c\u1ee9u c\u1ea3 qu\u1ea7n l\xe2m.")
B.afv=new A.c0("Ng\u1ecdn C\u1ecf D\u1ef1 Ng\xf4n","Ti\u1ec3u Linh Ch\u1ec9 L\u1ed9","M\u1ed9t \u0111\u1ed3i c\u1ecf th\u1ea5p nh\u01b0ng m\u1ed7i ng\u1ecdn l\u1ea1i t\u1ef1 xoay v\u1ec1 m\u1ed9t h\u01b0\u1edbng kh\xe1c nhau nh\u01b0 ch\u1ec9 v\xf4 s\u1ed1 con \u0111\u01b0\u1eddng tr\xf9ng l\u1eb7p. Tr\xean \u0111\u1ec9nh \u0111\u1ed3i l\xe0 tinh linh nh\u1ecf b\u1eb1ng b\xe0n tay, \u0111\xf4i m\u1eaft s\xe1ng ng\u1eddi nh\u01b0 v\u1eeba ch\u1ee9a s\u1ee3 h\xe3i v\u1eeba ch\u1ee9a thi\xean c\u01a1.","Ti\u1ec3u linh n\xe0y t\u1eebng d\u1eabn v\xf4 s\u1ed1 \u0111\xe0n th\xfa ch\u1ecdn \u0111\xfang m\u1ed9t l\u1ed1i s\u1ed1ng gi\u1eefa h\xe0ng tr\u0103m ng\xe3 ch\u1ebft. N\xf3 gi\u1eef \u0111\u1ed3i d\u1ef1 ng\xf4n kh\xf4ng v\xec ki\xeau h\xe3nh, m\xe0 v\xec v\u1eabn \xe1m \u1ea3nh b\u1edfi \u0111\xfang m\u1ed9t l\u1ea7n ch\u1ec9 sai khi\u1ebfn c\u1ea3 m\u1ed9t gi\u1ed1ng chim tr\u1eddi tuy\u1ec7t ch\u1ee7ng ngay tr\u01b0\u1edbc b\xecnh minh.")
B.afG=new A.c0("M\u1ea3 H\u1ed3 Ti\xean","C\u1eedu V\u0129 M\u1ed9c \u1ea2nh","Gi\u1eefa nh\u1eefng g\u1ed1c c\xe2y nghi\xeang l\xe0 ch\xedn \u0111u\xf4i l\xe1 x\xf2e ra nh\u01b0 qu\u1ea1t tang, c\xf2n th\xe2n h\u1ed3 ti\xean \u0111\xe3 h\xf3a th\xe0nh b\xf3ng m\u1edd trong th\xe2n g\u1ed7. \xc1nh nh\xecn c\u1ee7a n\xf3 v\u1eeba quy\u1ebfn r\u0169 v\u1eeba bu\u1ed3n nh\u01b0 \u0111\xe3 h\u1ecdc \u0111\u1ee7 c\xe1ch gi\u1eef ng\u01b0\u1eddi m\xe0 kh\xf4ng gi\u1eef n\u1ed5i k\u1ebb m\xecnh ch\u1edd.","H\u1ed3 ti\xean n\xe0y t\u1eebng d\u1eabn d\u1ee5 th\u1ee3 s\u0103n \u0111i l\u1ea1c \u0111\u1ec3 c\u1ee9u b\u1ea7y linh th\xfa non, nh\u01b0ng c\u0169ng v\xec th\u1ebf m\xe0 mang ti\u1ebfng t\xe0 d\u1ecb su\u1ed1t h\xe0ng th\u1ebf k\u1ef7. Sau khi nh\u1eefng k\u1ebb cu\u1ed1i c\xf9ng c\u1ea7n n\xe0ng c\u1ee9u \u0111\u1ec1u ch\u1ebft gi\xe0, n\xe0ng \u1edf l\u1ea1i gi\u1eefa m\u1ea3 c\xe2y nh\u01b0 m\u1ed9t oan s\u1eed kh\xf4ng c\xf2n ai minh x\xe9t.")
B.afd=new A.c0("Mi\u1ec7ng H\u1ed1 C\xe2y \u0102n Sao","Tinh Th\u1ef1c C\u1ed5 \u0110\u1eb1ng","D\u01b0\u1edbi h\u1ed1 s\xe2u l\xe0 m\u1ed9t c\xe2y d\xe2y leo kh\u1ed5ng l\u1ed3 \u0111ang m\u1edf n\u1ee5 nh\u01b0 m\u1ed9t c\xe1i mi\u1ec7ng nh\xecn l\xean tr\u1eddi. Quanh m\xe9p h\u1ed1 r\u01a1i \u0111\u1ea7y nh\u1eefng m\u1ea3nh kho\xe1ng s\xe1ng nh\u01b0 v\u1ea3y sao b\u1ecb nhai d\u1edf.","C\u1ed5 \u0111\u1eb1ng n\xe0y t\u1eebng nu\u1ed1t c\xe1c thi\xean th\u1ea1ch mang \u0111\u1ed9c m\u1ed9c r\u01a1i xu\u1ed1ng r\u1eebng, t\u1ef1 bi\u1ebfn m\xecnh th\xe0nh k\u1ebb b\u1ecb hi\u1ec3u l\u1ea7m l\xe0 qu\xe1i v\u1eadt \u0103n tr\u1eddi. N\xf3 canh mi\u1ec7ng h\u1ed1 v\xec bi\u1ebft ch\u1ec9 c\u1ea7n th\xeam m\u1ed9t m\u1ea3nh sao \u0111\u1ed9c l\u1ecdt qua, c\u1ea3 T\u1ecbch L\xe2m s\u1ebd m\u1ecdc l\xean m\u1ed9t l\u1ea7n tuy\u1ec7t di\u1ec7t kh\xe1c.")
B.afE=new A.c0("Th\u1ec1m H\u01b0\u01a1u C\u1ed5","Linh C\u1eefu M\u1eabu L\u1ed9c","M\u1ed9t \u0111\xe0n h\u01b0\u01a1u g\u1ed7 \u0111\u1ee9ng b\u1ea5t \u0111\u1ed9ng quanh b\u1eadc th\u1ec1m r\xeau ph\u1ee7, c\xfai \u0111\u1ea7u nh\u01b0 ch\u1ecbu tang. \u1ede ch\xednh gi\u1eefa l\xe0 linh l\u1ed9c c\xe1i gi\xe0 nua, tr\xean l\u01b0ng mang v\xf4 s\u1ed1 v\xf2ng d\xe2y th\u1ea3o d\u01b0\u1ee3c \u0111\xe3 kh\xf4 c\u1ee9ng t\u1eeb l\xe2u.","N\xe0ng t\u1eebng tha thu\u1ed1c t\u1edbi t\u1eebng \u1ed5 linh th\xfa b\u1ec7nh khi d\u1ecbch th\u1ed1i tr\xe0n qua r\u1eebng s\xe2u. \u0110\u1ebfn khi ch\xednh m\xecnh kh\xf4ng c\u1ee9u n\u1ed5i \u0111\xe0n con, n\xe0ng h\xf3a \u0111\xe1 t\u1ea1i th\u1ec1m n\xe0y \u0111\u1ec3 vi\u1ec7c ch\u0103m s\xf3c kh\xf4ng b\u1ecb l\u1ecbch s\u1eed khu r\u1eebng qu\xean th\xe0nh m\u1ed9t c\xf4ng vi\u1ec7c nh\u1ecf nhoi.")
B.afm=new A.c0("B\u1eadc Th\u1ec1m M\u1ed9c Kh\u1ea3i","Kh\u1ea3i M\u1ed9c Th\u1ee7 \u1ea4n","Nh\u1eefng phi\u1ebfn g\u1ed7 kh\u1eafc ph\xf9 v\u0103n x\u1ebfp th\xe0nh b\u1eadc nh\u01b0 l\u1ed1i v\xe0o m\u1ed9t \u0111i\u1ec7n ph\u1ee7 \u0111\xe3 b\u1ecb c\xe2y nu\u1ed1t m\u1ea5t. Tr\xean b\u1eadc cao nh\u1ea5t l\xe0 m\u1ed9c t\u01b0\u1edbng m\u1eb7c gi\xe1p v\u1ecf c\xe2y, m\u1ed9t tay gi\u1eef \u1ea5n, m\u1ed9t tay gi\u1eef l\u1ea5y ch\xednh v\u1ebft n\u1ee9t \u0111ang s\xe1ng d\u01b0\u1edbi ch\xe2n.","Kh\u1ea3i M\u1ed9c t\u1eebng ch\u1ec9 huy h\xe0ng r\xe0o s\u1ed1ng phong k\xedn c\u01a1n d\u1ecbch \u0103n linh tr\xed \u1edf ph\xeda b\u1eafc. H\u1eafn \u0111\u1ee9ng l\u1ea1i tr\xean b\u1eadc th\u1ec1m \u0111\u1ebfn h\xf3a c\u1ee9ng, bi\u1ebfn b\u1ea3n th\xe2n th\xe0nh \u1ea5n cu\u1ed1i c\xf9ng \u0111\xf3ng v\xe0o \u0111\u01b0\u1eddng n\u1ee9t gi\u1eefa l\xfd tr\xed v\xe0 cu\u1ed3ng h\xf3a.")
B.aft=new A.c0("B\u1ea3n Doanh C\xe0nh G\xe3y","Th\u1ee5 Binh V\xf4 Danh","H\xe0ng lo\u1ea1t th\xe2n c\xe2y c\u1ee5t c\xe0nh x\u1ebfp th\xe0nh \u0111\u1ed9i h\xecnh nh\u01b0 qu\xe2n s\u0129 ch\u1ebft \u0111\u1ee9ng, ph\xeda tr\u01b0\u1edbc l\xe0 th\u1ee5 binh mang g\u01b0\u01a1ng m\u1eb7t kh\xf4ng kh\u1eafc r\xf5 n\xe9t n\xe0o. Gi\xf3 th\u1ed5i qua \u0111\u1ed9i h\xecnh \u1ea5y kh\xf4ng nghe nh\u01b0 l\xe1, m\xe0 nh\u01b0 nh\u1eefng h\u01a1i th\u1edf t\u1eadp th\u1ec3 \u0111\xe3 b\u1ecb c\u1eaft ngang.","\u0110\xe1m th\u1ee5 binh n\xe0y \u0111\u01b0\u1ee3c sinh ra \u0111\u1ec3 ch\u1eafn \u0111\u01b0\u1eddng x\xe2m nh\u1eadp v\xe0o l\xf5i r\u1eebng v\xe0 ch\u01b0a t\u1eebng c\xf3 t\xean ri\xeang. V\u1ecb ch\u1ec9 huy v\xf4 danh c\u1ee7a ch\xfang \u1edf l\u1ea1i \u0111\xe2y \u0111\u1ec3 nh\u1eafc r\u1eb1ng nh\u1eefng k\u1ebb b\u1ea3o v\u1ec7 \u0111\u1ea7u ti\xean c\u1ee7a m\u1ed9t th\u1ebf gi\u1edbi th\u01b0\u1eddng l\xe0 nh\u1eefng k\u1ebb ch\u1eb3ng bao gi\u1edd \u0111\u01b0\u1ee3c ghi c\xf4ng.")
B.afA=new A.c0("Gi\u1ebfng S\u01b0\u01a1ng C\xe2y M\u01a1","M\u1ed9ng M\u1ed9c T\u01b0\u1edbi H\u1ed3n","Gi\u1ebfng s\xe2u kh\xf4ng c\xf3 n\u01b0\u1edbc m\xe0 \u0111\u1ea7y s\u01b0\u01a1ng, tr\xean mi\u1ec7ng gi\u1ebfng m\u1ecdc m\u1ed9t c\xe2y m\u01a1 n\u1edf tr\xe1i m\xf9a quanh n\u0103m. M\u1ed9t b\xf3ng ng\u01b0\u1eddi m\u1ea3nh nh\u01b0 kh\xf3i ng\u1ed3i t\u1ef1a g\u1ed1c, m\u1eaft lim dim nh\u01b0 canh gi\u1eef gi\u1ea5c m\u01a1 cho c\u1ea3 khu r\u1eebng.","M\u1ed9ng M\u1ed9c k\xe9o nh\u1eefng c\u01a1n \xe1c m\u1ed9ng ra kh\u1ecfi b\u1ea7y th\xfa sau m\u1ed7i \u0111\u1ee3t th\u1ea3m s\xe1t b\u1eb1ng c\xe1ch gi\u1ea5u ch\xfang d\u01b0\u1edbi gi\u1ebfng s\u01b0\u01a1ng c\u1ee7a m\xecnh. Nh\u1eefng qu\u1ea3 m\u01a1 tr\xe1i m\xf9a l\xe0 k\u1ebft tinh t\u1eeb s\u1ee3 h\xe3i \u0111\xe3 \u0111\u01b0\u1ee3c l\u1ecdc s\u1ea1ch, th\u1ee9 ng\u1ecdt hi\u1ebfm hoi l\u1edbn l\xean t\u1eeb r\u1ea5t nhi\u1ec1u \u0111\xeam kh\xf4ng ng\u1ee7.")
B.afU=new A.c0("B\u1edd \u0110\xe1 C\u1ed5 Tham","Tham M\u1ed9c Nu\u1ed1t \u0110\u1ed9c","B\xean b\u1edd \u0111\xe1 m\u1ecdc m\u1ed9t th\xe2n c\xe2y d\u1ecb d\u1ea1ng, r\u1ec5 to nh\u01b0 r\u1eafn qu\u1ea5n l\u1ea5y v\xf4 s\u1ed1 h\xf2n \u0111\xe1 \u0111en b\u1ecb \u0103n m\xf2n. Gi\u1eefa \u0111\xe1m r\u1ec5 l\u1ea5p l\xf3 g\u01b0\u01a1ng m\u1eb7t c\u1ee7a m\u1ed9t sinh linh \u0111au \u0111\u1edbn t\u1edbi m\u1ee9c t\u1eebng h\u01a1i th\u1edf \u0111\u1ec1u l\xe0m l\xe1 xung quanh t\xe1i \u0111i.","C\xe2y n\xe0y tham kh\xf4ng ph\u1ea3i v\xec b\u1ea3n t\xednh, m\xe0 v\xec ph\u1ea3i h\xfat m\u1ecdi ch\u1ea5t \u0111\u1ed9c \u0111\u1ecba m\u1ea1ch v\xe0o ng\u01b0\u1eddi \u0111\u1ec3 gi\u1eef cho ph\u1ea7n c\xf2n l\u1ea1i c\u1ee7a T\u1ecbch L\xe2m c\xf2n xanh. N\xf3 b\u1ecb gh\xe9t v\xe0 b\u1ecb s\u1ee3 nh\u01b0 m\u1ed9t th\u1ee9 \xf4 u\u1ebf, nh\u01b0ng ch\xednh nh\u1eefng k\u1ebb b\u1ecb xem l\xe0 b\u1ea9n \u0111\u1ee5c \u1ea5y l\u1ea1i \u0111ang gi\u1eef ph\u1ea7n trong l\xe0nh cho t\u1ea5t c\u1ea3.")
B.afp=new A.c0("B\xe3i C\xe1nh Ti\xean T\xe0n","Ti\xean Linh G\xe3y C\xe1nh","B\xe3i c\u1ecf ph\u1ee7 \u0111\u1ea7y nh\u1eefng m\u1ea3nh c\xe1nh m\u1ecfng trong su\u1ed1t nh\u01b0 c\xe1nh ve, nh\u01b0ng m\u1ed7i m\u1ea3nh \u0111\u1ec1u ph\xe1t \xe1nh s\xe1ng d\u1ecbu. Tr\xean phi\u1ebfn \u0111\xe1 gi\u1eefa b\xe3i l\xe0 m\u1ed9t ti\xean linh kh\xf4ng c\xf2n c\xe1nh, vai sau l\u01b0ng tr\u01a1 ra nh\u01b0 hai v\u1ebft th\u01b0\u01a1ng \u0111\xe3 kh\xf4.","N\xe0ng \u0111\xe3 x\xe9 c\xe1nh m\xecnh d\u1ec7t th\xe0nh m\xe0n che cho m\u1ed9t l\u1ee9a tinh linh nh\u1ecf tr\u1ed1n kh\u1ecfi b\xe3o linh \xe1p. Nh\u1eefng m\u1ea3nh c\xe1nh c\xf2n l\u1ea1i bay quanh \u0111\xe2y kh\xf4ng ph\u1ea3i t\xe0n t\xedch th\u1ea5t b\u1ea1i, m\xe0 l\xe0 m\u1ed9t v\xf2ng h\u1ed9 ph\xe1p d\u1ecbu d\xe0ng \u0111\u01b0\u1ee3c gi\u1eef b\u1eb1ng th\xe2n x\xe1c \u0111\xe3 m\u1ea5t c\u1ee7a ch\xednh n\xe0ng.")
B.afJ=new A.c0("Th\u1ec1m H\u1ea1t Gi\xf3","Phong M\u1ed9c D\u01b0 \xc2m","M\u1ed7i vi\xean s\u1ecfi \u1edf b\u1eadc th\u1ec1m \u0111\u1ec1u n\u1ee9t ra m\u1ed9t m\u1ea7m c\u1ecf nh\u1ecf nghi\xeang c\xf9ng m\u1ed9t h\u01b0\u1edbng gi\xf3. Tr\xean lan can r\xeau \u0111\u1ee9ng m\u1ed9t sinh v\u1eadt l\xf4ng m\u1ecbn nh\u01b0 s\xf3c bay, \u0111\xf4i tai d\xe0i rung l\xean theo nh\u1eefng ti\u1ebfng v\u1ecdng m\xe0 ta kh\xf4ng nghe th\u1ea5y.","N\xf3 l\xe0 k\u1ebb nghe tin d\u1eef s\u1edbm nh\u1ea5t c\u1ee7a T\u1ecbch L\xe2m, t\u1eebng truy\u1ec1n b\xe1o \u0111\u1ed9ng cho to\xe0n v\xf9ng tr\u01b0\u1edbc khi c\xe1c \u0111\u1ee3t s\u0103n l\u1edbn \u1eadp t\u1edbi. \u0110\u1ebfn nay v\u1eabn canh b\u1eadc th\u1ec1m n\xe0y v\xec n\u1ebfu n\xf3 ng\u1eebng l\u1eafng nghe, khu r\u1eebng s\u1ebd th\u1eadt s\u1ef1 tr\u1edf th\xe0nh m\u1ed9t n\u01a1i kh\xf4ng c\xf2n ai tr\u1ea3 l\u1eddi ti\u1ebfng gi\xf3 n\u1eefa.")
B.afa=new A.c0("C\u1ed3n S\xe2m V\u01b0\u01a1ng","S\xe2m Ch\u1ee7 Th\u1ee7 C\u1ed1t","D\u01b0\u1edbi c\u1ed3n \u0111\u1ea5t m\u1ecdc ra h\xe0ng tr\u0103m b\u1ed9 r\u1ec5 h\xecnh ng\u01b0\u1eddi nh\u01b0 nh\u1eefng c\xe1nh tay mu\u1ed1n b\xf2 l\xean m\u1eb7t \u0111\u1ea5t. Ch\xednh gi\u1eefa l\xe0 c\u1ee7 s\xe2m kh\u1ed5ng l\u1ed3 mang n\xe9t m\u1eb7t l\xe3o gi\u1ea3, tr\xean \u0111\u1ec9nh \u0111\u1ea7u n\u1edf m\u1ed9t v\xf2ng hoa \u0111\u1ecf nh\u01b0 v\u01b0\u01a1ng mi\u1ec7n tang.","S\xe2m ch\u1ee7 d\xf9ng th\xe2n m\xecnh h\u1ea5p thu tinh c\u1ed1t c\u1ee7a linh th\xfa ch\u1ebft \u0111\u1ec3 \u0111\u1ea5t kh\xf4ng tr\u1edf n\xean c\u1eb1n ch\u1ebft. Nh\u1eefng b\u1ed9 r\u1ec5 h\xecnh ng\u01b0\u1eddi kh\xf4ng ph\u1ea3i t\xe0 d\u1ecb, m\xe0 l\xe0 h\xecnh d\u1ea1ng c\u1ee7a m\u1ed9t ngh\u0129a \u0111\u1ecba \u0111\xe3 \u0111\u01b0\u1ee3c khu r\u1eebng \xf4m l\u1ea1i v\xe0 nu\xf4i th\xe0nh s\u1ef1 s\u1ed1ng m\u1edbi.")
B.afi=new A.c0("\u0110\u1ec1n C\xe0nh Ng\xe0n M\u1eaft","Thi\xean M\u1ee5c M\u1ed9c Th\u1ea7n","M\u1ed7i c\xe0nh c\xe2y quanh ng\xf4i \u0111\u1ec1n \u0111\u1ec1u m\u1ecdc m\u1ed9t con m\u1eaft b\u1eb1ng nh\u1ef1a trong, ch\u1edbp m\u1edf r\u1ea5t ch\u1eadm. Tr\xean n\u1ec1n \u0111\u1ec1n l\xe0 m\u1ed9c th\u1ea7n th\xe2n cao g\u1ea7y, to\xe0n th\xe2n chi ch\xedt nh\u1eefng v\u1ec7t nh\u1ef1a ch\u1ea3y nh\u01b0 t\u1eebng gi\u1ecdt n\u01b0\u1edbc m\u1eaft \u0111\xe3 h\xf3a th\xe0nh c\u01a1 quan quan s\xe1t.","Thi\xean M\u1ee5c ch\u1ea5p nh\u1eadn m\u1ecdc th\xeam m\u1eaft \u0111\u1ec3 canh m\u1ecdi ng\u1ea3 \u0111\u01b0\u1eddng sau khi m\u1ed9t l\u1ea7n ng\u1ee7 qu\xean khi\u1ebfn c\u1ea3 \u0111\xe0n ti\u1ec3u linh b\u1ecb b\u1eaft. T\u1eeb \u0111\xf3, n\xf3 kh\xf4ng c\xf2n \u0111\u01b0\u1ee3c ph\xe9p kh\xe9p h\u1ebft m\u1eaft th\xeam l\u1ea7n n\xe0o n\u1eefa, tr\u1edf th\xe0nh hi\u1ec7n th\xe2n c\u1ee7a s\u1ef1 c\u1ea3nh gi\xe1c \u0111\u01b0\u1ee3c kh\u1eafc s\xe2u t\u1edbi m\u1ee9c t\xe0n nh\u1eabn.")
B.afM=new A.c0("M\u1ecfm C\xe2y Treo Tr\u0103ng","Nguy\u1ec7t M\u1ed9c G\u1ecdi \u0110\xeam","M\u1ed9t m\u1ecfm n\xfai m\u1ecdc ra duy nh\u1ea5t m\u1ed9t th\xe2n c\xe2y tr\u1eafng, t\xe1n l\xe1 gi\u1eef nguy\xean \xe1nh b\u1ea1c nh\u01b0 \u0111ang treo c\u1ea3 m\u1ea3nh tr\u0103ng th\u1ea5p xu\u1ed1ng. D\u01b0\u1edbi g\u1ed1c c\xe2y l\xe0 linh n\u1eef m\u1ed9c b\u1ea1ch g\u1ea7n nh\u01b0 trong su\u1ed1t, n\xe9t m\u1eb7t y\xean t\u1edbi m\u1ee9c bu\u1ed1t gi\xe1.","Nguy\u1ec7t M\u1ed9c d\xf9ng \xe1nh tr\u0103ng gi\u1ea3 n\xe0y ru ng\u1ee7 c\xe1c lo\xe0i ch\u1ec9 d\xe1m ra ngo\xe0i khi \u0111\xeam t\u1edbi, gi\xfap ch\xfang t\u1ed3n t\u1ea1i qua th\u1eddi \u0111\u1ea1i s\u0103n \u0111u\u1ed5i kh\u1ed1c li\u1ec7t. C\xe1i gi\xe1 l\xe0 ch\xednh n\xe0ng ph\u1ea3i th\u1ee9c su\u1ed1t m\u1ecdi \u0111\xeam, d\u1ea7n d\u1ea7n qu\xean m\u1ea5t \xe1nh s\xe1ng m\u1eb7t tr\u1eddi \u0111\xe3 tr\xf4ng ra sao.")
B.afF=new A.c0("Ng\xe3 Ba H\u1ea1t M\xe1u","X\xedch Hoa M\u1ed9 Th\xfa","Ba l\u1ed1i \u0111\u01b0\u1eddng g\u1eb7p nhau t\u1ea1i m\u1ed9t b\u1ee5i hoa \u0111\u1ecf th\u1eabm nh\u01b0 c\xf2n t\u01b0\u01a1i b\u1eb1ng m\xe1u n\xf3ng. Trong b\u1ee5i hoa l\xe0 m\u1ed9t linh th\u1ec3 nh\u1ecf b\xe9, tay \xf4m t\u1eebng chi\u1ebfc r\u0103ng nanh v\xe0 m\xf3ng vu\u1ed1t nh\u01b0 \u0111\u1ed3 ch\xf4n c\u1ea5t c\u1ee7a nh\u1eefng th\xfa d\u1eef t\u1eebng ng\xe3 xu\u1ed1ng.","X\xedch Hoa m\u1ecdc l\xean t\u1eeb m\xe1u c\u1ee7a nh\u1eefng linh th\xfa chi\u1ebfn \u0111\u1ea5u \u0111\u1ec3 \u0111\xe0n non ch\u1ea1y tho\xe1t. N\xf3 gom r\u0103ng vu\u1ed1t ch\xfang l\u1ea1i v\xec bi\u1ebft b\u1ea3n n\u0103ng d\u1eef d\u1ed9i \u1ea5y c\u0169ng x\u1ee9ng \u0111\xe1ng \u0111\u01b0\u1ee3c t\u01b0\u1edfng nh\u1edb nh\u01b0 b\u1ea5t k\u1ef3 l\xf2ng d\u1ecbu hi\u1ec1n n\xe0o kh\xe1c trong khu r\u1eebng.")
B.aff=new A.c0("L\u01b0ng \u0110\u1ed3i M\u1ed9c Th\u1ea7n","Gi\xe0 Thi\xean T\xe0ng Ph\xe1ch","C\u1ea3 qu\u1ea3 \u0111\u1ed3i th\u1ef1c ra l\xe0 l\u01b0ng c\u1ee7a m\u1ed9t m\u1ed9c th\u1ea7n \u0111ang ng\u1ed3i, r\xeau ph\u1ee7 k\xedn t\u1edbi m\u1ee9c su\xfdt kh\xf4ng nh\u1eadn ra h\xecnh ng\u01b0\u1eddi. Khi ta b\u01b0\u1edbc t\u1edbi, l\u1edbp l\xe1 tr\xean vai n\xf3 run l\xean nh\u01b0 m\u1ed9t sinh v\u1eadt qu\xe1 l\u1edbn v\u1eeba th\u1ee9c d\u1eady sau gi\u1ea5c ng\u1ee7 k\xe9o d\xe0i nhi\u1ec1u tri\u1ec1u \u0111\u1ea1i.","Gi\xe0 Thi\xean l\xe0 m\u1ed9t trong nh\u1eefng ch\u1ee7 linh \u0111\u1ea7u ti\xean k\xfd kh\u1ebf \u01b0\u1edbc cho con ng\u01b0\u1eddi tr\xfa ch\xe2n \u1edf T\u1ecbch L\xe2m. Sau khi ch\u1ee9ng ki\u1ebfn m\u1ecdi l\u1eddi h\u1ee9a chung s\u1ed1ng \u0111\u1ed5 v\u1ee1, n\xf3 t\u1ef1 bi\u1ebfn th\xe2n m\xecnh th\xe0nh qu\u1ea3 \u0111\u1ed3i canh ph\u1ea7n r\u1eebng c\xf2n l\u1ea1i, \u0111\u1ec3 \xedt nh\u1ea5t l\xf2ng tin c\u0169 kh\xf4ng bi\u1ebfn m\u1ea5t ho\xe0n to\xe0n kh\u1ecfi m\u1eb7t \u0111\u1ea5t.")
B.afh=new A.c0("N\xf4i M\u1ea7m C\u1eedu Di\u1ec7p","C\u1eedu Di\u1ec7p M\u1eabu Th\u1ea7n","Ch\xedn chi\u1ebfc l\xe1 kh\u1ed5ng l\u1ed3 x\xf2e ra th\xe0nh chi\u1ebfc n\xf4i \xf4m l\u1ea5y t\xe2m l\xe2m \u0111\u1ecba, m\u1ed7i l\xe1 mang m\u1ed9t m\xe0u l\u1ee5c kh\xe1c nhau. N\u1eb1m gi\u1eefa n\xf4i l\xe1 l\xe0 m\u1eabu th\u1ea7n c\xf3 g\u01b0\u01a1ng m\u1eb7t hi\u1ec1n h\xf2a nh\u01b0ng kh\xed t\u1ee9c n\u1eb7ng nh\u01b0 c\u1ea3 v\xf9ng \u0111\u1ea5t \u0111ang th\u1edf qua ng\u01b0\u1eddi n\xe0ng.","C\u1eedu Di\u1ec7p gi\u1eef ngu\u1ed3n m\u1ea7m g\u1ed1c c\u1ee7a T\u1ecbch L\xe2m, n\u01a1i m\u1ecdi gi\u1ed1ng c\xe2y v\xe0 nhi\u1ec1u ti\xean linh t\u1eebng \u0111\u01b0\u1ee3c sinh ra l\u1ea7n \u0111\u1ea7u. N\xe0ng kh\xf4ng r\u1eddi n\xf4i m\u1ea7m v\xec hi\u1ec3u ch\u1ec9 c\u1ea7n n\u01a1i n\xe0y ng\u1eebng \u0111\u1eadp m\u1ed9t nh\u1ecbp, to\xe0n b\u1ed9 khu r\u1eebng s\u1ebd d\u1ea7n s\u1ed1ng nh\u01b0 c\xe1i x\xe1c bi\u1ebft m\u1ecdc l\xe1 m\xe0 th\xf4i.")
B.afw=new A.c0("\u0110\xe0i Linh Chi V\u01b0\u01a1ng","Chi V\u01b0\u01a1ng T\u1eed Sinh","Nh\u1eefng t\u1ea7ng linh chi l\u1edbn l\xean nh\u01b0 m\xe1i \u0111i\u1ec7n ch\u1ed3ng ch\u1ea5t quanh m\u1ed9t \u0111\xe0i \u0111\u1ea5t \u0111\u1ecf. Tr\xean \u0111\u1ec9nh \u0111\xe0i l\xe0 v\u1ecb v\u01b0\u01a1ng gi\u1ea3 mang m\u0169 t\xe1n n\u1ea5m, \xe1nh m\u1eaft l\u1ea1nh m\xe0 m\u1ec7t nh\u01b0 ng\u01b0\u1eddi \u0111\xe3 cai qu\u1ea3n qu\xe1 nhi\u1ec1u chu k\u1ef3 m\u1ee5c v\xe0 m\u1ecdc.","Chi V\u01b0\u01a1ng hi\u1ec3u nh\u1ea5t r\u1eb1ng \u0111\u1ec3 khu r\u1eebng s\u1ed1ng th\xec c\u0169ng ph\u1ea3i c\xf3 th\u1ee9 m\u1ee5c \u0111i, n\xean h\u1eafn cai tr\u1ecb t\u1ea7ng ph\xe2n h\u1ee7y c\u1ee7a T\u1ecbch L\xe2m b\u1eb1ng k\u1ef7 lu\u1eadt g\u1ea7n nh\u01b0 t\xe0n nh\u1eabn. S\u1ef1 \u0111\xe1ng s\u1ee3 c\u1ee7a h\u1eafn l\xe0 chi\u1ebfc van c\xe2n b\u1eb1ng cho m\u1ed9t th\u1ebf gi\u1edbi ch\u1ec9 c\u1ea7n nghi\xeang qu\xe1 sang th\u01b0\u01a1ng ti\u1ebfc l\xe0 s\u1ebd ng\u1eebng t\xe1i sinh.")
B.afN=new A.c0("L\xf2ng Ch\u1ea3o V\u1ecf C\u0169","M\xe3ng Linh L\u1ed9t X\xe1c","C\u1ea3 l\xf2ng ch\u1ea3o ph\u1ee7 \u0111\u1ea7y nh\u1eefng l\u1edbp da r\u1eafn kh\u1ed5ng l\u1ed3 trong su\u1ed1t nh\u01b0 t\u1ea5m m\xe0n b\u1ecf \u0111i c\u1ee7a nhi\u1ec1u ki\u1ebfp s\u1ed1ng. \u1ede gi\u1eefa qu\u1ea5n m\xecnh quanh th\xe2n c\xe2y ch\u1ebft l\xe0 m\u1ed9t c\u1ef1 m\xe3ng xanh l\u1ee5c, \u0111\xf4i m\u1eaft n\xf3 t\u1ec9nh t\xe1o t\u1edbi m\u1ee9c khi\u1ebfn kh\xf4ng kh\xed quanh \u0111\xe2y nh\u01b0 b\u1ecb si\u1ebft l\u1ea1i.","M\xe3ng linh \u0111\u1ed5i x\xe1c kh\xf4ng \u0111\u1ec3 m\u1ea1nh h\u01a1n, m\xe0 \u0111\u1ec3 k\xe9o ch\u1ea5t nguy\u1ec1n kh\u1ecfi m\xe1u v\xe0 ch\xf4n n\xf3 v\xe0o t\u1eebng l\u1edbp da b\u1ecf l\u1ea1i. N\xf3 \u1edf \u0111\xe2y canh l\xf2ng ch\u1ea3o v\xec hi\u1ec3u n\u1ebfu ai v\xf4 t\xecnh ch\u1ea1m v\xe0o nh\u1eefng l\u1edbp da kia, m\u1ecdi \u0111\u1ed9c ch\xfa c\u1ee7a nhi\u1ec1u th\u1ebf k\u1ef7 s\u1ebd th\u1ee9c d\u1eady trong c\xf9ng m\u1ed9t l\xfac.")
B.afP=new A.c0("\u0110\u1ec9nh Ph\u1ea5n Thi\xean","Thi\xean Ph\u1ea5n C\u1ed5 \u0110i\u1ec7p","Kh\xf4ng kh\xed tr\xean \u0111\u1ec9nh n\xfai \u0111\u1eb7c m\u1edd b\u1edfi l\u1edbp ph\u1ea5n s\xe1ng c\u1ee9 r\u01a1i m\xe3i nh\u01b0 tuy\u1ebft xanh. Trong m\xe0n ph\u1ea5n kh\u1ed5ng l\u1ed3 \u1ea5y l\xe0 m\u1ed9t c\u1ed5 \u0111i\u1ec7p v\u1edbi th\xe2n h\xecnh g\u1ea7n nh\u01b0 th\u1ea7n th\xe1nh, v\u1ed7 c\xe1nh r\u1ea5t ch\u1eadm nh\u01b0 \u0111i\u1ec1u khi\u1ec3n nh\u1ecbp th\u1edf c\u1ee7a c\u1ea3 ng\u1ecdn n\xfai.","C\u1ed5 \u0111i\u1ec7p n\xe0y ph\xe1t t\xe1n ph\u1ea5n \u0111\u1ec3 ch\u1eefa nh\u1eefng v\xf9ng c\xe2y b\u1ecb kh\xf4 linh m\u1ea1ch sau chi\u1ebfn lo\u1ea1n, nh\u01b0ng ph\u1ea5n c\u1ee7a n\xf3 qu\xe1 m\u1ea1nh n\xean ch\u1ec9 c\xf3 th\u1ec3 d\xf9ng \u1edf n\u01a1i kh\xf4ng c\xf2n ng\u01b0\u1eddi s\u1ed1ng. Ng\u1ecdn n\xfai \u0111\u1eb9p \u0111\u1ebfn huy\u1ec5n ho\u1eb7c n\xe0y v\xec th\u1ebf c\u0169ng l\xe0 m\u1ed9t ph\xf2ng tr\u1ecb th\u01b0\u01a1ng kh\u1ed5ng l\u1ed3 m\xe0 ch\u1ec9 sinh v\u1eadt huy\u1ec1n b\xed m\u1edbi ch\u1ecbu n\u1ed5i.")
B.afr=new A.c0("T\xe2m L\xe2m M\u1ed9c T\u1ed5","M\u1ed9c T\u1ed5 V\u1ea1n Linh","Cu\u1ed1i c\xf9ng ta \u0111\u1ee9ng tr\u01b0\u1edbc l\xf5i r\u1eebng: m\u1ed9t g\u1ed1c c\xe2y l\u1edbn t\u1edbi m\u1ee9c c\u1ea3 tr\u1eddi \u0111\u1ea5t nh\u01b0 m\u1ecdc t\u1eeb \u0111\xf3 ra, chung quanh treo \u0111\u1ea7y x\u01b0\u01a1ng th\xfa th\u1ea7n, k\xe9n ti\xean linh v\xe0 bia g\u1ed7 kh\xf4ng ch\u1eef. T\u1eeb th\xe2n c\xe2y hi\u1ec7n ra d\xe1ng v\u1ecb t\u1ed5 linh gi\xe0 nua, \xe1nh m\u1eaft ch\u1ea5t \u0111\u1ee7 th\u01b0\u01a1ng y\xeau, m\u1ec7t m\u1ecfi v\xe0 c\u1ea3nh gi\xe1c c\u1ee7a m\u1ed9t th\u1ebf gi\u1edbi \u0111\xe3 t\u1ef1 nh\u1ed1t m\xecnh qu\xe1 l\xe2u.","M\u1ed9c T\u1ed5 l\xe0 k\u1ebb \u0111\xe3 thu nh\u1eadn nh\u1eefng gi\u1ed1ng lo\xe0i ch\u1ea1y kh\u1ecfi c\xe1c th\u1eddi \u0111\u1ea1i di\u1ec7t s\u1ea1ch v\xe0 bi\u1ebfn T\u1ecbch L\xe2m th\xe0nh n\u01a1i tr\xfa \u1ea9n cu\u1ed1i c\xf9ng kh\xf4ng cho con ng\u01b0\u1eddi b\u01b0\u1edbc s\xe2u th\xeam n\u1eefa. L\xe3o gi\u1eef m\u1ecdi x\u01b0\u01a1ng c\u1ed1t, linh h\u1ed3n v\xe0 h\u1ea1t gi\u1ed1ng quanh m\xecnh \u0111\u1ec3 b\u1ea3o t\u1ed3n k\xfd \u1ee9c c\u1ee7a m\u1ed9t th\u1ebf gi\u1edbi huy\u1ec1n b\xed \u0111ang t\xe0n \u0111i, v\xe0 sau tr\u1eadn n\xe0y ta hi\u1ec3u con \u0111\u01b0\u1eddng k\u1ebf ti\u1ebfp kh\xf4ng ch\u1ec9 l\xe0 ph\xe1 phong \u1ea5n, m\xe0 c\xf2n ph\u1ea3i tr\u1ea3 l\u1eddi xem li\u1ec7u nh\xe2n th\u1ebf c\xf2n x\u1ee9ng \u0111\u1ec3 nh\u1eefng c\xe1nh c\u1eeda cu\u1ed1i c\xf9ng m\u1edf ra hay kh\xf4ng.")
