B.aqy=new A.aO("Vi\xeam T\xe2m C\u1ed1c \u0111\u1ecf r\u1ef1c nh\u01b0 m\u1ed9t tr\xe1i tim b\u1ecb moi ra kh\u1ecfi l\u1ed3ng ng\u1ef1c \u0111\u1ea5t tr\u1eddi, v\u1eabn c\xf2n \u0111ang co gi\u1eadt trong l\u1eeda.","Ng\u01b0\u1eddi canh c\u1ed1c t\u1eebng l\xe0 m\u1ed9t l\xf2 luy\u1ec7n s\u1ed1ng, nh\u1ed1t tu s\u0129 sa c\u01a1 l\xe0m c\u1ee7i cho tham v\u1ecdng c\u1ee7a k\u1ebb m\u1ea1nh. Tro c\u0169 kh\xf4ng bi\u1ebft n\xf3i, nh\u01b0ng t\u1eebng v\u1ebft ch\xe1y tr\xean v\xe1ch \u0111\xe1 \u0111\u1ec1u gi\u1eef l\u1ea1i t\xean c\u1ee7a nh\u1eefng ng\u01b0\u1eddi \u0111\xe3 b\u1ecb thi\xeau th\xe0nh b\xed m\u1eadt. Khi ng\u1ecdn l\u1eeda l\u1ecbm \u0111i, b\xed c\u1ea3nh \u0111\u1ea7u ti\xean kh\xf4ng c\xf2n l\xe0 n\u01a1i th\u1eed gan, m\xe0 tr\u1edf th\xe0nh n\u01a1i c\xf3 ng\u01b0\u1eddi ch\u1ecbu \u0111\u1ee9ng l\u1ea1i \u0111\u1ec3 nh\u1edb.",null)
B.aqU=new A.aO("M\u1eb7t n\u01b0\u1edbc Cam L\u1ed9 H\u1ed3 ph\u1eb3ng l\u1eb7ng \u0111\u1ebfn \u0111\xe1ng s\u1ee3, nh\u01b0 th\u1ec3 m\u1ecdi ti\u1ebfng k\xeau c\u1ee9u t\u1eebng r\u01a1i xu\u1ed1ng \u0111\xe2y \u0111\u1ec1u \u0111\xe3 b\u1ecb nu\u1ed1t tr\u1ecdn.","D\u01b0\u1edbi l\u1edbp n\u01b0\u1edbc ng\u1ecdt l\xe0 nh\u1eefng kh\u1ebf \u01b0\u1edbc nhu\u1ed9m m\xe1u. K\u1ebb gi\u1eef h\u1ed3 t\u1eebng h\u1ee9a ban thu\u1ed1c c\u1ee9u m\u1ea1ng, \u0111\u1ed5i l\u1ea1i l\xe0 tu\u1ed5i tr\u1ebb, k\xfd \u1ee9c v\xe0 c\u1ea3 t\xean h\u1ecd c\u1ee7a ng\u01b0\u1eddi b\u1ec7nh. Bao ng\u01b0\u1eddi s\u1ed1ng s\xf3t r\u1eddi \u0111i nh\u01b0ng kh\xf4ng c\xf2n nh\u1edb m\xecnh l\xe0 ai; h\u1ed3 trong veo, c\xf2n \u0111\u1eddi h\u1ecd th\xec \u0111\u1ee5c m\xe3i. \u0110\xe1nh b\u1ea1i h\u1eafn kh\xf4ng tr\u1ea3 l\u1ea1i \u0111\u01b0\u1ee3c qu\xe1 kh\u1ee9, nh\u01b0ng \xedt nh\u1ea5t c\u0169ng ch\u1eb7n th\xeam m\u1ed9t th\u1ebf h\u1ec7 b\u1ecb x\xf3a kh\u1ecfi ch\xednh cu\u1ed9c \u0111\u1eddi m\xecnh.",null)
B.ari=new A.aO("M\u1ed9c H\u1ed3n Vi\u1ec7n ng\u1eadp m\xf9i l\xe1 m\u1ee5c, nh\u01b0 m\u1ed9t ngh\u0129a \u0111\u1ecba \u0111\u01b0\u1ee3c ng\u1ee5y trang th\xe0nh khu v\u01b0\u1eddn ch\u1eefa l\xe0nh.","Vi\u1ec7n ch\u1ee7 t\u1eebng gom nh\u1eefng ng\u01b0\u1eddi h\u1ea5p h\u1ed1i, cho h\u1ecd \u0103n d\u01b0\u1ee3c c\u1ecf r\u1ed3i bu\u1ed9c linh h\u1ed3n c\u1eafm r\u1ec5 v\xe0o th\xe2n c\xe2y \u0111\u1ec3 t\u1ea1o ra \u201clinh m\u1ed9c b\u1ea5t t\u1eed\u201d. K\u1ebb ngo\xe0i nh\xecn v\xe0o t\u01b0\u1edfng \u0111\xe2y l\xe0 ph\xfac \u0111\u1ecba c\u1ee9u ng\u01b0\u1eddi, n\xe0o ng\u1edd m\u1ed7i g\u1ed1c c\u1ed5 th\u1ee5 \u0111\u1ec1u l\xe0 m\u1ed9t n\u1ea5m m\u1ed3 \u0111\u1ee9ng th\u1eb3ng. Khi tr\u1eadn chi\u1ebfn k\u1ebft th\xfac, gi\xf3 th\u1ed5i qua t\xe0ng l\xe1 mang theo \xe2m thanh gi\u1ed1ng ti\u1ebfng th\u1edf ph\xe0o \u0111\u1ea7u ti\xean sau r\u1ea5t nhi\u1ec1u n\u0103m b\u1ecb giam trong g\u1ed7 th\u1ecbt.",null)
B.aqd=new A.aO("Nham Tinh Tr\u1ee5 d\u1ef1ng gi\u1eefa \u0111\u1ea5t hoang nh\u01b0 x\u01b0\u01a1ng s\u1ed1ng c\u1ee7a m\u1ed9t c\u1ef1 nh\xe2n \u0111\xe3 ch\u1ebft m\xe0 v\u1eabn kh\xf4ng ch\u1ecbu ng\xe3 xu\u1ed1ng.","K\u1ebb tr\u1ea5n gi\u1eef n\u01a1i n\xe0y t\u1eebng b\u1eaft phu m\u1ecf \u0111\xe0o s\xe2u \u0111\u1ebfn t\u1eadn huy\u1ebft m\u1ea1ch linh th\u1ea1ch, ai ki\u1ec7t s\u1ee9c th\xec b\u1ecb ch\xf4n s\u1ed1ng ngay d\u01b0\u1edbi c\u1ed9t \u0111\xe1 \u0111\u1ec3 \u201cl\xe0m n\u1ec1n m\xf3ng\u201d. B\xed c\u1ea3nh v\xec v\u1eady m\u1edbi \u0111\u1ee9ng v\u1eefng, v\xec n\xf3 \u0111\u01b0\u1ee3c d\u1ef1ng tr\xean l\u01b0ng c\u1ee7a nh\u1eefng ng\u01b0\u1eddi kh\xf4ng bao gi\u1edd c\xf3 c\u01a1 h\u1ed9i tr\u1edf v\u1ec1 nh\xe0. Khi c\u1ed9t tr\u1ee5 n\u1ee9t ra, ti\u1ebfng \u0111\xe1 \u0111\u1ed5 nghe kh\xf4ng gi\u1ed1ng th\u1ea5t b\u1ea1i c\u1ee7a m\u1ed9t boss, m\xe0 gi\u1ed1ng m\u1ed9t m\xf3n n\u1ee3 cu\u1ed1i c\xf9ng \u0111\xe3 b\u1eaft \u0111\u1ea7u ch\u1ecbu tr\u1ea3.",null)
B.arj=new A.aO("L\xf4i Ph\u1ea1t \u0110\xe0i im \u1eafng tr\u01b0\u1edbc b\xe3o, nh\u01b0 ph\xe1p tr\u01b0\u1eddng \u0111ang ch\u1edd th\xeam m\u1ed9t c\xe1i t\xean n\u1eefa b\u1ecb g\u1ecdi l\xean.","Ng\xe0y tr\u01b0\u1edbc n\u01a1i n\xe0y x\u1eed t\u1ed9i kh\xf4ng c\u1ea7n ch\u1ee9ng c\u1ee9, ch\u1ec9 c\u1ea7n c\xf3 ai \u0111\xf3 \u0111\u1ee7 y\u1ebfu \u0111\u1ec3 kh\xf4ng th\u1ec3 t\u1ef1 minh oan. M\u1ed9t \u0111\u1ea1o s\u1ea5m gi\xe1ng xu\u1ed1ng l\xe0 xong, v\u1eeba nhanh v\u1eeba s\u1ea1ch, v\u1eeba \u0111\u1ee7 \u0111\u1ec3 ng\u01b0\u1eddi ng\u1ed3i tr\xean cao tin m\xecnh v\u1eabn l\xe0 c\xf4ng l\xfd. Nh\u01b0ng c\xf4ng l\xfd kh\xf4ng bao gi\u1edd c\u1ea7n s\u1ea5m s\xe9t \u0111\u1ec3 b\u1ecbt mi\u1ec7ng ng\u01b0\u1eddi v\xf4 t\u1ed9i. Khi l\xf4i quang tan \u0111i, chi\u1ebfc \u0111\xe0i tr\u1ed1ng tr\u01a1n l\u1ea7n \u0111\u1ea7u ti\xean tr\xf4ng gi\u1ed1ng m\u1ed9t n\u01a1i con ng\u01b0\u1eddi c\xf3 th\u1ec3 b\u01b0\u1edbc qua m\xe0 kh\xf4ng c\xfai \u0111\u1ea7u.",null)
B.aqR=new A.aO("X\xedch Di\u1ec7m \u0110\u1ed9ng s\xe2u hun h\xfat, t\u1eebng l\xe0 \u0111\u01b0\u1eddng r\xfat lui, r\u1ed3i b\u1ecb bi\u1ebfn th\xe0nh l\xf2 nung cho nh\u1eefng k\u1ebb b\u1ecb ph\u1ea3n b\u1ed9i.","\u0110\xe1m ng\u01b0\u1eddi tr\u1ed1n chi\u1ebfn t\u1eebng t\u01b0\u1edfng t\xecm \u0111\u01b0\u1ee3c l\u1ed1i s\u1ed1ng trong \u0111\u1ed9ng l\u1eeda. Ng\u01b0\u1eddi gi\u1eef c\u1ed5ng kh\xf3a h\u1ecd l\u1ea1i, \u0111\u1ed5i m\u1ea1ng h\u1ecd l\u1ea5y m\u1ed9t kho linh kho\xe1ng v\u1edbi t\xf4ng m\xf4n \u0111\u1ed1i \u0111\u1ecbch. Ng\xe0y h\u1eafn gi\xe0u l\xean, trong \u0111\u1ed9ng ch\u1ec9 c\xf2n tro v\xe0 ti\u1ebfng m\xf3ng tay c\xe0o \u0111\xe1. Ta b\u01b0\u1edbc ra kh\u1ecfi \u0111\xf3 v\u1edbi \xe1o c\xf2n \xe1m m\xf9i kh\xe9t, hi\u1ec3u r\u1eb1ng c\xf3 nh\u1eefng n\u01a1i kh\xf4ng n\xean g\u1ecdi l\xe0 ph\xf3 b\u1ea3n, v\xec ch\xfang v\u1ed1n d\u0129 l\xe0 hi\u1ec7n tr\u01b0\u1eddng.",null)
B.aqB=new A.aO("H\xe0n Tri\u1ec1u \u0110i\u1ec7n l\u1ea1nh \u0111\u1ebfn m\u1ee9c l\u1eddi n\xf3i v\u1eeba r\u1eddi m\xf4i \u0111\xe3 nghe nh\u01b0 m\u1ed9t \u0111i\u1ec1u h\u1ed1i h\u1eadn.","\u0110i\u1ec7n n\xe0y t\u1eebng giam nh\u1eefng ng\u01b0\u1eddi ch\u1ed1ng l\u1ec7nh tri\u1ec1u \u0111\xecnh trong b\u0103ng ng\u1ecdc, gi\u1eef h\u1ecd s\u1ed1ng l\u01b0ng ch\u1eebng \u0111\u1ec3 ti\u1ec7n tra h\u1ecfi su\u1ed1t nhi\u1ec1u th\xe1ng tr\u1eddi. Kh\xf4ng \xedt ng\u01b0\u1eddi g\u1ee5c xu\u1ed1ng m\xe0 v\u1eabn c\xf2n nguy\xean t\u01b0 th\u1ebf qu\u1ef3, nh\u01b0 th\u1ec3 c\xe1i ch\u1ebft c\u0169ng kh\xf4ng gi\xfap h\u1ecd ng\u1ea9ng \u0111\u1ea7u l\xean l\u1ea7n cu\u1ed1i. Sau tr\u1eadn, m\u1eb7t b\u0103ng n\u1ee9t d\u1ecdc th\xe0nh nh\u1eefng \u0111\u01b0\u1eddng d\xe0i nh\u01b0 v\u1ebft s\u1eb9o; \u0111\u1eb9p, nh\u01b0ng l\xe0 v\u1ebb \u0111\u1eb9p m\xe0 ch\u1ec9 k\u1ebb ch\u01b0a t\u1eebng b\u1ecb nh\u1ed1t m\u1edbi d\xe1m ca t\u1ee5ng.",null)
B.ar7=new A.aO("Thanh M\u1ed9c C\u1ea3nh t\u0129nh l\u1eb7ng b\u1ea5t th\u01b0\u1eddng, gi\u1ed1ng khu v\u01b0\u1eddn d\xe0nh cho ng\u01b0\u1eddi ch\u1ebft h\u01a1n l\xe0 n\u01a1i nu\xf4i d\u01b0\u1ee1ng s\u1ef1 s\u1ed1ng.","K\u1ebb ch\u1ee7 c\u1ea3nh thu nh\u1eb7t thi th\u1ec3 tr\u1ebb nh\u1ecf r\u1ed3i gieo h\u1ea1t v\xe0o tim h\u1ecd, tin r\u1eb1ng s\u1ef1 h\u1ed3n nhi\xean l\xe0 lo\u1ea1i \u0111\u1ea5t t\u1ed1t nh\u1ea5t \u0111\u1ec3 tr\u1ed3ng linh d\u01b0\u1ee3c. Bao nhi\xeau m\xf9a xu\xe2n \u0111i qua, hoa v\u1eabn n\u1edf, ch\u1ec9 l\xe0 kh\xf4ng c\xf2n ai \u0111\u1ee7 d\u0169ng kh\xed nh\xecn ch\xfang nh\u01b0 hoa n\u1eefa. Ta ch\xf4n ph\u1ea7n r\u1ec5 cu\u1ed1i c\xf9ng xu\u1ed1ng th\u1eadt s\xe2u, kh\xf4ng ph\u1ea3i \u0111\u1ec3 n\xf3 m\u1ecdc l\u1ea1i, m\xe0 \u0111\u1ec3 \u0111\xe1m tr\u1ebb \u1ea5y l\u1ea7n \u0111\u1ea7u ti\xean \u0111\u01b0\u1ee3c y\xean ngh\u1ec9 nh\u01b0 con ng\u01b0\u1eddi.",null)
B.are=new A.aO("\u0110\u1ecba C\u1ed1t \u0110\xe0n ch\u1ea5t \u0111\u1ea7y x\u01b0\u01a1ng c\u1ed5, nh\u01b0 m\u1ed9t t\u1ebf \u0111\xe0n lu\xf4n thi\u1ebfu \u0111\xfang m\u1ed9t n\u1ea1n nh\xe2n cu\u1ed1i c\xf9ng l\xe0 ng\u01b0\u1eddi \u0111ang \u0111\u1ee9ng tr\u01b0\u1edbc m\u1eb7t n\xf3.","Ng\u01b0\u1eddi tr\u1ea5n \u0111\xe0n tin r\u1eb1ng x\u01b0\u01a1ng tu s\u0129 c\xf3 th\u1ec3 gi\u1eef linh l\u1ef1c b\u1ec1n h\u01a1n linh th\u1ea1ch, n\xean b\u1eaft \u0111\u1ea7u cu\u1ed9c s\u0103n \u201cv\u1eadt li\u1ec7u\u201d d\u01b0\u1edbi danh ngh\u0129a h\u1ed9 \u0111\u1ea1o. M\u1ed7i b\u1ed9 h\xe0i c\u1ed1t \u1edf \u0111\xe2y \u0111\u1ec1u t\u1eebng l\xe0 m\u1ed9t ng\u01b0\u1eddi c\xf3 th\u1ea7y, c\xf3 b\u1ea1n, c\xf3 k\u1ebb \u0111\u1ee3i v\u1ec1. Khi h\u1eafn ng\xe3 xu\u1ed1ng, ta kh\xf4ng ph\xe1 \u0111\xe0n ngay; ta nh\u1eb7t t\u1eebng m\u1ea3nh x\u01b0\u01a1ng tr\u01b0\u1edbc, v\xec c\xf3 nh\u1eefng \u0111i\u1ec1u ph\u1ea3i \u0111\u01b0\u1ee3c \u0111\u1ed1i x\u1eed nh\u01b0 di c\u1ed1t tr\u01b0\u1edbc khi \u0111\u01b0\u1ee3c \u0111\u1ed1i x\u1eed nh\u01b0 chi\u1ebfn l\u1ee3i ph\u1ea9m.",null)
B.aql=new A.aO("Thi\xean L\xf4i Cung s\xe1ng r\u1ef1c t\u1eebng nh\u1ecbp, nh\u01b0 c\xf3 m\u1ed9t v\u1ecb th\u1ea7n n\xf3ng n\u1ea3y \u0111ang \u0111\u1ebfm t\u1ed9i ng\u01b0\u1eddi b\u1eb1ng ch\u1edbp gi\u1eadt.","Th\u1eadt ra \u1edf \u0111\xe2y ch\u01b0a t\u1eebng c\xf3 th\u1ea7n, ch\u1ec9 c\xf3 m\u1ed9t k\u1ebb h\u1ecdc \u0111\u01b0\u1ee3c c\xe1ch m\u01b0\u1ee3n thi\xean t\u01b0\u1ee3ng \u0111\u1ec3 d\u1ef1ng quy\u1ec1n uy. H\u1eafn bi\u1ebfn s\u1ee3 h\xe3i th\xe0nh lu\u1eadt l\u1ec7, bi\u1ebfn khu\u1ea5t ph\u1ee5c th\xe0nh \u0111\u1ee9c h\u1ea1nh, r\u1ed3i g\u1ecdi t\u1ea5t c\u1ea3 l\xe0 thi\xean m\u1ec7nh. \u0110\xe1m ng\u01b0\u1eddi qu\u1ef3 d\u01b0\u1edbi \u0111i\u1ec7n l\xe2u ng\xe0y t\u1edbi m\u1ee9c qu\xean m\u1ea5t b\u1ea7u tr\u1eddi th\u1eadt kh\xf4ng thu\u1ed9c v\u1ec1 ri\xeang ai. \u0110\xeam nay, cung \u0111i\u1ec7n v\u1eabn c\xf2n \u0111\xf3, nh\u01b0ng ti\u1ebfng s\u1ea5m \u0111\xe3 th\xf4i kh\xf4ng c\xf2n l\xe0 ti\u1ebfng c\u1ee7a ch\u1ee7 nh\xe2n n\xe0o n\u1eefa.",null)
B.aqc=new A.aO("H\u1ecfa V\u1ef1c T\xe2m Nh\xe3n gi\u1ed1ng m\u1ed9t con m\u1eaft kh\u1ed5ng l\u1ed3 \u0111ang nh\xecn xo\xe1y v\xe0o l\xf2ng ng\u01b0\u1eddi, ch\u1edd ai l\u1ed9 ra d\u1ee5c ni\u1ec7m \u0111\u1ec3 nu\u1ed1t l\u1ea5y.","N\u01a1i n\xe0y t\u1eebng l\xe0 ch\u1ed7 th\xed luy\u1ec7n d\xe0nh cho \u0111\u1ec7 t\u1eed c\xf3 t\xe2m ma. V\u1ec1 sau, tr\u01b0\u1edfng l\xe3o ph\u1ee5 tr\xe1ch c\u1ed1 \xfd d\u1eabn d\u1ee5 ng\u01b0\u1eddi tr\u1ebb tr\u01b0\u1ee3t ng\xe3 r\u1ed3i d\xf9ng ch\xednh l\u1ed7i l\u1ea7m \u1ea5y l\xe0m c\u1edb t\u01b0\u1edbc \u0111o\u1ea1t linh c\u0103n v\xe0 t\xe0i s\u1ea3n c\u1ee7a h\u1ecd. B\xed c\u1ea3nh gi\u1eef l\u1ea1i t\u1ea5t c\u1ea3 s\u1ef1 x\u1ea5u h\u1ed5 \u0111\xf3 nh\u01b0 than h\u1ed3ng ch\xf4n d\u01b0\u1edbi c\xe1t. Khi l\u01b0\u1ee1i ki\u1ebfm ch\u1ea5m d\u1ee9t h\u1eafn, ta hi\u1ec3u c\xf3 nh\u1eefng ng\u01b0\u1eddi kh\xf4ng ch\u1ebft v\xec sai l\u1ea7m c\u1ee7a m\xecnh, m\xe0 ch\u1ebft v\xec b\u1ecb k\u1ebb kh\xe1c bi\u1ebfn sai l\u1ea7m th\xe0nh c\xf4ng c\u1ee5 h\xe0nh h\xecnh.",null)
B.ar9=new A.aO("Th\u1ee7y K\xednh Uy\xean ph\u1ea3n chi\u1ebfu qu\xe1 r\xf5, \u0111\u1ebfn m\u1ee9c b\xf3ng m\xecnh trong n\u01b0\u1edbc tr\xf4ng c\xf2n th\u1eadt h\u01a1n c\u1ea3 ch\xednh m\xecnh.","Uy\xean c\u1ea3nh n\xe0y chuy\xean b\u1ebb cong k\xfd \u1ee9c. Ng\u01b0\u1eddi qua \u0111\xe2y th\u01b0\u1eddng \u0111\u01b0\u1ee3c cho th\u1ea5y phi\xean b\u1ea3n \u0111\u1eb9p h\u01a1n c\u1ee7a qu\xe1 kh\u1ee9 r\u1ed3i b\u1ecb c\u1ed9t ch\u1eb7t v\xe0o \u0111\xf3 cho \u0111\u1ebfn khi h\xf3a \u0111i\xean. K\u1ebb canh uy\xean b\xe1n nh\u1eefng \u1ea3o \u1ea3nh \u1ea5y cho ng\u01b0\u1eddi s\u1eafp tuy\u1ec7t v\u1ecdng, \u0111\u1ec3 r\u1ed3i moi s\u1ea1ch linh th\u1ea1ch v\xe0 hy v\u1ecdng c\u1ee7a h\u1ecd. Ta ch\xe9m v\u1ee1 l\u1edbp g\u01b0\u01a1ng n\u01b0\u1edbc, \u0111\u1ec3 nh\u1eefng ng\u01b0\u1eddi t\u1eebng ch\xecm trong n\xf3 cu\u1ed1i c\xf9ng c\u0169ng c\xf3 quy\u1ec1n \u0111au v\xec s\u1ef1 th\u1eadt thay v\xec b\u1ecb ru ng\u1ee7 b\u1edfi d\u1ed1i tr\xe1.",null)
B.aqi=new A.aO("M\u1ed9c \u1ea2nh L\xe2m \u0111an ch\u1eb1ng ch\u1ecbt b\xf3ng c\xe2y, nh\u01b0 th\u1ec3 c\u1ea3 khu r\u1eebng \u0111ang c\u1ed1 gi\u1eef b\xed m\u1eadt n\xe0o \u0111\xf3 kh\xf4ng cho \xe1nh s\xe1ng ch\u1ea1m t\u1edbi.","M\u1ed9t nh\xe1nh t\xe0 tu t\u1eebng d\xf9ng khu r\u1eebng n\xe0y \u0111\u1ec3 luy\u1ec7n \u201cth\u1ebf th\xe2n s\u1ed1ng\u201d, b\u1eaft ng\u01b0\u1eddi ngh\xe8o \u0111\u1ed5i v\xe0i bao g\u1ea1o l\u1ea5y kh\u1ebf \u01b0\u1edbc r\u1ed3i r\xfat d\u1ea7n tu\u1ed5i th\u1ecd c\u1ee7a h\u1ecd sang k\u1ebb quy\u1ec1n qu\xfd. T\xe1n l\xe1 um t\xf9m v\xec h\xfat qu\xe1 nhi\u1ec1u n\u0103m th\xe1ng c\u01b0\u1edbp \u0111\u01b0\u1ee3c. Khi tr\u1eadn \u0111\xe1nh kh\xe9p l\u1ea1i, \xe1nh s\xe1ng xuy\xean qua k\u1ebd l\xe1 \u0111\u1ea7u ti\xean sau r\u1ea5t l\xe2u, m\u1ecfng th\xf4i nh\u01b0ng \u0111\u1ee7 \u0111\u1ec3 ta tin r\u1eb1ng c\xf3 nh\u1eefng khu r\u1eebng c\u1ea7n \u0111\u01b0\u1ee3c c\u1ee9u kh\xf4ng ph\u1ea3i kh\u1ecfi l\u1eeda, m\xe0 kh\u1ecfi b\xe0n tay con ng\u01b0\u1eddi.",null)
B.aq6=new A.aO("Nham H\u1ed3n M\xf4n \u0111\u1ee9ng s\u1eebng s\u1eefng nh\u01b0 c\xe1nh c\u1ed5ng ch\u1ec9 m\u1edf m\u1ed9t chi\u1ec1u, qua r\u1ed3i th\xec ch\u1ec9 c\xf2n c\xe1ch \u0111\u1ec3 h\u1ed3n \u1edf l\u1ea1i.","Bao \u0111o\xe0n th\xe1m hi\u1ec3m b\u1ecb d\u1ee5 \u0111\u1ebfn \u0111\xe2y b\u1eb1ng l\u1eddi \u0111\u1ed3n kho b\xe1u c\u1ed5. C\xe1nh c\u1ed5ng \u0111\xf3ng l\u1ea1i, linh h\u1ed3n ng\u01b0\u1eddi ch\u1ebft b\u1ecb \xe9p l\xe0m k\u1ebb d\u1eabn \u0111\u01b0\u1eddng cho n\u1ea1n nh\xe2n ti\u1ebfp theo, t\u1ea1o th\xe0nh m\u1ed9t d\xe2y chuy\u1ec1n tuy\u1ec7t v\u1ecdng kh\xf4ng d\u1ee9t. Ng\u01b0\u1eddi gi\u1eef m\xf4n kh\xf4ng c\u1ea7n m\u1ea1nh nh\u1ea5t, ch\u1ec9 c\u1ea7n nh\u1eabn t\xe2m nh\u1ea5t. Ta ph\xe1 c\u1eeda \u0111\xe1 b\u1eb1ng t\u1ea5t c\u1ea3 linh l\u1ef1c c\xf2n l\u1ea1i, b\u1edfi c\xf3 nh\u1eefng n\u01a1i n\u1ebfu kh\xf4ng m\u1edf toang ra, n\xf3 s\u1ebd m\xe3i \u0103n th\u1ecbt s\u1ef1 t\xf2 m\xf2 c\u1ee7a con ng\u01b0\u1eddi t\u1eebng l\u1edbp m\u1ed9t.",null)
B.aqL=new A.aO("C\u1eedu Ti\xeau L\xf4i V\u1ef1c l\xe0 \u0111o\u1ea1n cu\u1ed1i c\u1ee7a b\xed c\u1ea3nh, n\u01a1i tr\u1eddi \u0111\u1ea5t \u0111\u1ec1u mang v\u1ebb m\u1eb7t c\u1ee7a m\u1ed9t b\u1ea3n \xe1n \u0111\xe3 vi\u1ebft xong.","\u0110\u1ebfn t\u1eadn \u0111\xe2y m\u1edbi hi\u1ec3u B\xed C\u1ea3nh kh\xf4ng \u0111\u01b0\u1ee3c t\u1ea1o ra \u0111\u1ec3 kh\u1ea3o nghi\u1ec7m thi\xean t\xe0i, m\xe0 \u0111\u1ec3 ch\u1ecdn ra k\u1ebb n\xe0o ch\u1ecbu \u0111\u1ef1ng t\u1ed1t nh\u1ea5t tr\u01b0\u1edbc b\u1ea5t c\xf4ng m\xe0 kh\xf4ng ph\xe1t \u0111i\xean. Ng\u01b0\u1eddi \u0111\u1ee9ng cu\u1ed1i c\xf9ng tr\xean l\xf4i v\u1ef1c \u0111\xe3 canh gi\u1eef quy t\u1eafc \u1ea5y qu\xe1 l\xe2u, l\xe2u \u0111\u1ebfn m\u1ee9c ch\xednh h\u1eafn c\u0169ng kh\xf4ng c\xf2n nh\u1edb m\xecnh l\xe0 ng\u01b0\u1eddi thi h\xe0nh hay n\u1ea1n nh\xe2n \u0111\u1ea7u ti\xean. Khi h\u1eafn ng\xe3 xu\u1ed1ng, b\xed c\u1ea3nh kh\xf4ng s\u1ee5p \u0111\u1ed5 ngay; n\xf3 ch\u1ec9 y\xean \u0111i. M\u1ed9t s\u1ef1 y\xean l\u1eb7ng hi\u1ebfm hoi, nh\u01b0 th\u1ec3 c\u1ea3 v\xf9ng \u0111\u1ea5t cu\u1ed1i c\xf9ng c\u0169ng \u0111\u01b0\u1ee3c ph\xe9p m\u1ec7t.",null)
