B.aqj=new A.aO("Tho\xe1t kh\u1ecfi Enkavia ch\u01b0a bao l\xe2u, con thuy\u1ec1n \u0111\xe3 b\u1ecb h\u1ea3i l\u01b0u b\xf3p xo\u1eafn th\xe0nh m\u1ed9t l\u1ed7 h\u1ed5ng kh\xf4ng gian. Khi ta \u0111\u1eb7t ch\xe2n l\xean b\u1edd c\xe1t n\xe0y, m\u1eb7t bi\u1ec3n l\u1ea1i treo tr\xean \u0111\u1ea7u nh\u01b0 m\u1ed9t t\u1ea5m g\u01b0\u01a1ng kh\u1ed5ng l\u1ed3.","Ng\u01b0\u1eddi \u0111\u1ea7u ti\xean ta c\u1ee9u \u1edf Ngh\u1ecbch H\u1ea3i n\xf3i r\u1eb1ng n\u01a1i n\xe0y kh\xf4ng ph\xe2n r\xf5 ng\u01b0\u1eddi s\u1ed1ng hay k\u1ebb ch\u1ebft; ai c\xf2n ch\u1ea5p ni\u1ec7m th\xec b\u1ecb gi\u1eef l\u1ea1i, ai c\xf2n th\u01b0\u01a1ng nh\u1edb th\xec b\u1ecb b\u1eaft ph\u1ea3i nh\xecn th\u01b0\u01a1ng nh\u1edb \u1ea5y l\u1eb7p \u0111i l\u1eb7p l\u1ea1i. Phi\u1ebfn \u0111\xe1 \u0111\u1ea7u ti\xean ch\u01b0a m\u1edf, nh\u01b0ng ta \u0111\xe3 hi\u1ec3u chuy\u1ebfn \u0111i n\xe0y kh\xf4ng ch\u1ec9 \u0111\u1ec3 t\xecm \u0111\u01b0\u1eddng ra, m\xe0 c\xf2n \u0111\u1ec3 h\u1ecfi xem v\xec sao qu\xe1 nhi\u1ec1u s\u1ed1 ph\u1eadn v\xf4 t\u1ed9i l\u1ea1i b\u1ecb nh\u1ed1t v\xe0o m\u1ed9t th\u1ebf gi\u1edbi kh\xf4ng n\xean t\u1ed3n t\u1ea1i.",null)
B.aqO=new A.aO("Tr\u1ea1m g\xe1c tr\u01b0\u1edbc m\u1eb7t treo \u0111\u1ea7y chu\xf4ng s\xf2, m\u1ed7i ti\u1ebfng rung \u0111\u1ec1u nh\u01b0 m\u1ed9t c\xe2u g\u1ecdi \u0111\xf2 d\xe0nh cho ng\u01b0\u1eddi \u0111\xe3 ch\xecm. Ta nghe trong \u0111\xf3 c\xf3 c\u1ea3 t\xean c\u1ee7a nh\u1eefng k\u1ebb ch\u01b0a t\u1eebng \u0111\u01b0\u1ee3c ai \u0111\u01b0a v\u1ec1 b\u1edd.","K\u1ebb gi\u1eef tr\u1ea1m kh\xf4ng ph\u1ea3i \xe1c qu\u1ef7 sinh ra t\u1eeb h\u01b0 v\xf4, m\xe0 l\xe0 m\u1ed9t ng\u01b0\u1eddi ch\u1ed3ng \u0111\xe3 ch\u1edd v\u1ee3 gi\u1eefa b\xe3o bi\u1ec3n \u0111\u1ebfn h\xf3a \u0111i\xean. H\u1eafn gi\u1eef linh h\u1ed3n ng\u01b0\u1eddi ch\u1ebft l\u1ea1i v\xec s\u1ee3 n\u1ebfu bu\xf4ng tay, tr\xean \u0111\u1eddi s\u1ebd ch\u1eb3ng c\xf2n ai nh\u1edb h\u1ecd t\u1eebng t\u1ed3n t\u1ea1i. Ta khuy\xean \u0111\u01b0\u1ee3c h\u1eafn bu\xf4ng chi\u1ebfc chu\xf4ng \u0111\u1ea7u ti\xean, v\xe0 t\u1eeb \u0111\xf3 hi\u1ec3u ra: Ngh\u1ecbch H\u1ea3i s\u1ed1ng b\u1eb1ng nh\u1eefng l\u1eddi t\u1eeb bi\u1ec7t ch\u01b0a bao gi\u1edd \u0111\u01b0\u1ee3c n\xf3i tr\u1ecdn.",null)
B.aqg=new A.aO("Phi\u1ebfn \u0111\xe1 Ngh\u1ecbch H\u1ea3i d\u1ef1ng gi\u1eefa m\u01b0a ng\u01b0\u1ee3c, t\u1eebng n\xe9t v\u0103n nh\u01b0 \u0111ang h\xfat h\u1ebft mu\u1ed1i bi\u1ec3n kh\u1ecfi m\xe1u th\u1ecbt. N\u1ebfu m\u1edf \u0111\u01b0\u1ee3c n\xf3, c\xf3 l\u1ebd ta s\u1ebd bi\u1ebft v\xec sao c\u1ea3 v\xf9ng bi\u1ec3n n\xe0y c\u1ee9 l\u1eb7p \u0111i l\u1eb7p l\u1ea1i m\u1ed9t b\xecnh minh kh\xf4ng bao gi\u1edd t\u1edbi.","Phi\u1ebfn \u0111\xe1 th\u1ee9 nh\u1ea5t s\xe1ng l\xean, hi\u1ec7n ra \u0111\u1ed3 h\xecnh c\u1ee7a n\u0103m ti\u1ec3u th\u1ebf gi\u1edbi bao quanh m\u1ed9t l\xf5i phong \u1ea5n n\u1eb1m \u1edf trung t\xe2m. Ta v\u1eabn ch\u01b0a bi\u1ebft ai d\u1ef1ng n\xean n\u01a1i n\xe0y, ch\u1ec9 bi\u1ebft m\u1ecdi con \u0111\u01b0\u1eddng cu\u1ed1i c\xf9ng \u0111\u1ec1u b\u1ecb k\xe9o v\u1ec1 c\xf9ng m\u1ed9t \u0111i\u1ec3m nh\u01b0 th\u1ec3 c\xf3 m\u1ed9t b\xe0n tay v\xf4 h\xecnh t\u1eeb r\u1ea5t l\xe2u v\u1eabn ch\u01b0a ch\u1ecbu bu\xf4ng. T\u1eeb \u0111\xe2y, h\xe0nh tr\xecnh kh\xf4ng c\xf2n l\xe0 \u0111i m\xf2 l\u1ed1i ra n\u1eefa, m\xe0 l\xe0 l\u1ea7n theo t\u1eebng d\u1ea5u c\u0169 \u0111\u1ec3 h\u1ecfi xem ai \u0111\xe3 b\u1eaft c\u1ea3 m\u1ed9t th\u1ebf gi\u1edbi ph\u1ea3i s\u1ed1ng ng\u01b0\u1ee3c nh\u01b0 th\u1ebf n\xe0y.",null)
B.aqs=new A.aO("Th\xe0nh treo tr\xean \u0111\u1ea7u, ng\u01b0\u1eddi \u0111i d\u01b0\u1edbi m\xe1i, chim bay s\xe1t m\u1eb7t \u0111\u1ea5t. \u1ede n\u01a1i m\u1ecdi th\u1ee9 b\u1ecb l\u1eadt \xfap n\xe0y, ta ch\u1ec9 s\u1ee3 l\xf2ng ng\u01b0\u1eddi c\u0169ng \u0111\xe3 b\u1ecb l\u1eadt kh\u1ecfi ch\u1ed7 v\u1ed1n ph\u1ea3i thu\u1ed9c v\u1ec1.","Thi\xean Th\xe0nh \xdap B\xf3ng ph\u1ed3n hoa h\u01a1n Ngh\u1ecbch H\u1ea3i, nh\u01b0ng n\u1ed7i \u0111au \u1edf \u0111\xe2y \u0111\u01b0\u1ee3c gi\u1ea5u kh\xe9o h\u01a1n nhi\u1ec1u. Ng\u01b0\u1eddi ta \u0103n b\u1eb1ng b\xe1t v\xe0ng, m\u1eb7c b\u1eb1ng g\u1ea5m v\xf3c, v\u1eady m\xe0 ai c\u0169ng s\u1ee3 \xe1nh s\xe1ng r\u1ecdi th\u1eb3ng v\xe0o m\u1eb7t v\xec d\u01b0\u1edbi \xe1nh s\xe1ng \u1ea5y s\u1ebd hi\u1ec7n ra c\xe1i b\xf3ng th\u1eadt c\u1ee7a m\xecnh: m\u1ed9t ng\u01b0\u1eddi m\u1eb9 t\u1eebng b\u1ecf con, m\u1ed9t quan sai t\u1eebng b\xe1n \xe1n, m\u1ed9t k\u1ebb s\u1ed1ng nh\u1edd v\xe0o s\u1ef1 c\xe2m l\u1eb7ng c\u1ee7a ng\u01b0\u1eddi kh\xe1c. Th\u1ebf gi\u1edbi n\xe0y kh\xf4ng ch\u1ec9 \u0111\u1ea3o ng\u01b0\u1ee3c tr\u1eddi \u0111\u1ea5t, n\xf3 c\xf2n \xe9p m\u1ed7i ng\u01b0\u1eddi nh\xecn th\u1ea5y ph\u1ea7n t\u1ed9i l\u1ed7i m\xe0 tr\u01b0\u1edbc \u0111\xe2y h\u1ecd lu\xf4n quay m\u1eb7t b\u1ecf \u0111i.",null)
B.ar2=new A.aO("Phi\u1ebfn \u0111\xe1 th\u1ee9 hai \u0111\u01b0\u1ee3c \u0111\u1eb7t gi\u1eefa trung t\xe2m c\u1ee7a c\u1ea3 m\u1ed9t th\xe0nh qu\xe1ch l\u01a1 l\u1eedng. Ta c\xf3 c\u1ea3m gi\xe1c ch\u1ec9 c\u1ea7n sai m\u1ed9t b\u01b0\u1edbc, to\xe0n b\u1ed9 b\u1ea7u tr\u1eddi \xfap ng\u01b0\u1ee3c n\xe0y s\u1ebd r\u01a1i xu\u1ed1ng nh\u01b0 b\u1ea3n \xe1n d\xe0nh cho nh\u1eefng k\u1ebb c\xf2n s\u1ed1ng.","Khi phi\u1ebfn \u0111\xe1 th\u1ee9 hai m\u1edf, \xe1nh s\xe1ng ch\u1ec9 k\u1ecbp l\u1ed9 ra v\xe0i n\xe9t ch\u1eef \u0111\xe3 b\u1ecb m\xe0i m\xf2n v\xe0 m\u1ed9t v\xf2ng tr\u1eadn c\u0169 b\u1ecb \u0111\u1ee9t \u0111o\u1ea1n \u1edf m\xe9p. C\xf3 k\u1ebb t\u1eebng c\u1ed1 gi\u1eef \u1ed5n \u0111\u1ecbnh n\u01a1i n\xe0y, ho\u1eb7c t\u1eebng c\u1ed1 nh\u1ed1t th\u1ee9 g\xec \u0111\xf3 \u1edf s\xe2u b\xean d\u01b0\u1edbi, nh\u01b0ng m\u1ecdi \u0111\u1ea7u m\u1ed1i quan tr\u1ecdng \u0111\u1ec1u b\u1ecb c\u1ed1 \xfd che m\u1edd. Ta ch\u1ec9 bi\u1ebft m\u1ed9t \u0111i\u1ec1u: c\xe0ng \u0111i ti\u1ebfp, nh\u1eefng m\u1ea3nh \u0111\u1eddi m\u1eafc k\u1eb9t \u1edf \u0111\xe2y c\xe0ng cho th\u1ea5y \u0111\xe2y kh\xf4ng ph\u1ea3i tai bi\u1ebfn v\xf4 ch\u1ee7, m\xe0 l\xe0 di t\xedch c\u1ee7a m\u1ed9t \xfd ch\xed qu\xe1 l\u1edbn \u0111\xe3 m\u1ee5c n\xe1t theo n\u0103m th\xe1ng.",null)
B.aqY=new A.aO("\u1ede M\u1ed9c Vi\xean Tro, c\xe2y n\u1edf hoa tr\u01b0\u1edbc r\u1ed3i m\u1edbi th\xe0nh n\u1ee5, tr\u1ebb con h\xe1t ru m\u1eb9, c\xf2n kh\xf3i b\u1ebfp bay xu\u1ed1ng m\u1eb7t \u0111\u1ea5t nh\u01b0 mu\u1ed1n ch\xf4n lu\xf4n nh\u1eefng b\u1eefa c\u01a1m ch\u01b0a tr\u1ecdn. Ta bi\u1ebft n\u01a1i n\xe0y s\u1ebd \u0111au theo m\u1ed9t c\xe1ch kh\xe1c.","Nh\u1eefng ng\u01b0\u1eddi d\xe2n \u1edf M\u1ed9c Vi\xean Tro s\u1ed1ng nh\u01b0 th\u1ec3 n\u1ebfu l\xe0m \u0111\u1ee7 m\u1ecdi th\u1ee9 theo chi\u1ec1u ng\u01b0\u1ee3c l\u1ea1i th\xec ng\u01b0\u1eddi \u0111\xe3 m\u1ea5t s\u1ebd quay v\u1ec1. H\u1ecd gi\u1eef \xe1o tang ch\u01b0a m\u1eb7c xong, gi\u1eef m\xe2m c\u01a1m ch\u01b0a k\u1ecbp d\u1ecdn, gi\u1eef ti\u1ebfng c\u01b0\u1eddi c\xf2n v\u01b0\u1edbng \u1edf b\u1eadc c\u1eeda, nh\u01b0 th\u1ec3 ch\u1ec9 c\u1ea7n ch\u1edd th\xeam m\u1ed9t ch\xfat l\xe0 m\xf9a c\u0169 s\u1ebd nh\u1ea3 ng\u01b0\u1eddi th\xe2n ra. Ta \u0111i qua t\u1eebng c\u0103n nh\xe0 v\xe0 hi\u1ec3u ra r\u1eb1ng n\u1ed7i \u0111au l\u1edbn nh\u1ea5t kh\xf4ng ph\u1ea3i ch\u1ebft ch\xf3c, m\xe0 l\xe0 bi\u1ebft ch\u1eafc m\u1ed9t ng\u01b0\u1eddi s\u1ebd kh\xf4ng tr\u1edf l\u1ea1i m\xe0 v\u1eabn kh\xf4ng \u0111\u1ee7 can \u0111\u1ea3m \u0111\u1ec3 c\u1ea5t ph\u1ea7n c\u01a1m c\u1ee7a h\u1ecd \u0111i.",null)
B.aqH=new A.aO("Phi\u1ebfn \u0111\xe1 M\u1ed9c Vi\xean ph\u1ee7 \u0111\u1ea7y r\u1ec5 c\xe2y tr\u1eafng b\u1ec7ch, nh\u01b0 x\u01b0\u01a1ng tay c\u1ee7a nh\u1eefng k\u1ebb \u0111\xe3 \u0111\xe0o b\u1edbi k\xfd \u1ee9c m\xecnh t\u1edbi t\u1eadn c\xf9ng m\xe0 v\u1eabn kh\xf4ng t\xecm th\u1ea5y m\u1ed9t c\xe2u tr\u1ea3 l\u1eddi \u0111\u1ee7 d\u1ecbu d\xe0ng.",'Phi\u1ebfn \u0111\xe1 th\u1ee9 ba h\xe9 l\u1ed9 th\xeam nh\u1eefng \u0111o\u1ea1n k\xfd l\u1ee5c r\u1eddi r\u1ea1c: h\xecnh thuy\u1ec1n v\u1ee1, nh\u1eefng b\xf3ng ng\u01b0\u1eddi qu\u1ef3 b\xean m\xe9p v\u1ef1c s\xe1ng, v\xe0 m\u1ed9t c\xe2u duy nh\u1ea5t c\xf2n \u0111\u1ecdc \u0111\u01b0\u1ee3c l\xe0 "\u0111\u1eebng \u0111\u1ec3 h\u1ecd tan v\xe0o kho\u1ea3ng tr\u1ed1ng". Ta v\u1eabn ch\u01b0a bi\u1ebft "h\u1ecd" l\xe0 ai, c\u0169ng ch\u01b0a bi\u1ebft k\u1ebb n\xe0o \u0111\xe3 vi\u1ebft c\xe2u \u1ea5y, nh\u01b0ng t\u1eeb m\u1ea3nh k\xfd l\u1ee5c n\xe0y c\xf3 th\u1ec3 ch\u1eafc r\u1eb1ng Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c t\u1eebng b\u1eaft \u0111\u1ea7u t\u1eeb m\u1ed9t bi\u1ebfn c\u1ed1 n\u01a1i bi\u1ec3n v\xe0 t\u1eeb n\u1ed7 l\u1ef1c tuy\u1ec7t v\u1ecdng c\u1ee7a m\u1ed9t ng\u01b0\u1eddi kh\xf4ng ch\u1ea5p nh\u1eadn \u0111\u1ec3 ai \u0111\xf3 bi\u1ebfn m\u1ea5t.',null)
B.aqM=new A.aO("Tinh M\u1ed9 kh\xf4ng c\xf3 gi\xf3, ch\u1ec9 c\xf3 nh\u1eefng v\xec sao ch\xf4n n\u1eeda v\u1eddi d\u01b0\u1edbi c\xe1t v\xe0 \u0111\xe1m ng\u01b0\u1eddi l\u1eef h\xe0nh c\xfai \u0111\u1ea7u mang theo h\u0169 tro c\u1ee7a ng\u01b0\u1eddi th\xe2n. C\u1ea3 sa m\u1ea1c nh\u01b0 \u0111ang l\u1eb7ng l\u1ebd ch\u1ecbu tang.","\u1ede \u0111\xe2y, ai c\u0169ng mang tr\xean ng\u01b0\u1eddi m\u1ed9t c\xe1i ch\u1ebft ch\u01b0a k\u1ecbp ti\u1ec5n. C\xf3 ng\u01b0\u1eddi gi\u1eef h\u0169 tro c\u1ee7a cha, c\xf3 ng\u01b0\u1eddi c\xf5ng di v\u1eadt c\u1ee7a ch\u1ed3ng, c\xf3 ng\u01b0\u1eddi ch\u1ec9 gi\u1eef \u0111\u01b0\u1ee3c m\u1ed9t \u0111\u1ed3ng ti\u1ec1n \u0111\u1ed3ng v\xe0 n\xf3i \u0111\xf3 l\xe0 th\u1ee9 cu\u1ed1i c\xf9ng con g\xe1i m\xecnh t\u1eebng n\u1eafm. C\xe0ng nh\xecn h\u1ecd, ta c\xe0ng tin g\u1ed1c r\u1ec5 c\u1ee7a n\u01a1i n\xe0y h\u1eb3n t\u1eebng g\u1eafn v\u1edbi c\u1ee9u v\u1edbt ho\u1eb7c gi\u1eef l\u1ea1i, ch\u1ee9 kh\xf4ng thu\u1ea7n t\xfay l\xe0 h\u1ee7y di\u1ec7t. Nh\u01b0ng c\u1ee9u t\u1edbi m\u1ee9c bi\u1ebfn ng\u01b0\u1eddi kh\xe1c th\xe0nh t\xf9 nh\xe2n c\u1ee7a k\xfd \u1ee9c th\xec r\u1ed1t cu\u1ed9c c\u0169ng l\xe0 m\u1ed9t d\u1ea1ng t\xe0n nh\u1eabn kh\xe1c.",null)
B.aqm=new A.aO("Phi\u1ebfn \u0111\xe1 Tinh M\u1ed9 d\u1ef1ng gi\u1eefa \u0111\u1ed3ng h\u1ed3 \u0111\xe3 t\u1eaft, c\xe1t ph\u1ee7 l\xean nh\u1eefng v\u1ec7t ch\u1eef nh\u01b0 th\u1ec3 n\u0103m th\xe1ng \u1edf \u0111\xe2y kh\xf4ng tr\xf4i m\xe0 ch\u1ec9 l\u1eafng xu\u1ed1ng. Ta bi\u1ebft sau l\u1ea7n n\xe0y, c\xe1nh c\u1eeda trung t\xe2m s\u1ebd kh\xf4ng c\xf2n xa n\u1eefa.","Phi\u1ebfn \u0111\xe1 th\u1ee9 t\u01b0 cho ta th\u1ea5y v\xf2ng tr\u1eadn \u1edf l\xf5i trung t\xe2m ch\u1ec9 ch\u1ecbu m\u1edf th\xeam khi k\u1ebb \u0111i \u0111\u01b0\u1eddng mang theo m\u1ed9t lo\u1ea1i kh\xed t\u1ee9c r\u1ea5t \u0111\u1eb7c bi\u1ec7t, th\u1ee9 kh\xed t\u1ee9c ta v\u1eeba ch\u1ea1m ph\u1ea3i \u1edf Enkavia. V\u1eady l\xe0 vi\u1ec7c ta b\u1ecb h\xfat v\xe0o n\u01a1i n\xe0y kh\xf4ng ho\xe0n to\xe0n do xui r\u1ee7i. C\xf3 th\u1ee9 g\xec \u0111\xf3 \u1edf trung t\xe2m \u0111\xe3 nh\u1eadn ra ta t\u1eeb tr\u01b0\u1edbc c\u1ea3 khi ta k\u1ecbp hi\u1ec3u m\xecnh \u0111ang r\u01a1i v\xe0o \u0111\xe2u. Nh\u01b0ng v\xec sao n\xf3 ch\u1edd ta, n\xf3 c\u1ea7n ta l\xe0m g\xec, v\xe0 li\u1ec7u \u1edf cu\u1ed1i con \u0111\u01b0\u1eddng n\xe0y l\xe0 l\u1ed1i ra hay ch\u1ec9 l\xe0 m\u1ed9t c\xe1i b\u1eaby tinh vi h\u01a1n, t\u1ea5t c\u1ea3 v\u1eabn ph\u1ea3i \u0111\u1ec3 t\u1edbi \u0111i\u1ec3m cu\u1ed1i c\xf9ng m\u1edbi c\xf3 th\u1ec3 tr\u1ea3 l\u1eddi.",null)
B.ar3=new A.aO("B\u1eadc \u0111\xe1 tr\u01b0\u1edbc Uy\xean M\xf4n rung l\xean theo nh\u1ecbp tim ta. C\xe0ng \u0111\u1ebfn g\u1ea7n trung t\xe2m, ta c\xe0ng nghe r\xf5 v\xf4 s\u1ed1 ti\u1ebfng ng\u01b0\u1eddi ch\u1ed3ng l\xean nhau: l\u1eddi c\u1ea7u c\u1ee9u, l\u1eddi xin l\u1ed7i, l\u1eddi t\u1eeb bi\u1ec7t ch\u01b0a k\u1ecbp n\xf3i v\xe0 c\u1ea3 ti\u1ebfng th\u1edf cu\u1ed1i c\u1ee7a m\u1ed9t tu s\u0129 gi\xe0.","Uy\xean M\xf4n m\u1edf ra m\u1ed9t khe s\xe1ng \u0111\u1ee7 \u0111\u1ec3 nh\xecn th\u1ea5y h\xe0nh lang \u0111\xe1 k\xe9o s\xe2u v\xe0o l\xf2ng \u0111\u1ea5t. Nh\u01b0ng c\xe0ng t\u1edbi g\u1ea7n, ta c\xe0ng nh\u1eadn ra bi k\u1ecbch \u1edf \u0111\xe2y kh\xf4ng ch\u1ec9 l\xe0 v\xe0i oan h\u1ed3n \u0111\u01a1n l\u1ebb. Nhi\u1ec1u ng\u01b0\u1eddi m\u1eafc k\u1eb9t trong Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c \u0111\xe3 s\u1ed1ng c\u1ea3 \u0111\u1eddi d\u01b0\u1edbi tr\u1eadt t\u1ef1 m\xe9o m\xf3 n\xe0y, quen \u0111\u1ebfn m\u1ee9c kh\xf4ng c\xf2n bi\u1ebft tr\u1eddi \u0111\u1ea5t b\xecnh th\u01b0\u1eddng v\u1ed1n n\xean nh\u01b0 th\u1ebf n\xe0o. N\u1ebfu ta d\u1eebng l\u1ea1i tr\u01b0\u1edbc c\xe1nh c\u1eeda cu\u1ed1i, n\u01a1i n\xe0y s\u1ebd ti\u1ebfp t\u1ee5c nu\u1ed1t nh\u1eefng \u0111\u1eddi ng\u01b0\u1eddi m\u1edbi, v\xe0 m\u1ecdi \u0111au kh\u1ed5 ta v\u1eeba ch\u1ee9ng ki\u1ebfn s\u1ebd ch\u1ec9 l\xe0 m\u1edf \u0111\u1ea7u cho nh\u1eefng chu k\u1ef3 sau.",null)
B.aqD=new A.aO("T\xe2m \u0110\xecnh T\xe1ng Nguy\u1ec7t im l\u1eb7ng \u0111\u1ebfn m\u1ee9c nghe \u0111\u01b0\u1ee3c c\u1ea3 ti\u1ebfng tro b\u1ee5i r\u01a1i t\u1eeb m\xe1i \u0111\xe1. Ta bi\u1ebft ch\u1ec9 c\u1ea7n b\u01b0\u1edbc th\xeam m\u1ed9t tr\u1eadn n\u1eefa, m\u1ecdi c\xe2u h\u1ecfi b\u1ecb k\xe9o d\xe0i su\u1ed1t h\xe0nh tr\xecnh n\xe0y s\u1ebd kh\xf4ng c\xf2n ch\u1ed7 \u0111\u1ec3 tr\u1ed1n.","Tr\u1eadn ph\xe1p \u1edf T\xe2m \u0110\xecnh \u0111\xe3 r\xfat g\u1ea7n h\u1ebft, ch\u1ec9 \u0111\u1ec3 l\u1ea1i m\u1ed9t l\u1ed1i \u0111i th\u1eb3ng v\xe0o linh \u0111\xe0i cu\u1ed1i c\xf9ng. Kh\xf4ng c\xf2n th\xeam manh m\u1ed1i n\xe0o n\u1eeda v\u1eddi n\u1eefa, c\u0169ng kh\xf4ng c\xf2n ch\u1ed7 cho vi\u1ec7c t\u1ef1 l\u1eeba m\xecnh r\u1eb1ng \u0111\xe2y ch\u1ec9 l\xe0 m\u1ed9t v\xf9ng \u0111\u1ea5t l\u1ea1c l\u1ed1i t\xecnh c\u1edd. T\u1eeb \u0111\xe2y tr\u1edf \u0111i ho\u1eb7c ta m\u1edf \u0111\u01b0\u1ee3c ch\xe2n t\u01b0\u1edbng c\u1ee7a Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c, ho\u1eb7c ta s\u1ebd b\u1ecb n\xf3 nu\u1ed1t lu\xf4n nh\u01b0 bao ng\u01b0\u1eddi tr\u01b0\u1edbc \u0111\xf3.",null)
B.ar_=new A.aO("\u0110\u1ed9ng ti\xean \u0111\xe3 m\u1edf, nh\u01b0ng h\u01a1i th\u1edf b\xean trong l\u1ea1nh nh\u01b0 m\u1ed9t ng\xf4i m\u1ed9. N\u1ebfu ch\xe2n t\u01b0\u1edbng cu\u1ed1i c\xf9ng ch\u1ec9 l\xe0 di ch\xfac c\u1ee7a m\u1ed9t ng\u01b0\u1eddi t\u1ed1t \u0111\xe3 th\u1ea5t b\u1ea1i, ta v\u1eabn ph\u1ea3i nghe cho tr\u1ecdn \u0111\u1ec3 tr\u1ea3 l\u1eddi thay nh\u1eefng k\u1ebb b\u1ecb gi\u1eef l\u1ea1i \u1edf \u0111\xe2y.","B\xean trong \u0110\u1ed9ng Ti\xean V\xf4 Ch\u1ee7 kh\xf4ng c\xf3 b\xe1u v\u1eadt t\u1ed1i th\u01b0\u1ee3ng, ch\u1ec9 c\xf3 linh \u0111\xe0i, di th\u01b0 v\xe0 b\u1ed9 x\u01b0\u01a1ng \u0111\xe3 kh\xf4 c\u1ee7a Ninh T\u1ecbch Chu. Tr\u01b0\u1edbc khi ch\u1ebft, \xf4ng d\xf9ng ph\u1ea7n \u0111\u1ed9ng thi\xean cu\u1ed1i c\xf9ng \u0111\u1ec3 che ch\u1edf \u0111o\xe0n ng\u01b0\u1eddi b\u1ecb cu\u1ed1n v\xe0o khe n\u1ee9t h\u01b0 kh\xf4ng sau \u0111\u1ea1i n\u1ea1n ngo\xe0i bi\u1ec3n; nh\u01b0ng \xf4ng kh\xf4ng k\u1ecbp tr\u1edf l\u1ea1i \u0111\u1ec3 \u0111\xf3ng tr\u1eadn ph\xe1p, n\xean n\u0103m khoang ti\u1ec3u th\u1ebf gi\u1edbi c\u1ee9 t\u1ef1 xoay theo chi\u1ec1u ngh\u1ecbch, bi\u1ebfn k\xfd \u1ee9c th\xe0nh lao ng\u1ee5c, bi\u1ebfn th\u01b0\u01a1ng nh\u1edb th\xe0nh d\xe2y x\xedch. Ta ho\xe0n t\u1ea5t phi\u1ebfn \u0111\xe1 cu\u1ed1i, gi\u1ea3i tr\u1eadn, m\u1edf to\xe0n b\u1ed9 \u0111\u01b0\u1eddng ra cho c\u01b0 d\xe2n n\u01a1i \u0111\xe2y v\xe0 ch\xf4n l\u1ea1i h\xe0i c\u1ed1t \xf4ng trong ch\xednh ph\u1ee7 \u0111\u1ec7 c\u1ee7a m\xecnh. Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c kh\xf4ng sinh ra t\u1eeb \xe1c \xfd, m\xe0 t\u1eeb m\u1ed9t l\xf2ng c\u1ee9u ng\u01b0\u1eddi dang d\u1edf. C\xe0ng v\xec th\u1ebf, n\xf3 c\xe0ng nh\u1eafc ta r\u1eb1ng ngay c\u1ea3 thi\u1ec7n \xfd n\u1ebfu kh\xf4ng \u0111i \u0111\u1ebfn c\xf9ng c\u0169ng c\xf3 th\u1ec3 tr\u1edf th\xe0nh tai \u01b0\u01a1ng cho v\xf4 s\u1ed1 m\u1ea3nh \u0111\u1eddi.","N\u1ebfu ta ng\xe3 tr\u01b0\u1edbc linh \u0111\xe0i n\xe0y, nh\u1eefng ng\u01b0\u1eddi b\u1ecb k\u1eb9t trong n\u0103m ti\u1ec3u th\u1ebf gi\u1edbi s\u1ebd c\xf2n ph\u1ea3i s\u1ed1ng ti\u1ebfp nhi\u1ec1u \u0111\u1eddi d\u01b0\u1edbi m\u1ed9t b\u1ea7u tr\u1eddi l\u1eadt \xfap, m\xe3i m\xe3i kh\xf4ng bi\u1ebft v\xec sao m\xecnh kh\u1ed5 nh\u01b0 th\u1ebf.")
